/* AUTO-GENERATED — Michigan Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["MI"] = {"code":"MI","name":"Michigan","agency":"Michigan SOS","agencyShort":"SOS","handbook":"https://www.michigan.gov/sos/resources/forms/michigan-cdl-manual","links":{},"en":[{"q":"On Michigan's designated highways, what is the maximum legal width of a commercial vehicle (excluding mirrors and certain safety equipment) before an oversize permit is required?","options":["108 inches (9 feet)","96 inches (8 feet)","120 inches (10 feet)","102 inches (8 feet 6 inches)"],"answer":3,"explanation":"Michigan limits vehicle width to 102 inches (8'6\") on designated highways and 96 inches (8') on other roads, consistent with the federal national-network standard. Source: Michigan Vehicle Code MCL 257.717; MDOT 'Maximum Legal Truck Loadings and Dimensions' (T-1).","handbook":"","hbref":""},{"q":"What is the maximum legal height for a vehicle and its load on Michigan highways without a special transport permit?","options":["14 feet 0 inches","13 feet 6 inches","14 feet 6 inches","13 feet 0 inches"],"answer":1,"explanation":"Michigan sets the maximum vehicle-and-load height at 13 feet 6 inches; anything taller requires an oversize permit. Source: MCL 257.718; MDOT Maximum Legal Truck Loadings and Dimensions (T-1).","handbook":"","hbref":""},{"q":"What is the maximum length of a semitrailer (including load) operated on Michigan's designated highways without a permit?","options":["60 feet","48 feet","53 feet","57 feet"],"answer":2,"explanation":"Michigan allows a semitrailer up to 53 feet, including load, on designated highways (50 feet on non-designated roads). Source: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1).","handbook":"","hbref":""},{"q":"Under federal limits that Michigan applies on the Interstate system, what is the maximum gross vehicle weight for a standard 5-axle combination without a permit?","options":["88,000 pounds","76,000 pounds","73,280 pounds","80,000 pounds"],"answer":3,"explanation":"On the Interstate system Michigan enforces the federal cap of 80,000 pounds gross for vehicles subject to the federal bridge formula. Source: 23 CFR 658.17 as applied in Michigan; MDOT truck weight guidance.","handbook":"","hbref":""},{"q":"What is the federal single-axle weight limit that applies to vehicles operating under the 80,000-pound federal standard on Michigan's Interstate highways?","options":["24,000 pounds","22,400 pounds","18,000 pounds","20,000 pounds"],"answer":3,"explanation":"For vehicles governed by the federal 80,000-pound standard, the single-axle limit is 20,000 pounds, the same figure Michigan applies on the Interstate. Source: 23 CFR 658.17 as applied in Michigan; MDOT weight guidance.","handbook":"","hbref":""},{"q":"Under the federal standard applied on Michigan's Interstate system, what is the maximum weight allowed on a tandem axle group?","options":["36,000 pounds","40,000 pounds","32,000 pounds","34,000 pounds"],"answer":3,"explanation":"The federal tandem-axle limit Michigan enforces on the Interstate is 34,000 pounds. Note Michigan's own state-law axle rules differ (see its 18,000-lb normal axle maximum). Source: 23 CFR 658.17; MDOT weight guidance.","handbook":"","hbref":""},{"q":"Because of axle-load rules predating federal limits, what is the maximum gross vehicle weight a properly configured truck can legally carry on Michigan roads off the Interstate?","options":["80,000 pounds","164,000 pounds","105,500 pounds","129,000 pounds"],"answer":1,"explanation":"Michigan's grandfathered weight law allows a maximum gross weight of about 164,000 pounds when axle loads and spacing comply, the highest routinely allowed in North America. Source: MCL 257.722; Michigan House Fiscal Agency, 'Michigan's Truck-Weight Law.'","handbook":"","hbref":""},{"q":"What is the maximum number of axles allowed on a Michigan truck-trailer combination that operates under the state's heavy-weight provisions?","options":["8 axles","11 axles","9 axles","13 axles"],"answer":1,"explanation":"Since 1967 Michigan has capped these combinations at 11 axles, which together with per-axle limits yields the roughly 164,000-pound maximum. Source: MCL 257.722; Michigan House Fiscal Agency truck-weight analysis.","handbook":"","hbref":""},{"q":"Under Michigan's own axle-load law, what is the 'normal loading maximum' for a single axle spaced 9 feet or more from adjacent axles?","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,400 pounds"],"answer":1,"explanation":"Michigan law sets the normal maximum single-axle load at 18,000 pounds where axle spacing is 9 feet or more, which is lower than the 20,000-lb federal figure. Source: MCL 257.722(1).","handbook":"","hbref":""},{"q":"Michigan's state axle law limits the maximum wheel load to a value tied to tire width. What is that limit?","options":["500 pounds per inch of tire width","700 pounds per inch of tire width","600 pounds per inch of tire width","850 pounds per inch of tire width"],"answer":1,"explanation":"Michigan caps wheel load at 700 pounds per inch of tire width, a standard that distributes heavy loads onto more tires and axles. Source: MCL 257.722(7).","handbook":"","hbref":""},{"q":"During Michigan's spring thaw (frost law) period, by what percentage are maximum axle loads reduced on concrete pavements?","options":["25 percent","35 percent","10 percent","50 percent"],"answer":0,"explanation":"During March, April, and May, Michigan reduces maximum axle loads by 25 percent on concrete pavements (and by 35 percent on other roads) to protect thawing roadbeds. Source: MCL 257.722(8).","handbook":"","hbref":""},{"q":"During Michigan's seasonal frost-law restrictions, axle loads on roads other than concrete pavement are reduced by what percentage?","options":["15 percent","45 percent","35 percent","25 percent"],"answer":2,"explanation":"On non-concrete roads, Michigan's spring weight restrictions reduce maximum axle loads by 35 percent during the March-May thaw period. Source: MCL 257.722(8).","handbook":"","hbref":""},{"q":"In which months does Michigan's seasonal weight reduction (frost law) typically apply?","options":["March, April, and May","January, February, and March","November, December, and January","April, May, and June"],"answer":0,"explanation":"Michigan's seasonal axle-load reductions apply during the spring thaw, statutorily tied to March, April, and May, with exact start/end dates announced by MDOT each year. Source: MCL 257.722(8); MDOT seasonal weight restriction notices.","handbook":"","hbref":""},{"q":"Michigan law allows the load on a combination of vehicles to extend how far beyond the rear of the vehicle before extra warning is required?","options":["2 feet","3 feet","4 feet","6 feet"],"answer":2,"explanation":"A load may project up to 4 feet beyond the rear (and 3 feet beyond the front); rear overhang of 4 feet or more requires a red flag by day and a red light by night. Source: MCL 257.719; MDOT loading dimensions guidance.","handbook":"","hbref":""},{"q":"A load extending beyond the rear of a Michigan commercial vehicle must display a red light or lantern at night once the overhang reaches what length?","options":["8 feet","2 feet","4 feet","6 feet"],"answer":2,"explanation":"Michigan requires a red flag in daylight and a red light or lantern at night for any load that projects 4 feet or more beyond the rear of the vehicle. Source: MCL 257.719; MDOT loading dimensions guidance.","handbook":"","hbref":""},{"q":"Who issues oversize/overweight transport permits for travel on Michigan state trunkline highways?","options":["The Federal Motor Carrier Safety Administration","The Michigan State Police only","The Michigan Department of Transportation (MDOT)","The Michigan Secretary of State"],"answer":2,"explanation":"MDOT issues permits for excess size or weight on state trunklines, while local road agencies handle roads under their jurisdiction. Source: MCL 257.725; MDOT Oversize/Overweight Permits.","handbook":"","hbref":""},{"q":"Through which online system does a carrier apply for an MDOT oversize/overweight permit in Michigan?","options":["CDLIS (Commercial Driver License Information System)","IRP (International Registration Plan portal)","SAFER (Safety and Fitness Electronic Records)","MiTRIP (Michigan Transport Routing and Internet Permitting)"],"answer":3,"explanation":"Michigan carriers obtain transport permits electronically through MiTRIP, MDOT's online routing and permitting system. Source: MDOT Oversize/Overweight Permits; MCL 257.725.","handbook":"","hbref":""},{"q":"A single-trip oversize permit in Michigan is generally issued for the occasional movement of a load that:","options":["Is being moved entirely on private property","Cannot be dismantled or rearranged to come within legal limits","The carrier simply prefers not to break down into smaller loads","Exceeds legal limits by less than one percent"],"answer":1,"explanation":"Michigan permits are issued only for the occasional movement of oversize or overweight loads that cannot reasonably be dismantled, reduced, or rearranged to meet legal limits. Source: MCL 257.725; MDOT permit policy.","handbook":"","hbref":""},{"q":"Under Michigan's natural gas vehicle provision, a vehicle powered by natural gas may exceed the applicable weight limits by how much to account for the heavier fuel system?","options":["5,000 pounds","2,000 pounds","550 pounds","10,000 pounds"],"answer":1,"explanation":"Michigan grants natural gas vehicles up to a 2,000-pound allowance above the otherwise applicable weight limits to offset the added weight of the fuel system. Source: Michigan Vehicle Code; MDOT weight guidance consistent with federal 23 U.S.C. 127 NGV allowance.","handbook":"","hbref":""},{"q":"For a Michigan combination such as a truck-tractor pulling two towed units, what is the maximum overall length (measured front of the first towed unit to rear of the last) before a permit is required?","options":["75 feet","58 feet","65 feet","53 feet"],"answer":1,"explanation":"Michigan allows these double combinations with no fixed overall vehicle length as long as the towed units, measured from the front of the first to the rear of the last, do not exceed 58 feet (each unit not over 28'6\"). Source: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1).","handbook":"","hbref":""},{"q":"In Michigan, which CDL group is required to operate any combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, where the towed unit has a GVWR of more than 10,000 pounds?","options":["Group A","Group B","Group C","Group D"],"answer":0,"explanation":"Michigan defines a Group (Class) A CDL as any combination of vehicles with a GCWR of 26,001 lbs or more, provided the GVWR of the towed unit(s) is more than 10,000 lbs. Source: Michigan CDL Manual (Michigan SOS), Section 1.","handbook":"","hbref":""},{"q":"Under Michigan rules, which CDL group covers a single vehicle with a gross vehicle weight rating (GVWR) of 26,001 pounds or more (which may tow a unit of 10,000 pounds or less)?","options":["Group A","Group B","Group C","Group H"],"answer":1,"explanation":"A Group (Class) B CDL in Michigan is for any single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a unit not over 10,000 lbs GVWR. Source: Michigan CDL Manual (Michigan SOS), Section 1.","handbook":"","hbref":""},{"q":"A Michigan Group (Class) C CDL is required for a smaller vehicle (under the Class A/B weight thresholds) only when it is used to transport which of the following?","options":["Any cargo weighing over 5,000 pounds","16 or more passengers (including the driver), or hazardous materials in placarded amounts","Any trailer regardless of weight","Only school children"],"answer":1,"explanation":"A Michigan Group C CDL applies to vehicles below the Class A/B weight limits that are designed to transport 16 or more passengers including the driver, or that carry hazardous materials in amounts requiring placards. Source: Michigan CDL Manual (Michigan SOS), Section 1.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Michigan CDL for INTRASTATE driving (operating only within Michigan)?","options":["16 years old","18 years old","21 years old","25 years old"],"answer":1,"explanation":"Michigan allows a CDL at age 18 for intrastate (within-state) commerce only; interstate operation requires age 21. Source: Michigan CDL Manual (Michigan SOS) / Michigan SOS CDL eligibility.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Michigan CDL that permits INTERSTATE driving (across state lines)?","options":["18 years old","19 years old","21 years old","23 years old"],"answer":2,"explanation":"Federal and Michigan rules require a driver to be at least 21 to operate a CMV in interstate commerce; drivers aged 18-20 are limited to intrastate operation. Source: Michigan CDL Manual (Michigan SOS); 49 CFR 391.11.","handbook":"","hbref":""},{"q":"In Michigan, how long must an applicant hold a Commercial Learner's Permit (CLP) before being allowed to take the CDL on-road skills test?","options":["A minimum of 7 days","A minimum of 14 days","A minimum of 30 days","A minimum of 60 days"],"answer":1,"explanation":"Michigan follows the federal rule requiring the CLP be held a minimum of 14 days before the applicant may take the CDL skills test. Source: Michigan SOS (cdl-apply); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Which endorsement is required on a Michigan CDL to operate a vehicle designed to carry 16 or more people, including the driver?","options":["P (Passenger)","N (Tank)","T (Doubles/Triples)","H (Hazardous Materials)"],"answer":0,"explanation":"The P (Passenger) endorsement is required in Michigan to operate a vehicle designed to transport 16 or more persons including the driver. Source: Michigan CDL Manual (Michigan SOS), endorsements section.","handbook":"","hbref":""},{"q":"Which Michigan CDL endorsement is required to drive a commercial vehicle used to transport pre-primary, primary, or secondary school students to and from school?","options":["P (Passenger)","S (School Bus)","T (Doubles/Triples)","C (Children)"],"answer":1,"explanation":"The S (School Bus) endorsement is required in Michigan to drive a school bus transporting students; applicants must already hold (or obtain) the P endorsement and pass the school bus knowledge and skills tests. Source: Michigan CDL Manual (Michigan SOS).","handbook":"","hbref":""},{"q":"On a Michigan CDL, which single code letter appears when a driver has been issued BOTH the Tank (N) and Hazardous Materials (H) endorsements?","options":["X","Z","HN","K"],"answer":0,"explanation":"Michigan places the combined code X on the license in lieu of separate N and H codes when a driver holds both the tank and hazardous materials endorsements. Source: Michigan CDL Manual (Michigan SOS), endorsements section.","handbook":"","hbref":""},{"q":"The Michigan T endorsement covers double and triple trailer combinations. However, regarding TRIPLE trailers on Michigan roads, which statement is true?","options":["Triple trailer combinations are not permitted in Michigan","Triple trailers are allowed only on interstate highways in Michigan","Triple trailers require a separate Class A-T permit in Michigan","Triple trailers are allowed statewide in Michigan with no restriction"],"answer":0,"explanation":"Although the T (Doubles/Triples) endorsement exists, triple trailer combinations are not permitted on Michigan roads. Source: Michigan CDL Manual (Michigan SOS), endorsements section.","handbook":"","hbref":""},{"q":"For which endorsement must a Michigan CDL applicant pass a Transportation Security Administration (TSA) Security Threat Assessment, including fingerprinting and a background check?","options":["N (Tank)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"answer":2,"explanation":"The H (Hazardous Materials) endorsement requires a TSA Security Threat Assessment with fingerprints and a background check, in addition to the HazMat knowledge test. Source: Michigan SOS CDL information; TSA HME / 49 CFR 1572.","handbook":"","hbref":""},{"q":"Under Michigan/federal definitions, the N (Tank) endorsement is generally required to haul liquid or gas in a tank with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of at least how many gallons?","options":["500 gallons","1,000 gallons","1,500 gallons","3,000 gallons"],"answer":1,"explanation":"The Tank (N) endorsement applies to tanks of individual rated capacity over 119 gallons and an aggregate rated capacity of 1,000 gallons or more. Source: Michigan CDL Manual (Michigan SOS); 49 CFR 383.5.","handbook":"","hbref":""},{"q":"How frequently must a Michigan CDL holder renew the TSA Security Threat Assessment to keep a Hazardous Materials (H) endorsement valid?","options":["Every year","Every 3 years","Every 5 years","Every 10 years"],"answer":2,"explanation":"The TSA Security Threat Assessment for a HazMat endorsement must be renewed every 5 years, including new fingerprinting and background check. Source: Michigan SOS CDL information; TSA HME (49 CFR 1572).","handbook":"","hbref":""},{"q":"Effective February 7, 2022, Entry-Level Driver Training (ELDT) must be completed before testing for which of the following in Michigan?","options":["A first-time Class A or Class B CDL, an upgrade from Class B to Class A, or a first-time P, S, or H endorsement","Only a first-time Class A CDL","Any CDL renewal","Only the Tank (N) endorsement"],"answer":0,"explanation":"Federal ELDT, applied in Michigan, is required for a first-time Class A or Class B CDL, a Class B-to-A upgrade, and first-time Passenger (P), School Bus (S), or Hazardous Materials (H) endorsements. Source: FMCSA ELDT rule (49 CFR 380); Michigan SOS.","handbook":"","hbref":""},{"q":"A Michigan CDL applicant must complete required Entry-Level Driver Training (ELDT) through which entity?","options":["Any driving instructor of the applicant's choice","A provider listed on the FMCSA Training Provider Registry (TPR)","The Michigan Secretary of State directly","The Michigan State Police academy"],"answer":1,"explanation":"ELDT must be delivered by a school or entity listed on the FMCSA Training Provider Registry (TPR); completion is reported electronically to FMCSA. Source: FMCSA ELDT rule (49 CFR 380); Michigan SOS.","handbook":"","hbref":""},{"q":"Which endorsement does NOT require Entry-Level Driver Training (ELDT) when obtained for the first time on a Michigan CDL?","options":["H (Hazardous Materials)","P (Passenger)","S (School Bus)","N (Tank)"],"answer":3,"explanation":"ELDT is mandated for first-time H, P, and S endorsements, but the N (Tank) endorsement is not covered by the ELDT rule. Source: FMCSA ELDT rule (49 CFR 380.603); Michigan SOS.","handbook":"","hbref":""},{"q":"Which set of documents must a Michigan CDL applicant present at a Secretary of State office to establish eligibility?","options":["Only a photo and a credit card","Proof of identity/legal presence, proof of Social Security number, and proof of Michigan residency","Only an employer letter","Only a passport photo and cash payment"],"answer":1,"explanation":"Michigan requires proof of identity/legal presence in the U.S., proof of Social Security number, and proof of Michigan residency to issue a CLP or CDL. Source: Michigan SOS CDL/license document requirements.","handbook":"","hbref":""},{"q":"On the Michigan CDL self-certification, a driver who operates a CMV across state lines and is NOT exempt from the federal physical qualification rules must certify in which category?","options":["Excepted Interstate","Non-excepted Interstate","Excepted Intrastate","Non-excepted Intrastate"],"answer":1,"explanation":"Michigan uses four self-certification categories; a driver in interstate commerce subject to the medical rules certifies Non-excepted Interstate and must maintain a valid medical examiner's certificate. Source: Michigan SOS CDL Self-Certification Form.","handbook":"","hbref":""},{"q":"Which Michigan CDL self-certification category requires the driver to maintain and submit a valid medical examiner's certificate (DOT medical card) to the Secretary of State?","options":["Excepted Interstate","Excepted Intrastate","Non-excepted Interstate","Any driver under age 21"],"answer":2,"explanation":"Of the four categories, the two 'non-excepted' types require a valid medical examiner's certificate; the non-excepted interstate driver must keep a current DOT medical card on file with Michigan SOS. Source: Michigan SOS CDL Self-Certification (BFS-103).","handbook":"","hbref":""},{"q":"A Michigan applicant must achieve at least what score on the ELDT theory (knowledge) assessment to satisfy the training requirement before the CDL knowledge test?","options":["70%","75%","80%","90%"],"answer":2,"explanation":"Federal ELDT, applied in Michigan, requires a minimum theory assessment score of 80% from a Training Provider Registry provider. Source: FMCSA ELDT rule (49 CFR 380.609); Michigan SOS.","handbook":"","hbref":""},{"q":"At or above what blood alcohol concentration (BAC) is a CDL holder prohibited from operating a commercial motor vehicle in Michigan?","options":["0.08","0.04","0.02","0.10"],"answer":1,"explanation":"Operating a CMV with a BAC of 0.04 or greater is a major offense in Michigan. This is half the 0.08 limit that applies to ordinary drivers. Source: Michigan CDL Manual (alcohol/disqualification section); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"For a first major offense (such as operating a CMV with a BAC of 0.04 or greater), how long is the CDL disqualification in Michigan when no hazardous materials are involved?","options":["60 days","6 months","1 year","3 years"],"answer":2,"explanation":"A first major offense results in a 1-year CDL disqualification in Michigan. Source: 49 CFR 383.51 Table 1, adopted in Michigan via the Michigan Vehicle Code (MCL 257.319b); Michigan CDL Manual.","handbook":"","hbref":""},{"q":"How long is the CDL disqualification for a first major offense if the driver was operating a vehicle required to be placarded for hazardous materials?","options":["1 year","18 months","3 years","5 years"],"answer":2,"explanation":"A first major offense committed while operating a placarded HazMat vehicle results in a 3-year disqualification, rather than the standard 1 year. Source: 49 CFR 383.51 Table 1; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period for a second major offense (for example, a second alcohol-related conviction) in Michigan?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"A second major offense results in a lifetime CDL disqualification in Michigan. Source: 49 CFR 383.51 Table 1; Michigan CDL Manual; MCL 257.319b.","handbook":"","hbref":""},{"q":"Under Michigan's implied-consent law, a CDL holder who refuses a lawfully requested chemical (alcohol) test for the first time is disqualified from operating a CMV for how long?","options":["90 days","1 year","3 years","Lifetime"],"answer":1,"explanation":"A first refusal to submit to a required alcohol test is treated like a major offense and results in a 1-year CDL disqualification, whether the driver was in a CMV or a personal vehicle. Source: Michigan implied-consent law (MCL 257.625c); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for CDL purposes in Michigan?","options":["Operating a CMV with a BAC of 0.04 or greater","Speeding 15 mph or more over the posted limit","Leaving the scene of an accident involving a CMV","Refusing a chemical test"],"answer":1,"explanation":"Speeding 15 mph or more over the posted limit is a serious traffic violation. The other choices are major offenses, not serious violations. Source: 49 CFR 383.51 Table 2; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"A CDL holder is convicted of TWO serious traffic violations arising from separate incidents within a 3-year period. What is the disqualification period in Michigan?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"Two serious traffic violations in separate incidents within 3 years result in a 60-day CDL disqualification. Source: 49 CFR 383.51 Table 2; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"A CDL holder is convicted of THREE serious traffic violations from separate incidents within a 3-year period. What is the disqualification period?","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"Three or more serious traffic violations in separate incidents within 3 years result in a 120-day CDL disqualification. Source: 49 CFR 383.51 Table 2; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period must a CDL holder accumulate before ANY disqualification begins?","options":["One","Two","Three","Four"],"answer":1,"explanation":"A single serious traffic violation does not trigger disqualification; the first disqualification (60 days) applies upon the SECOND conviction within 3 years. Source: 49 CFR 383.51 Table 2; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"Which violation, committed in a commercial motor vehicle, is a designated serious traffic violation that can count toward the 60/120-day disqualification in Michigan?","options":["Texting while driving the CMV","Operating with a BAC of 0.04 or greater","Using a CMV to commit a felony","Violating an out-of-service order"],"answer":0,"explanation":"Texting while driving a CMV is listed as a serious traffic violation. BAC 0.04+ and using a CMV in a felony are major offenses, and an out-of-service order violation has its own separate penalty schedule. Source: 49 CFR 383.51 Table 2; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"A driver convicted of a FIRST railroad-highway grade crossing violation in a CMV is disqualified in Michigan for not less than how long?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation carries a disqualification of no less than 60 days. Source: 49 CFR 383.51 Table 3; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification for a SECOND railroad-highway grade crossing violation within a 3-year period?","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"A second railroad-highway grade crossing violation within 3 years carries a disqualification of no less than 120 days. Source: 49 CFR 383.51 Table 3; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a THIRD railroad-highway grade crossing violation within a 3-year period?","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third or subsequent railroad-highway grade crossing violation within 3 years carries a disqualification of no less than 1 year. Source: 49 CFR 383.51 Table 3; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"What is the disqualification period for a FIRST conviction of violating a driver or vehicle out-of-service order while operating a CMV (non-HazMat, non-passenger)?","options":["No less than 30 days","No less than 90 days but not more than 1 year","No less than 180 days but not more than 1 year","No less than 1 year but not more than 5 years"],"answer":2,"explanation":"A first out-of-service order violation results in disqualification of no less than 180 days and not more than 1 year. Source: 49 CFR 383.51 Table 4; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"What is the disqualification range for a SECOND out-of-service order violation in separate incidents within a 10-year period?","options":["No less than 180 days but not more than 1 year","No less than 1 year but not more than 3 years","No less than 2 years but not more than 5 years","No less than 3 years but not more than 5 years"],"answer":2,"explanation":"A second out-of-service order violation within 10 years results in disqualification of no less than 2 years and not more than 5 years. Source: 49 CFR 383.51 Table 4; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"A driver violates an out-of-service order for the FIRST time while transporting placarded hazardous materials or while carrying 16 or more passengers. What is the disqualification range?","options":["No less than 90 days but not more than 1 year","No less than 180 days but not more than 2 years","No less than 1 year but not more than 3 years","No less than 3 years but not more than 5 years"],"answer":1,"explanation":"A first out-of-service order violation while hauling placarded HazMat or carrying 16+ passengers results in disqualification of no less than 180 days and not more than 2 years. Source: 49 CFR 383.51 Table 4; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"Under federal rules adopted in Michigan, what is the maximum civil penalty a CMV driver may face for using a hand-held mobile phone or texting while driving?","options":["$500","$1,000","$2,750","$11,000"],"answer":2,"explanation":"A driver may be fined up to $2,750 for a hand-held phone or texting violation; an employer who allows or requires it may be fined up to $11,000. Source: 49 CFR 392.80/392.82 and FMCSA No-Texting/Hand-Held rule fact sheet; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"A CMV driver is found with any measured or detected alcohol while on duty, or who used or possessed alcohol within 4 hours before going on duty. What is the immediate consequence?","options":["Immediate 1-year CDL disqualification","Placed out of service for 24 hours","Placed out of service for 7 days","Immediate lifetime disqualification"],"answer":1,"explanation":"Under the alcohol prohibition, such a driver must be placed out of service for 24 hours. This is separate from the 0.04 major-offense threshold. Source: 49 CFR 392.5; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"A CDL holder is convicted of an alcohol-related driving offense while driving their OWN personal (non-commercial) vehicle. How does this affect the CDL in Michigan?","options":["It has no effect because no CMV was involved","It results in a 1-year CDL disqualification","It results only in a 60-day disqualification","It results only in points, not disqualification"],"answer":1,"explanation":"Major offenses, including alcohol offenses, trigger CDL disqualification even when committed in a personal vehicle; a first such offense is a 1-year disqualification. Source: 49 CFR 383.51 Table 1; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"A CMV driver registers a BAC of 0.02 or greater but less than 0.04. Which statement best describes the consequence under the rules applied in Michigan?","options":["It is treated as a major offense with a 1-year disqualification","There is no consequence below 0.04","The driver may not perform safety-sensitive functions for 24 hours","It is an automatic out-of-service order violation"],"answer":2,"explanation":"A confirmed alcohol concentration of 0.02 or greater but below 0.04 bars the driver from performing safety-sensitive functions for 24 hours; a disqualifying major offense begins at 0.04. Source: 49 CFR 382.505 and 383.51; Michigan CDL Manual.","handbook":"","hbref":""},{"q":"Under Michigan's Move Over law, when approaching a stationary emergency vehicle with lights activated and you cannot safely move over a lane, by how much must you reduce your speed below the posted speed limit?","options":["At least 10 mph below the posted speed limit","At least 5 mph below the posted speed limit","At least 15 mph below the posted speed limit","At least 20 mph below the posted speed limit"],"answer":0,"explanation":"Michigan's Move Over law (MCL 257.653a) requires a driver approaching a stationary authorized emergency vehicle with lights activated to move over at least one lane, or if that is not possible, to reduce speed to at least 10 mph below the posted speed limit and pass with due care. Source: MCL 257.653a; Michigan State Police Move Over campaign.","handbook":"","hbref":""},{"q":"On a Michigan roadway with two or more lanes for travel in one direction, where may a truck with a gross weight of more than 10,000 pounds, a truck-tractor, or a combination be driven?","options":["Only in either of the two lanes farthest to the right","In any lane, the same as passenger cars","Only in the single extreme right-hand lane at all times","Only in the center lane to avoid merging traffic"],"answer":0,"explanation":"Michigan law (MCL 257.634) requires that on a roadway with two or more lanes in one direction, a truck over 10,000 lbs, a truck-tractor, or a vehicle-and-trailer combination be driven only in one of the two lanes farthest to the right. Source: MCL 257.634.","handbook":"","hbref":""},{"q":"On a Michigan limited-access freeway where the posted speed limit is greater than 65 mph, what is the maximum speed for a truck with a gross weight of 10,000 pounds or more?","options":["65 mph","60 mph","70 mph","55 mph"],"answer":0,"explanation":"Under MCL 257.627, where the posted limit exceeds 65 mph, a truck of 10,000 lbs or more, a truck-tractor or combination, or a school bus may not exceed 65 mph on a limited-access freeway or state trunkline highway. This reflects the change made by Public Act 445 of 2016. Source: MCL 257.627.","handbook":"","hbref":""},{"q":"In Michigan, at what distance from the nearest rail must the driver of a placarded hazardous-materials vehicle stop before crossing a railroad track at grade?","options":["Within 50 feet but not less than 15 feet","Within 100 feet but not less than 25 feet","Within 40 feet but not less than 10 feet","Within 75 feet but not less than 20 feet"],"answer":0,"explanation":"MCL 257.669 requires drivers of placarded vehicles (and vehicles carrying 16+ passengers or passengers for hire) to activate hazard lights and stop within 50 feet but not less than 15 feet from the nearest rail before crossing. Source: MCL 257.669; Michigan CDL Manual Section 9.","handbook":"","hbref":""},{"q":"In Michigan, a vehicle meeting or overtaking a school bus that is stopped with two alternately flashing red lights must come to a full stop at what minimum distance from the bus?","options":["Not less than 20 feet","Not less than 10 feet","Not less than 15 feet","Not less than 30 feet"],"answer":0,"explanation":"MCL 257.682 requires a driver overtaking or meeting a school bus displaying flashing red lights to stop not less than 20 feet from the bus and not proceed until the bus moves or the signals are turned off. Source: MCL 257.682.","handbook":"","hbref":""},{"q":"In Michigan, on a highway divided into two roadways by a raised intervening space or physical barrier, which drivers are NOT required to stop for a school bus displaying flashing red lights on the opposite side?","options":["Drivers meeting the bus from the opposite roadway across the barrier","All drivers in both directions must still stop","Only drivers directly behind the bus","Only drivers in the lane nearest the bus"],"answer":0,"explanation":"Under MCL 257.682(2), where a highway is divided into two roadways by a raised intervening space, physical barrier, or clearly indicated dividing section, a driver meeting the bus across that division is not required to stop. Drivers traveling behind the bus on the same roadway must still stop. Source: MCL 257.682(2).","handbook":"","hbref":""},{"q":"When a Michigan CDL driver stops a commercial vehicle on the shoulder of a one-way or divided highway, where should the three reflective warning triangles be placed?","options":["At 10, 100, and 200 feet toward approaching traffic","At 10, 100, and 100 feet on both sides of the vehicle","At 25, 100, and 250 feet toward approaching traffic","At 50, 150, and 300 feet toward approaching traffic"],"answer":0,"explanation":"On a one-way or divided highway, warning devices are placed at 10, 100, and 200 feet from the rear of the vehicle toward approaching traffic. The Michigan CDL Manual follows the federal FMCSA standard (49 CFR 392.22). Source: Michigan CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a two-lane, two-way Michigan highway, how should a stopped CMV driver place the three warning triangles?","options":["One about 10 feet behind, one about 100 feet behind, and one about 100 feet ahead of the vehicle","All three about 100 feet behind the vehicle in a row","One at 10, one at 200, and one at 500 feet behind the vehicle","One on the hood and two about 50 feet behind the vehicle"],"answer":0,"explanation":"On a two-lane, two-way road, place one triangle about 10 feet to the rear toward approaching traffic, one about 100 feet to the rear, and one about 100 feet to the front of the vehicle. Source: Michigan CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"During Michigan's spring 'frost law' seasonal weight restrictions, what is the maximum speed for a commercial vehicle hauling a reduced-load weight on a restricted route, as set in the Michigan Vehicle Code?","options":["35 mph","45 mph","25 mph","55 mph"],"answer":0,"explanation":"MCL 257.627 provides that during periods when reduced (seasonal) load limits are in effect, vehicles operating under those reduced loads are limited to 35 mph. This is part of Michigan's distinctive frost-law program. Source: MCL 257.627; MDOT seasonal weight restrictions.","handbook":"","hbref":""},{"q":"Under Michigan's seasonal weight restrictions, which routes are designated as having NO reduction in legal axle weights during the spring thaw?","options":["'All-season' routes, shown in green and gold on the MDOT Truck Operators Map","All county gravel roads","Only interstate freeways inside city limits","Routes shown in solid or dashed red on the MDOT Truck Operators Map"],"answer":0,"explanation":"MDOT designates 'all-season' routes (green and gold on the MDOT Truck Operators Map) that keep full legal axle weights year-round, while 'seasonal' routes (solid or dashed red) are subject to spring axle-weight reductions. Source: MDOT Truck Operators Map / seasonal weight restriction guidance.","handbook":"","hbref":""},{"q":"During Michigan's spring weight restrictions on a 'seasonal' route, what axle-weight reduction applies to flexible (asphalt) pavement?","options":["35 percent","25 percent","10 percent","50 percent"],"answer":0,"explanation":"On seasonal routes during spring restrictions, MDOT imposes a 35 percent axle-weight reduction on flexible (asphalt) pavement and 25 percent on rigid (concrete) pavement. Source: MDOT seasonal weight restriction guidance.","handbook":"","hbref":""},{"q":"A Michigan CDL driver approaches a railroad crossing marked with a sign reading 'EXEMPT' while hauling a placarded load. What does Michigan law require?","options":["A stop is not required at a crossing marked 'exempt'","The driver must still stop within 50 feet of the nearest rail","The driver must stop and set out warning triangles","The driver must stop only if hazard lights are unavailable"],"answer":0,"explanation":"Under MCL 257.669, a stop is not required at a railroad grade crossing marked with a sign reading 'exempt,' even for placarded vehicles. At all other crossings the placarded vehicle must stop 15 to 50 feet from the nearest rail. Source: MCL 257.669.","handbook":"","hbref":""},{"q":"What is the maximum legal width of a commercial vehicle or its load in Michigan without an oversize permit?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":0,"explanation":"MCL 257.717 sets Michigan's maximum legal width at 96 inches (8 feet); anything wider requires an oversize permit. Note this is narrower than the 102-inch standard used by many other states. Source: MCL 257.717; MDOT Maximum Legal Truck Loadings and Dimensions.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a commercial vehicle, loaded or unloaded, in Michigan without a permit?","options":["13 feet 6 inches","14 feet 0 inches","13 feet 0 inches","12 feet 6 inches"],"answer":0,"explanation":"MCL 257.719 sets Michigan's maximum legal vehicle height, loaded or unloaded, at 13 feet 6 inches. Source: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions.","handbook":"","hbref":""},{"q":"On a Michigan freeway with three or more lanes for travel in the same direction, what does the lane-use law (MCL 257.634) say about which lane a vehicle must use?","options":["A vehicle is not prohibited from traveling in any lane of a freeway having three or more lanes in the same direction","All vehicles must remain in the extreme right lane unless passing","Trucks must use only the center lane","All vehicles must use only the two left lanes"],"answer":0,"explanation":"MCL 257.634 provides that the keep-right requirement does not prohibit a vehicle from traveling in any lane of a freeway having three or more lanes in the same direction. Heavy trucks remain limited to the two right-most lanes, however. Source: MCL 257.634.","handbook":"","hbref":""},{"q":"In Michigan, before crossing a railroad track at grade, the driver of a school bus must do which of the following in addition to stopping 15 to 50 feet from the nearest rail?","options":["Activate hazard lights, open the passenger door and driver window, and listen and look both ways","Sound the horn three times before proceeding","Place reflective triangles 100 feet behind the bus","Shift into a low gear and cross while accelerating"],"answer":0,"explanation":"MCL 257.1857 requires a school bus driver to stop 15-50 feet from the nearest rail, activate hazard warning lights, turn off noise sources, open the passenger door and driver-side window, and look and listen both ways before proceeding without shifting gears on the tracks. Source: MCL 257.1857.","handbook":"","hbref":""},{"q":"A CDL driver is on a Michigan two-lane county highway with no posted speed limit signs. What is the general statutory speed limit that applies?","options":["55 mph","45 mph","65 mph","60 mph"],"answer":0,"explanation":"MCL 257.627 sets a 55 mph general speed limit on trunkline and county highways where no other limit is posted (and a matching 55 mph general gravel-road speed limit). A heavy truck would not exceed this. Source: MCL 257.627.","handbook":"","hbref":""},{"q":"Which statement about toll roads is accurate for commercial drivers operating in Michigan?","options":["Michigan has no toll highways; tolls apply only at certain bridge and tunnel crossings such as the Mackinac, Blue Water, and International bridges","All Michigan interstate freeways are toll roads requiring a transponder","Trucks pay tolls on I-94 and I-75 but cars do not","Michigan charges tolls on all state trunkline highways during winter"],"answer":0,"explanation":"Michigan's interstate and state highways are toll-free; tolls are collected only at specific border and strait crossings such as the Mackinac Bridge, Blue Water Bridge, and the International Bridge at Sault Ste. Marie. Source: MDOT bridge toll information.","handbook":"","hbref":""},{"q":"Regarding routine periodic vehicle inspections, what is true for commercial vehicles registered in Michigan?","options":["Michigan does not require a statewide periodic safety or emissions inspection, though CMVs must still meet federal CMV inspection requirements","Michigan requires an annual emissions test for every commercial vehicle","Michigan requires a biennial safety inspection at a state-run station","Michigan requires a smog check before every CDL renewal"],"answer":0,"explanation":"Michigan does not mandate a statewide periodic safety or emissions inspection for vehicles. Commercial motor vehicles, however, remain subject to federal FMCSA inspection and maintenance requirements regardless of the lack of a state program. Source: Michigan SOS / MDOT; 49 CFR Part 396.","handbook":"","hbref":""},{"q":"Under Michigan's Move Over law, when traffic conditions allow you to change lanes for a stationary authorized emergency vehicle, how far over must you move?","options":["At least one moving lane or two vehicle widths from the stationary vehicle","Completely off the roadway onto the far shoulder","At least three vehicle widths from the stationary vehicle","Into the leftmost lane regardless of position"],"answer":0,"explanation":"MCL 257.653a requires drivers, when possible, to move into a lane at least one moving lane or two vehicle widths away from the stationary authorized emergency vehicle, while also slowing to at least 10 mph below the posted limit. Source: MCL 257.653a.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in Michigan?","options":["The Michigan State Police Commercial Vehicle Division","The Michigan Department of Transportation (MDOT)","The Michigan Department of State (Secretary of State)","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":2,"explanation":"In Michigan, CDLs are issued by the Michigan Department of State, headed by the Secretary of State; CDL knowledge tests and applications are handled at SOS offices. Source: Michigan CDL Manual (SOS) and michigan.gov SOS CDL pages.","handbook":"","hbref":""},{"q":"Where are CDL on-road and basic control skills tests administered in Michigan?","options":["At any Secretary of State branch office by SOS staff","At FMCSA regional testing centers","By the Michigan State Police motor carrier officers","By MDOS-approved third-party driver testing businesses"],"answer":3,"explanation":"Michigan does not give CDL skills tests at SOS branches; the three-part skills test is administered by Michigan Department of State (MDOS)-approved third-party driver testing businesses. Source: Michigan CDL Manual (SOS).","handbook":"","hbref":""},{"q":"How many parts make up the Michigan CDL skills test?","options":["Two: a written test and an on-road driving test","Three: pre-trip inspection, basic vehicle control, and on-road driving","Two: basic control skills and a hazardous materials check","Four: pre-trip, backing, on-road, and a written safety test"],"answer":1,"explanation":"The Michigan CDL skills test has three parts: the vehicle (pre-trip) inspection test, the basic vehicle control skills test, and the on-road driving test, all of which must be passed. Source: Michigan CDL Manual (SOS).","handbook":"","hbref":""},{"q":"Before a first-time CDL applicant can take the skills test in Michigan, what federal training must be completed?","options":["An employer-sponsored apprenticeship of at least six months","A 40-hour hazardous materials safety course","Entry-Level Driver Training (ELDT) from a registered provider","A defensive driving course approved by MDOT"],"answer":2,"explanation":"Since February 7, 2022, the FMCSA Entry-Level Driver Training (ELDT) rule requires first-time CDL applicants (and certain upgrades/endorsements) to complete ELDT from a provider on the FMCSA Training Provider Registry before the skills test. Source: Michigan CDL Manual (SOS); FMCSA ELDT rule.","handbook":"","hbref":""},{"q":"After receiving a CLP, how long must a Michigan applicant wait before taking the CDL skills test?","options":["At least 7 days","At least 60 days","At least 14 days","At least 30 days"],"answer":2,"explanation":"Federal and Michigan rules require the CLP to be held for at least 14 days before the applicant may take the CDL skills test. Source: Michigan CDL Manual (SOS); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"When self-certifying their type of driving for a Michigan CDL, how many federal categories must an applicant choose from?","options":["Two","Five","Three","Four"],"answer":3,"explanation":"Every Michigan CDL applicant must self-certify to one of four categories: non-excepted interstate, excepted interstate, non-excepted intrastate, or excepted intrastate. Source: Michigan CDL Self-Certification Form (SOS); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which self-certification category requires a Michigan driver to maintain a federal DOT medical examiner's certificate?","options":["None of the categories require a medical certificate","Non-excepted interstate","Excepted intrastate","Excepted interstate"],"answer":1,"explanation":"A driver self-certifying as 'non-excepted interstate' operates in interstate commerce and must maintain a valid DOT medical examiner's certificate; the 'excepted' categories do not require it for the same reason. Source: Michigan CDL Self-Certification Form (SOS); 49 CFR 383.71/391.","handbook":"","hbref":""},{"q":"What does a Michigan driver mean when self-certifying as 'excepted intrastate'?","options":["They drive across state lines but are excepted from all federal rules","They drive only within Michigan but must hold a federal medical card","They drive only within Michigan in operations the state has excepted from medical certification requirements","They drive interstate and must keep their medical card on file with the SOS"],"answer":2,"explanation":"'Excepted intrastate' means the driver operates a CMV only within Michigan in activities the state has determined are excepted from the medical certification requirement, so a federal medical card is not required. Source: Michigan CDL Self-Certification Form (SOS); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a CDL for driving a commercial motor vehicle only within Michigan (intrastate)?","options":["21 years old","19 years old","18 years old","16 years old"],"answer":2,"explanation":"An applicant must be at least 18 to hold a CDL for intrastate (Michigan-only) commercial driving; interstate operation generally requires age 21. Source: Michigan CDL Manual (SOS); MCL 257.312e.","handbook":"","hbref":""},{"q":"On the Michigan CDL knowledge tests, which test must every CDL applicant pass regardless of vehicle class?","options":["The general knowledge test","The passenger transport test","The hazardous materials test","The doubles/triples test"],"answer":0,"explanation":"All CDL applicants must pass the general knowledge test; additional knowledge tests (e.g., air brakes, combination, endorsements) depend on the class and endorsements sought. Source: Michigan CDL Manual (SOS); 49 CFR 383.23.","handbook":"","hbref":""},{"q":"At a Michigan CDL renewal in a Secretary of State office, which of these is part of the standard process?","options":["A mandatory written hazardous materials test for all renewals","A vision screening and a review of the applicant's state and national driving record","An automatic new DOT physical performed by SOS staff","Retaking the full three-part skills test every cycle"],"answer":1,"explanation":"At renewal the SOS office performs a vision test and checks the applicant's state and national (CDLIS) driving records; a full skills retest is not routinely required. Note: exact fees can change. Source: Michigan CDL Manual (SOS); michigan.gov SOS CDL renewal page.","handbook":"","hbref":""}],"ru":{"0":{"q":"На обозначенных автомагистралях штата Мичиган какова максимальная допустимая ширина коммерческого транспортного средства (без учёта зеркал и некоторого оборудования безопасности), при превышении которой требуется разрешение на негабаритный груз?","options":["108 inches (9 feet)","96 inches (8 feet)","120 inches (10 feet)","102 inches (8 feet 6 inches)"],"explanation":"Мичиган ограничивает ширину транспортного средства до 102 inches (8'6\") на обозначенных автомагистралях и до 96 inches (8') на остальных дорогах, что соответствует федеральному стандарту национальной сети. Источник: Michigan Vehicle Code MCL 257.717; MDOT 'Maximum Legal Truck Loadings and Dimensions' (T-1)."},"1":{"q":"Какова максимальная допустимая высота транспортного средства вместе с грузом на автомагистралях штата Мичиган без специального транспортного разрешения?","options":["14 feet 0 inches","13 feet 6 inches","14 feet 6 inches","13 feet 0 inches"],"explanation":"Мичиган устанавливает максимальную высоту транспортного средства с грузом в 13 feet 6 inches; всё, что выше, требует разрешения на негабаритный груз. Источник: MCL 257.718; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"2":{"q":"Какова максимальная длина полуприцепа (включая груз), эксплуатируемого на обозначенных автомагистралях штата Мичиган без разрешения?","options":["60 feet","48 feet","53 feet","57 feet"],"explanation":"Мичиган допускает полуприцеп длиной до 53 feet, включая груз, на обозначенных автомагистралях (50 feet на необозначенных дорогах). Источник: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"3":{"q":"Согласно федеральным ограничениям, которые Мичиган применяет в системе межштатных автомагистралей (Interstate), какова максимальная полная масса для стандартного 5-осного автопоезда без разрешения?","options":["88,000 pounds","76,000 pounds","73,280 pounds","80,000 pounds"],"explanation":"В системе Interstate Мичиган применяет федеральный предел полной массы в 80,000 pounds для транспортных средств, подпадающих под федеральную мостовую формулу. Источник: 23 CFR 658.17 в применении в Мичигане; рекомендации MDOT по массе грузовиков."},"4":{"q":"Каков федеральный предел нагрузки на одиночную ось, применяемый к транспортным средствам, работающим в рамках федерального стандарта 80,000 pounds на межштатных автомагистралях штата Мичиган?","options":["24,000 pounds","22,400 pounds","18,000 pounds","20,000 pounds"],"explanation":"Для транспортных средств, подпадающих под федеральный стандарт 80,000 pounds, предел нагрузки на одиночную ось составляет 20,000 pounds — ту же величину Мичиган применяет на Interstate. Источник: 23 CFR 658.17 в применении в Мичигане; рекомендации MDOT по массе."},"5":{"q":"Согласно федеральному стандарту, применяемому в системе межштатных автомагистралей штата Мичиган, каков максимальный вес, допустимый на группу спаренных осей (тандем)?","options":["36,000 pounds","40,000 pounds","32,000 pounds","34,000 pounds"],"explanation":"Федеральный предел для спаренных осей, который Мичиган применяет на Interstate, составляет 34,000 pounds. Обратите внимание, что собственные осевые нормы Мичигана отличаются (см. его обычный максимум нагрузки на ось в 18,000-lb). Источник: 23 CFR 658.17; рекомендации MDOT по массе."},"6":{"q":"В силу осевых норм, предшествующих федеральным ограничениям, какова максимальная полная масса, которую правильно сконфигурированный грузовик может законно перевозить по дорогам Мичигана за пределами системы Interstate?","options":["80,000 pounds","164,000 pounds","105,500 pounds","129,000 pounds"],"explanation":"«Дедушкин» закон Мичигана о массе допускает максимальную полную массу около 164,000 pounds при соблюдении осевых нагрузок и расстояний между осями — самый высокий показатель, регулярно допускаемый в Северной Америке. Источник: MCL 257.722; Michigan House Fiscal Agency, 'Michigan's Truck-Weight Law.'"},"7":{"q":"Каково максимальное число осей, допустимое для автопоезда (грузовик с прицепом) в Мичигане, работающего в рамках положений штата о повышенной массе?","options":["8 axles","11 axles","9 axles","13 axles"],"explanation":"С 1967 года Мичиган ограничивает такие автопоезда 11 осями, что вместе с пределами нагрузки на ось даёт максимум примерно в 164,000-pounds. Источник: MCL 257.722; анализ закона о массе грузовиков Michigan House Fiscal Agency."},"8":{"q":"Согласно собственному закону Мичигана об осевой нагрузке, каков «обычный максимум загрузки» для одиночной оси, расположенной на расстоянии 9 feet или более от соседних осей?","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,400 pounds"],"explanation":"Закон Мичигана устанавливает обычный максимум нагрузки на одиночную ось в 18,000 pounds, если расстояние между осями составляет 9 feet или более, что ниже федерального показателя в 20,000-lb. Источник: MCL 257.722(1)."},"9":{"q":"Осевой закон штата Мичиган ограничивает максимальную нагрузку на колесо величиной, привязанной к ширине шины. Каков этот предел?","options":["500 pounds per inch of tire width","700 pounds per inch of tire width","600 pounds per inch of tire width","850 pounds per inch of tire width"],"explanation":"Мичиган ограничивает нагрузку на колесо до 700 pounds per inch of tire width — стандарт, который распределяет тяжёлые грузы на большее число шин и осей. Источник: MCL 257.722(7)."},"10":{"q":"В период весеннего оттаивания (закон о промерзании, frost law) в Мичигане на какой процент снижаются максимальные осевые нагрузки на бетонных покрытиях?","options":["25 percent","35 percent","10 percent","50 percent"],"explanation":"В марте, апреле и мае Мичиган снижает максимальные осевые нагрузки на 25 percent на бетонных покрытиях (и на 35 percent на остальных дорогах), чтобы защитить оттаивающее дорожное основание. Источник: MCL 257.722(8)."},"11":{"q":"В период сезонных ограничений по закону о промерзании (frost law) в Мичигане осевые нагрузки на дорогах, отличных от бетонного покрытия, снижаются на какой процент?","options":["15 percent","45 percent","35 percent","25 percent"],"explanation":"На небетонных дорогах весенние ограничения по массе в Мичигане снижают максимальные осевые нагрузки на 35 percent в период оттаивания с марта по май. Источник: MCL 257.722(8)."},"12":{"q":"В какие месяцы обычно действует сезонное снижение массы (закон о промерзании, frost law) в Мичигане?","options":["March, April, and May","January, February, and March","November, December, and January","April, May, and June"],"explanation":"Сезонные снижения осевых нагрузок в Мичигане действуют в период весеннего оттаивания, законодательно привязанного к марту, апрелю и маю, с точными датами начала/окончания, объявляемыми MDOT каждый год. Источник: MCL 257.722(8); уведомления MDOT о сезонных ограничениях массы."},"13":{"q":"Закон Мичигана допускает выступ груза на автопоезде за заднюю часть транспортного средства на какое расстояние, прежде чем потребуется дополнительное предупреждение?","options":["2 feet","3 feet","4 feet","6 feet"],"explanation":"Груз может выступать до 4 feet за заднюю часть (и на 3 feet за переднюю); задний свес в 4 feet или более требует красного флажка днём и красного фонаря ночью. Источник: MCL 257.719; рекомендации MDOT по габаритам груза."},"14":{"q":"Груз, выступающий за заднюю часть коммерческого транспортного средства в Мичигане, должен иметь красный фонарь или лампу в ночное время, как только свес достигает какой длины?","options":["8 feet","2 feet","4 feet","6 feet"],"explanation":"Мичиган требует красный флажок днём и красный фонарь или лампу ночью для любого груза, выступающего на 4 feet или более за заднюю часть транспортного средства. Источник: MCL 257.719; рекомендации MDOT по габаритам груза."},"15":{"q":"Кто выдаёт разрешения на перевозку негабаритных/тяжеловесных грузов для движения по магистралям государственной дорожной сети штата Мичиган (state trunkline highways)?","options":["Federal Motor Carrier Safety Administration","Только Michigan State Police","Michigan Department of Transportation (MDOT)","Michigan Secretary of State"],"explanation":"MDOT выдаёт разрешения на превышение габаритов или массы на государственных магистралях (state trunklines), тогда как местные дорожные органы занимаются дорогами в пределах своей юрисдикции. Источник: MCL 257.725; MDOT Oversize/Overweight Permits."},"16":{"q":"Через какую онлайн-систему перевозчик подаёт заявку на разрешение MDOT на негабаритный/тяжеловесный груз в Мичигане?","options":["CDLIS (Commercial Driver License Information System)","IRP (International Registration Plan portal)","SAFER (Safety and Fitness Electronic Records)","MiTRIP (Michigan Transport Routing and Internet Permitting)"],"explanation":"Перевозчики Мичигана получают транспортные разрешения в электронном виде через MiTRIP — онлайн-систему маршрутизации и выдачи разрешений MDOT. Источник: MDOT Oversize/Overweight Permits; MCL 257.725."},"17":{"q":"Разрешение на одну поездку с негабаритным грузом в Мичигане, как правило, выдаётся для эпизодической перевозки груза, который:","options":["Перемещается полностью по частной территории","Не может быть разобран или переставлен, чтобы вписаться в допустимые пределы","Перевозчик просто предпочитает не разбивать на более мелкие грузы","Превышает допустимые пределы менее чем на один процент"],"explanation":"Разрешения в Мичигане выдаются только для эпизодической перевозки негабаритных или тяжеловесных грузов, которые невозможно разумно разобрать, уменьшить или переставить так, чтобы вписаться в допустимые пределы. Источник: MCL 257.725; разрешительная политика MDOT."},"18":{"q":"Согласно положению Мичигана о транспортных средствах на природном газе, насколько транспортное средство, работающее на природном газе, может превышать применимые пределы массы, чтобы учесть более тяжёлую топливную систему?","options":["5,000 pounds","2,000 pounds","550 pounds","10,000 pounds"],"explanation":"Мичиган предоставляет транспортным средствам на природном газе допуск до 2,000 pounds сверх применимых в иных случаях пределов массы, чтобы компенсировать дополнительный вес топливной системы. Источник: Michigan Vehicle Code; рекомендации MDOT по массе, согласующиеся с федеральным допуском для NGV по 23 U.S.C. 127."},"19":{"q":"Для мичиганского автопоезда, например тягача, буксирующего два прицепных звена, какова максимальная общая длина (измеряемая от передней части первого прицепного звена до задней части последнего), прежде чем потребуется разрешение?","options":["75 feet","58 feet","65 feet","53 feet"],"explanation":"Мичиган допускает такие двойные сцепки без фиксированной общей длины транспортного средства при условии, что прицепные звенья, измеренные от передней части первого до задней части последнего, не превышают 58 feet (каждое звено не более 28'6\"). Источник: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"20":{"q":"В Мичигане какая группа CDL требуется для управления любым автопоездом с полной массой автопоезда (GCWR) 26,001 pounds или более, где буксируемое звено имеет GVWR более 10,000 pounds?","options":["Group A","Group B","Group C","Group D"],"explanation":"Мичиган определяет CDL группы (класса) A как любой автопоезд с GCWR 26,001 lbs или более при условии, что GVWR буксируемого звена (звеньев) превышает 10,000 lbs. Источник: Michigan CDL Manual (Michigan SOS), Section 1."},"21":{"q":"Согласно правилам Мичигана, какая группа CDL охватывает одиночное транспортное средство с полной массой (GVWR) 26,001 pounds или более (которое может буксировать звено массой 10,000 pounds или менее)?","options":["Group A","Group B","Group C","Group H"],"explanation":"CDL группы (класса) B в Мичигане предназначена для любого одиночного транспортного средства с GVWR 26,001 lbs или более, либо для такого транспортного средства, буксирующего звено с GVWR не более 10,000 lbs. Источник: Michigan CDL Manual (Michigan SOS), Section 1."},"22":{"q":"CDL группы (класса) C в Мичигане требуется для более лёгкого транспортного средства (ниже весовых порогов класса A/B) только тогда, когда оно используется для перевозки чего из перечисленного?","options":["Любого груза весом более 5,000 pounds","16 или более пассажиров (включая водителя) либо опасных материалов в количествах, требующих табличек (placards)","Любого прицепа независимо от веса","Только школьников"],"explanation":"CDL группы C в Мичигане применяется к транспортным средствам ниже весовых пределов класса A/B, которые рассчитаны на перевозку 16 или более пассажиров, включая водителя, либо перевозят опасные материалы в количествах, требующих табличек (placards). Источник: Michigan CDL Manual (Michigan SOS), Section 1."},"23":{"q":"Каков минимальный возраст для получения CDL в Мичигане для ВНУТРИШТАТНОГО вождения (управление только в пределах Мичигана)?","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"Мичиган разрешает CDL с 18 лет только для внутриштатной торговли; межштатная эксплуатация требует возраста 21 год. Источник: Michigan CDL Manual (Michigan SOS) / критерии права на CDL Michigan SOS."},"24":{"q":"Каков минимальный возраст для получения CDL в Мичигане, дающей право на МЕЖШТАТНОЕ вождение (через границы штатов)?","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"Федеральные правила и правила Мичигана требуют, чтобы водителю было не менее 21 года для управления CMV в межштатной торговле; водители в возрасте 18-20 лет ограничены внутриштатной эксплуатацией. Источник: Michigan CDL Manual (Michigan SOS); 49 CFR 391.11."},"25":{"q":"В Мичигане как долго заявитель должен иметь Commercial Learner's Permit (CLP), прежде чем ему будет разрешено сдавать дорожный экзамен по навыкам CDL?","options":["Минимум 7 days","Минимум 14 days","Минимум 30 days","Минимум 60 days"],"explanation":"Мичиган следует федеральному правилу, требующему, чтобы CLP удерживался минимум 14 days, прежде чем заявитель сможет сдавать экзамен по навыкам CDL. Источник: Michigan SOS (cdl-apply); 49 CFR 383.25."},"26":{"q":"Какое дополнение (endorsement) требуется на CDL в Мичигане для управления транспортным средством, рассчитанным на перевозку 16 или более человек, включая водителя?","options":["P (Passenger)","N (Tank)","T (Doubles/Triples)","H (Hazardous Materials)"],"explanation":"Дополнение P (Passenger) требуется в Мичигане для управления транспортным средством, рассчитанным на перевозку 16 или более человек, включая водителя. Источник: Michigan CDL Manual (Michigan SOS), раздел о дополнениях."},"27":{"q":"Какое дополнение (endorsement) к CDL в Мичигане требуется для управления коммерческим транспортным средством, используемым для перевозки учащихся дошкольных, начальных или средних учебных заведений в школу и обратно?","options":["P (Passenger)","S (School Bus)","T (Doubles/Triples)","C (Children)"],"explanation":"Дополнение S (School Bus) требуется в Мичигане для управления школьным автобусом, перевозящим учащихся; заявители уже должны иметь (или получить) дополнение P и сдать тесты на знания и навыки по школьному автобусу. Источник: Michigan CDL Manual (Michigan SOS)."},"28":{"q":"На CDL в Мичигане какая единая буква-код проставляется, когда водителю выданы ОБА дополнения — Tank (N) и Hazardous Materials (H)?","options":["X","Z","HN","K"],"explanation":"Мичиган проставляет в правах объединённый код X вместо отдельных кодов N и H, когда водитель имеет оба дополнения — на цистерны и на опасные материалы. Источник: Michigan CDL Manual (Michigan SOS), раздел о дополнениях."},"29":{"q":"Дополнение T в Мичигане охватывает сцепки с двойными и тройными прицепами. Однако в отношении ТРОЙНЫХ прицепов на дорогах Мичигана какое утверждение верно?","options":["Сцепки с тройными прицепами в Мичигане не разрешены","Тройные прицепы разрешены только на межштатных автомагистралях в Мичигане","Тройные прицепы требуют отдельного разрешения класса A-T в Мичигане","Тройные прицепы разрешены по всему штату в Мичигане без ограничений"],"explanation":"Хотя дополнение T (Doubles/Triples) существует, сцепки с тройными прицепами на дорогах Мичигана не разрешены. Источник: Michigan CDL Manual (Michigan SOS), раздел о дополнениях."},"30":{"q":"Для какого дополнения заявитель на CDL в Мичигане должен пройти оценку угрозы безопасности (Security Threat Assessment) Transportation Security Administration (TSA), включая снятие отпечатков пальцев и проверку биографии?","options":["N (Tank)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"explanation":"Дополнение H (Hazardous Materials) требует оценки угрозы безопасности TSA с отпечатками пальцев и проверкой биографии, помимо теста на знания по HazMat. Источник: информация о CDL Michigan SOS; TSA HME / 49 CFR 1572."},"31":{"q":"Согласно определениям Мичигана/федеральным определениям, дополнение N (Tank) обычно требуется для перевозки жидкости или газа в цистерне с индивидуальной номинальной ёмкостью более 119 gallons и совокупной номинальной ёмкостью не менее скольких галлонов?","options":["500 gallons","1,000 gallons","1,500 gallons","3,000 gallons"],"explanation":"Дополнение Tank (N) применяется к цистернам с индивидуальной номинальной ёмкостью более 119 gallons и совокупной номинальной ёмкостью 1,000 gallons или более. Источник: Michigan CDL Manual (Michigan SOS); 49 CFR 383.5."},"32":{"q":"Как часто держатель CDL в Мичигане должен обновлять оценку угрозы безопасности (Security Threat Assessment) TSA, чтобы сохранить действительным дополнение Hazardous Materials (H)?","options":["Каждый год","Каждые 3 years","Каждые 5 years","Каждые 10 years"],"explanation":"Оценка угрозы безопасности TSA для дополнения HazMat должна обновляться каждые 5 years, включая повторное снятие отпечатков пальцев и проверку биографии. Источник: информация о CDL Michigan SOS; TSA HME (49 CFR 1572)."},"33":{"q":"С 7 февраля 2022 года обучение водителей начального уровня (Entry-Level Driver Training, ELDT) должно быть завершено до сдачи экзаменов на что из перечисленного в Мичигане?","options":["Впервые получаемая CDL класса A или класса B, повышение с класса B до класса A или впервые получаемое дополнение P, S или H","Только впервые получаемая CDL класса A","Любое продление CDL","Только дополнение Tank (N)"],"explanation":"Федеральное ELDT, применяемое в Мичигане, требуется для впервые получаемой CDL класса A или класса B, для повышения с класса B до A, а также для впервые получаемых дополнений Passenger (P), School Bus (S) или Hazardous Materials (H). Источник: FMCSA ELDT rule (49 CFR 380); Michigan SOS."},"34":{"q":"Заявитель на CDL в Мичигане должен пройти требуемое обучение водителей начального уровня (Entry-Level Driver Training, ELDT) через какую организацию?","options":["Любого инструктора по вождению на выбор заявителя","Провайдера, внесённого в реестр провайдеров обучения FMCSA (Training Provider Registry, TPR)","Напрямую через Michigan Secretary of State","Академию Michigan State Police"],"explanation":"ELDT должно проводиться школой или организацией, внесённой в реестр провайдеров обучения FMCSA (Training Provider Registry, TPR); о прохождении сообщается в FMCSA в электронном виде. Источник: FMCSA ELDT rule (49 CFR 380); Michigan SOS."},"35":{"q":"Какое дополнение НЕ требует обучения водителей начального уровня (Entry-Level Driver Training, ELDT) при получении его впервые на CDL в Мичигане?","options":["H (Hazardous Materials)","P (Passenger)","S (School Bus)","N (Tank)"],"explanation":"ELDT обязательно для впервые получаемых дополнений H, P и S, но дополнение N (Tank) не подпадает под правило ELDT. Источник: FMCSA ELDT rule (49 CFR 380.603); Michigan SOS."},"36":{"q":"Какой набор документов заявитель на CDL в Мичигане должен предъявить в офисе Secretary of State, чтобы подтвердить право на получение?","options":["Только фотографию и кредитную карту","Подтверждение личности/законного присутствия, подтверждение номера Social Security и подтверждение проживания в Мичигане","Только письмо от работодателя","Только фотографию на паспорт и оплату наличными"],"explanation":"Мичиган требует подтверждение личности/законного присутствия в США, подтверждение номера Social Security и подтверждение проживания в Мичигане для выдачи CLP или CDL. Источник: требования к документам для CDL/прав Michigan SOS."},"37":{"q":"В самосертификации CDL в Мичигане водитель, который управляет CMV через границы штатов и НЕ освобождён от федеральных правил физической квалификации, должен сертифицироваться в какой категории?","options":["Excepted Interstate","Non-excepted Interstate","Excepted Intrastate","Non-excepted Intrastate"],"explanation":"Мичиган использует четыре категории самосертификации; водитель в межштатной торговле, подпадающий под медицинские правила, сертифицируется как Non-excepted Interstate и должен иметь действительный сертификат медицинского эксперта (medical examiner's certificate). Источник: Michigan SOS CDL Self-Certification Form."},"38":{"q":"Какая категория самосертификации CDL в Мичигане требует, чтобы водитель имел и подавал в Secretary of State действительный сертификат медицинского эксперта (DOT medical card)?","options":["Excepted Interstate","Excepted Intrastate","Non-excepted Interstate","Любой водитель младше 21 года"],"explanation":"Из четырёх категорий два типа «non-excepted» требуют действительного сертификата медицинского эксперта; водитель категории non-excepted interstate должен держать актуальную DOT medical card в деле в Michigan SOS. Источник: Michigan SOS CDL Self-Certification (BFS-103)."},"39":{"q":"Какой минимальный балл заявитель в Мичигане должен набрать на теоретической (на знания) оценке ELDT, чтобы выполнить требование обучения до теста на знания CDL?","options":["70%","75%","80%","90%"],"explanation":"Федеральное ELDT, применяемое в Мичигане, требует минимального балла теоретической оценки в 80% от провайдера из реестра Training Provider Registry. Источник: FMCSA ELDT rule (49 CFR 380.609); Michigan SOS."},"40":{"q":"При какой концентрации алкоголя в крови (BAC) и выше держателю CDL запрещено управлять коммерческим транспортным средством в Мичигане?","options":["0.08","0.04","0.02","0.10"],"explanation":"Управление CMV с BAC 0.04 или выше является серьёзным нарушением (major offense) в Мичигане. Это половина предела 0.08, применяемого к обычным водителям. Источник: Michigan CDL Manual (раздел об алкоголе/дисквалификации); 49 CFR 383.51 Table 1."},"41":{"q":"За первое серьёзное нарушение (например, управление CMV с BAC 0.04 или выше) на какой срок дисквалифицируется CDL в Мичигане, если опасные материалы не задействованы?","options":["60 days","6 months","1 year","3 years"],"explanation":"Первое серьёзное нарушение влечёт дисквалификацию CDL на 1 year в Мичигане. Источник: 49 CFR 383.51 Table 1, принятая в Мичигане через Michigan Vehicle Code (MCL 257.319b); Michigan CDL Manual."},"42":{"q":"На какой срок дисквалифицируется CDL за первое серьёзное нарушение, если водитель управлял транспортным средством, обязанным иметь таблички (placards) для опасных материалов?","options":["1 year","18 months","3 years","5 years"],"explanation":"Первое серьёзное нарушение, совершённое при управлении транспортным средством с табличками (placards) HazMat, влечёт дисквалификацию на 3 years вместо стандартного 1 year. Источник: 49 CFR 383.51 Table 1; Michigan CDL Manual."},"43":{"q":"Каков срок дисквалификации CDL за второе серьёзное нарушение (например, второе осуждение, связанное с алкоголем) в Мичигане?","options":["3 years","5 years","10 years","Пожизненно"],"explanation":"Второе серьёзное нарушение влечёт пожизненную дисквалификацию CDL в Мичигане. Источник: 49 CFR 383.51 Table 1; Michigan CDL Manual; MCL 257.319b."},"44":{"q":"Согласно закону Мичигана о подразумеваемом согласии (implied-consent), держатель CDL, впервые отказавшийся от законно запрошенной химической (на алкоголь) проверки, дисквалифицируется от управления CMV на какой срок?","options":["90 days","1 year","3 years","Пожизненно"],"explanation":"Первый отказ пройти требуемую проверку на алкоголь приравнивается к серьёзному нарушению и влечёт дисквалификацию CDL на 1 year, независимо от того, был ли водитель в CMV или личном автомобиле. Источник: закон Мичигана о подразумеваемом согласии (MCL 257.625c); 49 CFR 383.51 Table 1."},"45":{"q":"Что из перечисленного классифицируется как «серьёзное нарушение ПДД» (serious traffic violation) для целей CDL в Мичигане?","options":["Управление CMV с BAC 0.04 или выше","Превышение скорости на 15 mph или более сверх установленного предела","Оставление места происшествия с участием CMV","Отказ от химической проверки"],"explanation":"Превышение скорости на 15 mph или более сверх установленного предела является серьёзным нарушением ПДД. Остальные варианты — это серьёзные нарушения (major offenses), а не serious violations. Источник: 49 CFR 383.51 Table 2; Michigan CDL Manual."},"46":{"q":"Держатель CDL осуждён за ДВА серьёзных нарушения ПДД, возникших в результате отдельных инцидентов в течение периода 3 years. Каков срок дисквалификации в Мичигане?","options":["30 days","60 days","120 days","1 year"],"explanation":"Два серьёзных нарушения ПДД в отдельных инцидентах в течение 3 years влекут дисквалификацию CDL на 60 days. Источник: 49 CFR 383.51 Table 2; Michigan CDL Manual."},"47":{"q":"Держатель CDL осуждён за ТРИ серьёзных нарушения ПДД из отдельных инцидентов в течение периода 3 years. Каков срок дисквалификации?","options":["60 days","90 days","120 days","1 year"],"explanation":"Три или более серьёзных нарушений ПДД в отдельных инцидентах в течение 3 years влекут дисквалификацию CDL на 120 days. Источник: 49 CFR 383.51 Table 2; Michigan CDL Manual."},"48":{"q":"Сколько серьёзных нарушений ПДД в течение периода 3 years держатель CDL должен накопить, прежде чем начнётся КАКАЯ-ЛИБО дисквалификация?","options":["Одно","Два","Три","Четыре"],"explanation":"Одно серьёзное нарушение ПДД не влечёт дисквалификации; первая дисквалификация (60 days) применяется при ВТОРОМ осуждении в течение 3 years. Источник: 49 CFR 383.51 Table 2; Michigan CDL Manual."},"49":{"q":"Какое нарушение, совершённое в коммерческом транспортном средстве, является назначенным серьёзным нарушением ПДД (serious traffic violation), которое может засчитываться в дисквалификацию на 60/120 days в Мичигане?","options":["Отправка текстовых сообщений во время управления CMV","Управление с BAC 0.04 или выше","Использование CMV для совершения тяжкого преступления (felony)","Нарушение приказа о выводе из эксплуатации (out-of-service order)"],"explanation":"Отправка текстовых сообщений во время управления CMV указана как серьёзное нарушение ПДД. BAC 0.04+ и использование CMV в тяжком преступлении являются серьёзными нарушениями (major offenses), а нарушение приказа о выводе из эксплуатации имеет собственную отдельную шкалу наказаний. Источник: 49 CFR 383.51 Table 2; Michigan CDL Manual."},"50":{"q":"Водитель, осуждённый за ПЕРВОЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) в CMV, дисквалифицируется в Мичигане не менее чем на какой срок?","options":["30 days","60 days","120 days","1 year"],"explanation":"Первое нарушение на железнодорожном переезде влечёт дисквалификацию не менее чем на 60 days. Источник: 49 CFR 383.51 Table 3; Michigan CDL Manual."},"51":{"q":"Какова минимальная дисквалификация CDL за ВТОРОЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) в течение периода 3 years?","options":["60 days","90 days","120 days","1 year"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 years влечёт дисквалификацию не менее чем на 120 days. Источник: 49 CFR 383.51 Table 3; Michigan CDL Manual."},"52":{"q":"Какова минимальная дисквалификация за ТРЕТЬЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) в течение периода 3 years?","options":["120 days","180 days","1 year","3 years"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в течение 3 years влечёт дисквалификацию не менее чем на 1 year. Источник: 49 CFR 383.51 Table 3; Michigan CDL Manual."},"53":{"q":"Каков срок дисквалификации за ПЕРВОЕ осуждение за нарушение приказа о выводе из эксплуатации водителя или транспортного средства (out-of-service order) при управлении CMV (без HazMat, без пассажиров)?","options":["Не менее 30 days","Не менее 90 days, но не более 1 year","Не менее 180 days, но не более 1 year","Не менее 1 year, но не более 5 years"],"explanation":"Первое нарушение приказа о выводе из эксплуатации влечёт дисквалификацию не менее чем на 180 days и не более чем на 1 year. Источник: 49 CFR 383.51 Table 4; Michigan CDL Manual."},"54":{"q":"Каков диапазон дисквалификации за ВТОРОЕ нарушение приказа о выводе из эксплуатации (out-of-service order) в отдельных инцидентах в течение периода 10 years?","options":["Не менее 180 days, но не более 1 year","Не менее 1 year, но не более 3 years","Не менее 2 years, но не более 5 years","Не менее 3 years, но не более 5 years"],"explanation":"Второе нарушение приказа о выводе из эксплуатации в течение 10 years влечёт дисквалификацию не менее чем на 2 years и не более чем на 5 years. Источник: 49 CFR 383.51 Table 4; Michigan CDL Manual."},"55":{"q":"Водитель ВПЕРВЫЕ нарушает приказ о выводе из эксплуатации (out-of-service order) при перевозке опасных материалов с табличками (placards) или при перевозке 16 или более пассажиров. Каков диапазон дисквалификации?","options":["Не менее 90 days, но не более 1 year","Не менее 180 days, но не более 2 years","Не менее 1 year, но не более 3 years","Не менее 3 years, но не более 5 years"],"explanation":"Первое нарушение приказа о выводе из эксплуатации при перевозке HazMat с табличками (placards) или 16+ пассажиров влечёт дисквалификацию не менее чем на 180 days и не более чем на 2 years. Источник: 49 CFR 383.51 Table 4; Michigan CDL Manual."},"56":{"q":"Согласно федеральным правилам, принятым в Мичигане, каков максимальный гражданский штраф, который может грозить водителю CMV за использование ручного мобильного телефона или отправку текстовых сообщений во время вождения?","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Водитель может быть оштрафован на сумму до $2,750 за использование ручного телефона или отправку текстовых сообщений; работодатель, который допускает или требует это, может быть оштрафован на сумму до $11,000. Источник: 49 CFR 392.80/392.82 и информационный листок FMCSA No-Texting/Hand-Held rule; Michigan CDL Manual."},"57":{"q":"У водителя CMV обнаружено любое измеренное или выявленное содержание алкоголя во время несения службы, либо он употреблял или хранил алкоголь в течение 4 hours перед выходом на службу. Каково непосредственное последствие?","options":["Немедленная дисквалификация CDL на 1 year","Вывод из эксплуатации на 24 hours","Вывод из эксплуатации на 7 days","Немедленная пожизненная дисквалификация"],"explanation":"Согласно запрету на алкоголь, такой водитель должен быть выведен из эксплуатации на 24 hours. Это отдельно от порога серьёзного нарушения в 0.04. Источник: 49 CFR 392.5; Michigan CDL Manual."},"58":{"q":"Держатель CDL осуждён за связанное с алкоголем нарушение при вождении СОБСТВЕННОГО личного (некоммерческого) автомобиля. Как это влияет на CDL в Мичигане?","options":["Не имеет последствий, поскольку CMV не было задействовано","Влечёт дисквалификацию CDL на 1 year","Влечёт только дисквалификацию на 60 days","Влечёт только начисление баллов, а не дисквалификацию"],"explanation":"Серьёзные нарушения (major offenses), включая алкогольные, влекут дисквалификацию CDL даже при совершении в личном автомобиле; первое такое нарушение — это дисквалификация на 1 year. Источник: 49 CFR 383.51 Table 1; Michigan CDL Manual."},"59":{"q":"У водителя CMV зафиксирован BAC 0.02 или выше, но менее 0.04. Какое утверждение лучше всего описывает последствие согласно правилам, применяемым в Мичигане?","options":["Это рассматривается как серьёзное нарушение (major offense) с дисквалификацией на 1 year","При значении ниже 0.04 последствий нет","Водитель не может выполнять функции, связанные с безопасностью, в течение 24 hours","Это автоматическое нарушение приказа о выводе из эксплуатации (out-of-service order)"],"explanation":"Подтверждённая концентрация алкоголя 0.02 или выше, но ниже 0.04, запрещает водителю выполнять функции, связанные с безопасностью, в течение 24 hours; дисквалифицирующее серьёзное нарушение (major offense) начинается с 0.04. Источник: 49 CFR 382.505 и 383.51; Michigan CDL Manual."},"60":{"q":"Согласно закону штата Мичиган Move Over («Уступи полосу»), при приближении к неподвижному автомобилю экстренных служб с включёнными проблесковыми маячками, если вы не можете безопасно перестроиться на соседнюю полосу, насколько вы обязаны снизить скорость ниже установленного ограничения?","options":["Как минимум на 10 mph ниже установленного ограничения скорости","Как минимум на 5 mph ниже установленного ограничения скорости","Как минимум на 15 mph ниже установленного ограничения скорости","Как минимум на 20 mph ниже установленного ограничения скорости"],"explanation":"Закон штата Мичиган Move Over (MCL 257.653a) требует, чтобы водитель, приближающийся к неподвижному уполномоченному автомобилю экстренных служб с включёнными маячками, перестроился как минимум на одну полосу, а если это невозможно, снизил скорость как минимум на 10 mph ниже установленного ограничения и проехал с должной осторожностью. Источник: MCL 257.653a; кампания Move Over полиции штата Мичиган."},"61":{"q":"На дороге штата Мичиган с двумя или более полосами для движения в одном направлении, по какой полосе может двигаться грузовик с полной массой более 10 000 фунтов, седельный тягач или автопоезд?","options":["Только по одной из двух крайних правых полос","По любой полосе, так же как легковые автомобили","Только по единственной крайней правой полосе в любое время","Только по центральной полосе, чтобы избежать встраивающегося транспорта"],"explanation":"Закон штата Мичиган (MCL 257.634) требует, чтобы на дороге с двумя или более полосами в одном направлении грузовик массой свыше 10 000 lbs, седельный тягач или сцепка «автомобиль-прицеп» двигались только по одной из двух крайних правых полос. Источник: MCL 257.634."},"62":{"q":"На скоростном шоссе ограниченного доступа в штате Мичиган, где установленное ограничение скорости превышает 65 mph, какова максимальная скорость для грузовика с полной массой 10 000 фунтов или более?","options":["65 mph","60 mph","70 mph","55 mph"],"explanation":"Согласно MCL 257.627, там где установленное ограничение превышает 65 mph, грузовик массой 10 000 lbs или более, седельный тягач или автопоезд, либо школьный автобус не могут превышать 65 mph на скоростном шоссе ограниченного доступа или на магистрали штата. Это отражает изменение, внесённое Public Act 445 of 2016. Источник: MCL 257.627."},"63":{"q":"В штате Мичиган на каком расстоянии от ближайшего рельса водитель транспортного средства с табличками опасных грузов обязан остановиться перед пересечением железнодорожного переезда в одном уровне?","options":["В пределах 50 feet, но не ближе 15 feet","В пределах 100 feet, но не ближе 25 feet","В пределах 40 feet, но не ближе 10 feet","В пределах 75 feet, но не ближе 20 feet"],"explanation":"MCL 257.669 требует, чтобы водители транспортных средств с табличками (а также транспортных средств, перевозящих 16 и более пассажиров или пассажиров за плату) включали аварийную сигнализацию и останавливались в пределах 50 feet, но не ближе 15 feet от ближайшего рельса перед пересечением. Источник: MCL 257.669; Michigan CDL Manual, раздел 9."},"64":{"q":"В штате Мичиган транспортное средство, встречающее или обгоняющее школьный автобус, который остановился с двумя попеременно мигающими красными огнями, обязано полностью остановиться на каком минимальном расстоянии от автобуса?","options":["Не менее 20 feet","Не менее 10 feet","Не менее 15 feet","Не менее 30 feet"],"explanation":"MCL 257.682 требует, чтобы водитель, обгоняющий или встречающий школьный автобус с мигающими красными огнями, остановился не менее чем в 20 feet от автобуса и не продолжал движение, пока автобус не тронется или сигналы не будут выключены. Источник: MCL 257.682."},"65":{"q":"В штате Мичиган на дороге, разделённой на две проезжие части приподнятой разделительной зоной или физическим барьером, какие водители НЕ обязаны останавливаться перед школьным автобусом с мигающими красными огнями, находящимся на противоположной стороне?","options":["Водители, встречающие автобус с противоположной проезжей части через барьер","Все водители в обоих направлениях всё равно обязаны остановиться","Только водители непосредственно позади автобуса","Только водители на полосе, ближайшей к автобусу"],"explanation":"Согласно MCL 257.682(2), там где дорога разделена на две проезжие части приподнятой разделительной зоной, физическим барьером или чётко обозначенной разделяющей секцией, водитель, встречающий автобус через это разделение, не обязан останавливаться. Водители, движущиеся позади автобуса по той же проезжей части, всё равно обязаны остановиться. Источник: MCL 257.682(2)."},"66":{"q":"Когда водитель CDL в штате Мичиган останавливает коммерческое транспортное средство на обочине дороги с односторонним движением или разделённой магистрали, где следует разместить три светоотражающих предупреждающих треугольника?","options":["На расстоянии 10, 100 и 200 feet в сторону приближающегося транспорта","На расстоянии 10, 100 и 100 feet с обеих сторон транспортного средства","На расстоянии 25, 100 и 250 feet в сторону приближающегося транспорта","На расстоянии 50, 150 и 300 feet в сторону приближающегося транспорта"],"explanation":"На дороге с односторонним движением или разделённой магистрали предупреждающие устройства размещаются на расстоянии 10, 100 и 200 feet от задней части транспортного средства в сторону приближающегося транспорта. Michigan CDL Manual следует федеральному стандарту FMCSA (49 CFR 392.22). Источник: Michigan CDL Manual; 49 CFR 392.22."},"67":{"q":"На двухполосной дороге с двусторонним движением в штате Мичиган, как водитель остановившегося CMV должен разместить три предупреждающих треугольника?","options":["Один примерно в 10 feet позади, один примерно в 100 feet позади и один примерно в 100 feet впереди транспортного средства","Все три примерно в 100 feet позади транспортного средства в ряд","Один на 10, один на 200 и один на 500 feet позади транспортного средства","Один на капоте и два примерно в 50 feet позади транспортного средства"],"explanation":"На двухполосной дороге с двусторонним движением разместите один треугольник примерно в 10 feet сзади в сторону приближающегося транспорта, один примерно в 100 feet сзади и один примерно в 100 feet впереди транспортного средства. Источник: Michigan CDL Manual; 49 CFR 392.22."},"68":{"q":"В период весенних сезонных весовых ограничений штата Мичиган («frost law»), какова максимальная скорость для коммерческого транспортного средства, перевозящего груз с пониженной массой по дороге с ограничениями, установленная в Дорожном кодексе штата Мичиган?","options":["35 mph","45 mph","25 mph","55 mph"],"explanation":"MCL 257.627 предусматривает, что в периоды действия пониженных (сезонных) весовых ограничений транспортные средства, работающие с этими пониженными нагрузками, ограничены скоростью 35 mph. Это часть характерной для Мичигана программы frost-law. Источник: MCL 257.627; сезонные весовые ограничения MDOT."},"69":{"q":"В рамках сезонных весовых ограничений штата Мичиган, какие маршруты обозначены как НЕ имеющие снижения допустимых осевых нагрузок во время весенней оттепели?","options":["Всесезонные маршруты («all-season»), показанные зелёным и золотым цветом на карте MDOT Truck Operators Map","Все окружные гравийные дороги","Только межштатные автомагистрали в пределах городской черты","Маршруты, показанные сплошным или пунктирным красным цветом на карте MDOT Truck Operators Map"],"explanation":"MDOT обозначает всесезонные маршруты («all-season», зелёным и золотым на карте MDOT Truck Operators Map), которые сохраняют полные допустимые осевые нагрузки круглый год, тогда как сезонные маршруты (сплошной или пунктирный красный) подлежат весеннему снижению осевых нагрузок. Источник: карта MDOT Truck Operators Map / руководство по сезонным весовым ограничениям."},"70":{"q":"Во время весенних весовых ограничений штата Мичиган на сезонном маршруте, какое снижение осевой нагрузки применяется к нежёсткому (асфальтовому) покрытию?","options":["35 процентов","25 процентов","10 процентов","50 процентов"],"explanation":"На сезонных маршрутах во время весенних ограничений MDOT вводит снижение осевой нагрузки на 35 процентов на нежёстком (асфальтовом) покрытии и на 25 процентов на жёстком (бетонном) покрытии. Источник: руководство MDOT по сезонным весовым ограничениям."},"71":{"q":"Водитель CDL в штате Мичиган приближается к железнодорожному переезду, обозначенному знаком «EXEMPT» («освобождён»), перевозя груз с табличками опасных грузов. Что требует закон штата Мичиган?","options":["Остановка не требуется на переезде, обозначенном знаком «exempt»","Водитель всё равно обязан остановиться в пределах 50 feet от ближайшего рельса","Водитель обязан остановиться и выставить предупреждающие треугольники","Водитель обязан остановиться только если аварийная сигнализация недоступна"],"explanation":"Согласно MCL 257.669, остановка не требуется на железнодорожном переезде в одном уровне, обозначенном знаком «exempt», даже для транспортных средств с табличками. На всех остальных переездах транспортное средство с табличками обязано остановиться на расстоянии от 15 до 50 feet от ближайшего рельса. Источник: MCL 257.669."},"72":{"q":"Какова максимальная допустимая по закону ширина коммерческого транспортного средства или его груза в штате Мичиган без разрешения на негабарит?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"MCL 257.717 устанавливает максимальную допустимую по закону ширину в штате Мичиган в 96 inches (8 feet); всё, что шире, требует разрешения на негабарит. Обратите внимание, что это уже, чем стандарт в 102 inches, используемый во многих других штатах. Источник: MCL 257.717; MDOT Maximum Legal Truck Loadings and Dimensions."},"73":{"q":"Какова максимальная допустимая по закону высота коммерческого транспортного средства, гружёного или порожнего, в штате Мичиган без разрешения?","options":["13 feet 6 inches","14 feet 0 inches","13 feet 0 inches","12 feet 6 inches"],"explanation":"MCL 257.719 устанавливает максимальную допустимую по закону высоту транспортного средства в штате Мичиган, гружёного или порожнего, в 13 feet 6 inches. Источник: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions."},"74":{"q":"На скоростном шоссе в штате Мичиган с тремя или более полосами для движения в одном направлении, что говорит закон об использовании полос (MCL 257.634) о том, какую полосу должно использовать транспортное средство?","options":["Транспортному средству не запрещено двигаться по любой полосе скоростного шоссе, имеющего три или более полосы в одном направлении","Все транспортные средства должны оставаться на крайней правой полосе, кроме случаев обгона","Грузовики должны использовать только центральную полосу","Все транспортные средства должны использовать только две левые полосы"],"explanation":"MCL 257.634 предусматривает, что требование держаться правее не запрещает транспортному средству двигаться по любой полосе скоростного шоссе, имеющего три или более полосы в одном направлении. Однако тяжёлые грузовики остаются ограничены двумя крайними правыми полосами. Источник: MCL 257.634."},"75":{"q":"В штате Мичиган перед пересечением железнодорожного переезда в одном уровне водитель школьного автобуса обязан сделать что из следующего в дополнение к остановке на расстоянии от 15 до 50 feet от ближайшего рельса?","options":["Включить аварийную сигнализацию, открыть пассажирскую дверь и водительское окно, прислушаться и осмотреться в обе стороны","Подать звуковой сигнал три раза перед началом движения","Разместить светоотражающие треугольники в 100 feet позади автобуса","Переключиться на низшую передачу и пересекать с ускорением"],"explanation":"MCL 257.1857 требует, чтобы водитель школьного автобуса остановился на расстоянии от 15 до 50 feet от ближайшего рельса, включил аварийную сигнализацию, выключил источники шума, открыл пассажирскую дверь и окно со стороны водителя, посмотрел и прислушался в обе стороны перед началом движения без переключения передач на путях. Источник: MCL 257.1857."},"76":{"q":"Водитель CDL находится на двухполосной окружной дороге в штате Мичиган без знаков ограничения скорости. Какое общее установленное законом ограничение скорости применяется?","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"MCL 257.627 устанавливает общее ограничение скорости 55 mph на магистралях и окружных дорогах, где не указано иное ограничение (и соответствующее общее ограничение 55 mph на гравийных дорогах). Тяжёлый грузовик не превысит это значение. Источник: MCL 257.627."},"77":{"q":"Какое утверждение о платных дорогах является верным для коммерческих водителей, работающих в штате Мичиган?","options":["В Мичигане нет платных магистралей; плата взимается только на определённых мостах и тоннелях, таких как мосты Mackinac, Blue Water и International","Все межштатные скоростные шоссе Мичигана являются платными дорогами, требующими транспондера","Грузовики платят за проезд по I-94 и I-75, а легковые автомобили нет","Мичиган взимает плату на всех магистралях штата зимой"],"explanation":"Межштатные шоссе и шоссе штата Мичиган бесплатны; плата взимается только на конкретных пограничных переходах и переходах через пролив, таких как мост Mackinac, мост Blue Water и International Bridge в Sault Ste. Marie. Источник: информация MDOT о плате за мосты."},"78":{"q":"Что касается планового периодического технического осмотра транспортных средств, что верно для коммерческих транспортных средств, зарегистрированных в штате Мичиган?","options":["Мичиган не требует общештатного периодического осмотра безопасности или выбросов, хотя CMV всё равно должны соответствовать федеральным требованиям к осмотру CMV","Мичиган требует ежегодного теста на выбросы для каждого коммерческого транспортного средства","Мичиган требует осмотра безопасности раз в два года на государственной станции","Мичиган требует проверки на смог перед каждым продлением CDL"],"explanation":"Мичиган не предписывает общештатный периодический осмотр безопасности или выбросов для транспортных средств. Однако коммерческие транспортные средства остаются субъектом федеральных требований FMCSA к осмотру и техническому обслуживанию независимо от отсутствия государственной программы. Источник: Michigan SOS / MDOT; 49 CFR Part 396."},"79":{"q":"Согласно закону штата Мичиган Move Over, когда дорожные условия позволяют вам сменить полосу для неподвижного уполномоченного автомобиля экстренных служб, насколько далеко вы обязаны перестроиться?","options":["Как минимум на одну движущуюся полосу или на две ширины транспортного средства от неподвижного транспортного средства","Полностью съехать с проезжей части на дальнюю обочину","Как минимум на три ширины транспортного средства от неподвижного транспортного средства","На крайнюю левую полосу независимо от положения"],"explanation":"MCL 257.653a требует, чтобы водители, когда это возможно, перестраивались на полосу, отстоящую как минимум на одну движущуюся полосу или на две ширины транспортного средства от неподвижного уполномоченного автомобиля экстренных служб, одновременно снижая скорость как минимум на 10 mph ниже установленного ограничения. Источник: MCL 257.653a."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в штате Мичиган?","options":["Michigan State Police Commercial Vehicle Division","Michigan Department of Transportation (MDOT)","Michigan Department of State (Secretary of State)","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"В штате Мичиган CDL выдаются Michigan Department of State, возглавляемым Secretary of State; тесты на знания CDL и заявления обрабатываются в офисах SOS. Источник: Michigan CDL Manual (SOS) и страницы CDL SOS на michigan.gov."},"81":{"q":"Где в штате Мичиган проводятся экзамены CDL по вождению на дороге и базовому управлению транспортным средством?","options":["В любом отделении Secretary of State сотрудниками SOS","В региональных центрах тестирования FMCSA","Офицерами автотранспортного контроля Michigan State Police","Сторонними организациями по тестированию водителей, одобренными MDOS"],"explanation":"Мичиган не проводит экзамены навыков CDL в отделениях SOS; трёхчастный экзамен навыков проводится сторонними организациями по тестированию водителей, одобренными Michigan Department of State (MDOS). Источник: Michigan CDL Manual (SOS)."},"82":{"q":"Из скольких частей состоит экзамен навыков CDL в штате Мичиган?","options":["Из двух: письменный тест и тест вождения на дороге","Из трёх: предрейсовый осмотр, базовое управление транспортным средством и вождение на дороге","Из двух: базовые навыки управления и проверка по опасным грузам","Из четырёх: предрейсовый осмотр, движение задним ходом, вождение на дороге и письменный тест по безопасности"],"explanation":"Экзамен навыков CDL в штате Мичиган состоит из трёх частей: тест осмотра транспортного средства (предрейсовый осмотр), тест базовых навыков управления транспортным средством и тест вождения на дороге, все из которых необходимо сдать. Источник: Michigan CDL Manual (SOS)."},"83":{"q":"Прежде чем впервые подающий заявление на CDL сможет сдать экзамен навыков в штате Мичиган, какое федеральное обучение должно быть завершено?","options":["Спонсируемая работодателем стажировка продолжительностью не менее шести месяцев","40-часовой курс безопасности по опасным грузам","Entry-Level Driver Training (ELDT) от зарегистрированного поставщика","Курс безопасного вождения, одобренный MDOT"],"explanation":"С 7 февраля 2022 года правило FMCSA Entry-Level Driver Training (ELDT) требует, чтобы впервые подающие заявление на CDL (а также при определённых повышениях категории/получении пометок) завершили ELDT у поставщика из FMCSA Training Provider Registry до экзамена навыков. Источник: Michigan CDL Manual (SOS); правило FMCSA ELDT."},"84":{"q":"После получения CLP, сколько времени должен ждать заявитель в штате Мичиган, прежде чем сдавать экзамен навыков CDL?","options":["Не менее 7 days","Не менее 60 days","Не менее 14 days","Не менее 30 days"],"explanation":"Федеральные и мичиганские правила требуют, чтобы CLP удерживалось не менее 14 days, прежде чем заявитель сможет сдать экзамен навыков CDL. Источник: Michigan CDL Manual (SOS); 49 CFR 383.25."},"85":{"q":"При самостоятельной сертификации своего типа вождения для мичиганского CDL, из скольких федеральных категорий должен выбрать заявитель?","options":["Из двух","Из пяти","Из трёх","Из четырёх"],"explanation":"Каждый заявитель на мичиганское CDL должен самостоятельно сертифицироваться по одной из четырёх категорий: non-excepted interstate, excepted interstate, non-excepted intrastate или excepted intrastate. Источник: Michigan CDL Self-Certification Form (SOS); 49 CFR 383.71."},"86":{"q":"Какая категория самостоятельной сертификации требует, чтобы водитель в штате Мичиган имел федеральный медицинский сертификат DOT?","options":["Ни одна из категорий не требует медицинского сертификата","Non-excepted interstate","Excepted intrastate","Excepted interstate"],"explanation":"Водитель, самостоятельно сертифицирующийся как «non-excepted interstate», работает в межштатной торговле и обязан иметь действительный медицинский сертификат DOT; категории «excepted» не требуют его по той же причине. Источник: Michigan CDL Self-Certification Form (SOS); 49 CFR 383.71/391."},"87":{"q":"Что имеет в виду водитель в штате Мичиган, самостоятельно сертифицируясь как «excepted intrastate»?","options":["Они ездят через границы штатов, но освобождены от всех федеральных правил","Они ездят только в пределах Мичигана, но обязаны иметь федеральную медицинскую карту","Они ездят только в пределах Мичигана в операциях, которые штат освободил от требований медицинской сертификации","Они ездят между штатами и обязаны хранить медицинскую карту в SOS"],"explanation":"«Excepted intrastate» означает, что водитель управляет CMV только в пределах Мичигана в деятельности, которую штат определил как освобождённую от требования медицинской сертификации, поэтому федеральная медицинская карта не требуется. Источник: Michigan CDL Self-Certification Form (SOS); 49 CFR 383.71."},"88":{"q":"Каков минимальный возраст для выдачи CDL для вождения коммерческого транспортного средства только в пределах штата Мичиган (intrastate)?","options":["21 год","19 лет","18 лет","16 лет"],"explanation":"Заявитель должен быть не моложе 18 лет, чтобы иметь CDL для внутриштатного (только в пределах Мичигана) коммерческого вождения; межштатная деятельность, как правило, требует возраста 21 год. Источник: Michigan CDL Manual (SOS); MCL 257.312e."},"89":{"q":"На мичиганских тестах знаний CDL, какой тест должен сдать каждый заявитель на CDL независимо от класса транспортного средства?","options":["Тест общих знаний","Тест по перевозке пассажиров","Тест по опасным грузам","Тест по сдвоенным/строенным прицепам"],"explanation":"Все заявители на CDL должны сдать тест общих знаний; дополнительные тесты знаний (например, по пневматическим тормозам, составным транспортным средствам, пометкам) зависят от класса и запрашиваемых пометок. Источник: Michigan CDL Manual (SOS); 49 CFR 383.23."},"90":{"q":"При продлении мичиганского CDL в офисе Secretary of State, что из этого является частью стандартного процесса?","options":["Обязательный письменный тест по опасным грузам для всех продлений","Проверка зрения и анализ водительской истории заявителя на уровне штата и страны","Автоматический новый медосмотр DOT, проводимый сотрудниками SOS","Повторная сдача полного трёхчастного экзамена навыков каждый цикл"],"explanation":"При продлении офис SOS проводит проверку зрения и проверяет водительскую историю заявителя на уровне штата и страны (CDLIS); полная повторная сдача экзамена навыков обычно не требуется. Примечание: точные сборы могут меняться. Источник: Michigan CDL Manual (SOS); страница продления CDL SOS на michigan.gov."}},"tr":{"0":{"q":"Michigan'ın belirlenmiş otoyollarında, bir gabari aşımı (oversize) izni gerekmeden önce ticari bir aracın azami yasal genişliği (aynalar ve belirli güvenlik ekipmanları hariç) nedir?","options":["108 inç (9 fit)","96 inç (8 fit)","120 inç (10 fit)","102 inç (8 fit 6 inç)"],"explanation":"Michigan, federal ulusal ağ standardına uygun olarak, belirlenmiş otoyollarda araç genişliğini 102 inç (8'6\") ve diğer yollarda 96 inç (8') ile sınırlar. Kaynak: Michigan Vehicle Code MCL 257.717; MDOT 'Maximum Legal Truck Loadings and Dimensions' (T-1)."},"1":{"q":"Özel bir taşıma izni olmadan Michigan otoyollarında bir araç ve yükü için azami yasal yükseklik nedir?","options":["14 fit 0 inç","13 fit 6 inç","14 fit 6 inç","13 fit 0 inç"],"explanation":"Michigan, azami araç ve yük yüksekliğini 13 fit 6 inç olarak belirler; daha yüksek olan herhangi bir şey için gabari aşımı izni gerekir. Kaynak: MCL 257.718; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"2":{"q":"İzin olmadan Michigan'ın belirlenmiş otoyollarında işletilen bir yarı römorkun (yük dahil) azami uzunluğu nedir?","options":["60 fit","48 fit","53 fit","57 fit"],"explanation":"Michigan, belirlenmiş otoyollarda yük dahil 53 fite kadar bir yarı römorka izin verir (belirlenmemiş yollarda 50 fit). Kaynak: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"3":{"q":"Michigan'ın Interstate sisteminde uyguladığı federal sınırlara göre, izin olmadan standart 5 akslı bir kombinasyon için azami brüt araç ağırlığı nedir?","options":["88,000 pound","76,000 pound","73,280 pound","80,000 pound"],"explanation":"Interstate sisteminde Michigan, federal köprü formülüne tabi araçlar için 80,000 poundluk federal brüt üst sınırı uygular. Kaynak: Michigan'da uygulanan 23 CFR 658.17; MDOT kamyon ağırlığı kılavuzu."},"4":{"q":"Michigan'ın Interstate otoyollarında 80,000 poundluk federal standart altında işletilen araçlara uygulanan federal tek aks ağırlık sınırı nedir?","options":["24,000 pound","22,400 pound","18,000 pound","20,000 pound"],"explanation":"80,000 poundluk federal standarda tabi araçlar için tek aks sınırı 20,000 pounddur; bu, Michigan'ın Interstate'te uyguladığı aynı değerdir. Kaynak: Michigan'da uygulanan 23 CFR 658.17; MDOT ağırlık kılavuzu."},"5":{"q":"Michigan'ın Interstate sisteminde uygulanan federal standarda göre, tandem aks grubuna izin verilen azami ağırlık nedir?","options":["36,000 pound","40,000 pound","32,000 pound","34,000 pound"],"explanation":"Michigan'ın Interstate'te uyguladığı federal tandem aks sınırı 34,000 pounddur. Michigan'ın kendi eyalet hukuku aks kurallarının farklı olduğunu unutmayın (18,000 lb'lik normal aks azamisine bakın). Kaynak: 23 CFR 658.17; MDOT ağırlık kılavuzu."},"6":{"q":"Federal sınırlardan önce gelen aks yükü kurallarından dolayı, uygun şekilde yapılandırılmış bir kamyonun Interstate dışındaki Michigan yollarında yasal olarak taşıyabileceği azami brüt araç ağırlığı nedir?","options":["80,000 pound","164,000 pound","105,500 pound","129,000 pound"],"explanation":"Michigan'ın kazanılmış hak (grandfathered) ağırlık yasası, aks yükleri ve mesafeleri uygun olduğunda yaklaşık 164,000 poundluk azami brüt ağırlığa izin verir; bu, Kuzey Amerika'da rutin olarak izin verilen en yüksek değerdir. Kaynak: MCL 257.722; Michigan House Fiscal Agency, 'Michigan's Truck-Weight Law.'"},"7":{"q":"Eyaletin ağır ağırlık hükümleri altında işletilen bir Michigan kamyon-römork kombinasyonunda izin verilen azami aks sayısı nedir?","options":["8 aks","11 aks","9 aks","13 aks"],"explanation":"1967'den beri Michigan bu kombinasyonları 11 aksla sınırlamıştır; bu, aks başına sınırlarla birlikte yaklaşık 164,000 poundluk azamiyi verir. Kaynak: MCL 257.722; Michigan House Fiscal Agency kamyon ağırlığı analizi."},"8":{"q":"Michigan'ın kendi aks yükü yasasına göre, bitişik akslardan 9 fit veya daha fazla mesafeli bir tek aks için 'normal yükleme azamisi' nedir?","options":["16,000 pound","18,000 pound","20,000 pound","22,400 pound"],"explanation":"Michigan yasası, aks mesafesinin 9 fit veya daha fazla olduğu durumlarda normal azami tek aks yükünü 18,000 pound olarak belirler; bu, 20,000 lb'lik federal değerden daha düşüktür. Kaynak: MCL 257.722(1)."},"9":{"q":"Michigan'ın eyalet aks yasası, azami tekerlek yükünü lastik genişliğine bağlı bir değerle sınırlar. Bu sınır nedir?","options":["Lastik genişliğinin inç başına 500 pound","Lastik genişliğinin inç başına 700 pound","Lastik genişliğinin inç başına 600 pound","Lastik genişliğinin inç başına 850 pound"],"explanation":"Michigan, tekerlek yükünü lastik genişliğinin inç başına 700 pound ile sınırlar; bu standart, ağır yükleri daha fazla lastiğe ve aksa dağıtır. Kaynak: MCL 257.722(7)."},"10":{"q":"Michigan'ın bahar çözülmesi (don yasası / frost law) döneminde, beton kaplamalarda azami aks yükleri yüzde kaç oranında azaltılır?","options":["yüzde 25","yüzde 35","yüzde 10","yüzde 50"],"explanation":"Mart, Nisan ve Mayıs aylarında Michigan, çözülen yol yataklarını korumak için beton kaplamalarda azami aks yüklerini yüzde 25 (ve diğer yollarda yüzde 35) oranında azaltır. Kaynak: MCL 257.722(8)."},"11":{"q":"Michigan'ın mevsimsel don yasası (frost law) kısıtlamaları sırasında, beton kaplama dışındaki yollarda aks yükleri yüzde kaç oranında azaltılır?","options":["yüzde 15","yüzde 45","yüzde 35","yüzde 25"],"explanation":"Beton olmayan yollarda, Michigan'ın bahar ağırlık kısıtlamaları, Mart-Mayıs çözülme döneminde azami aks yüklerini yüzde 35 oranında azaltır. Kaynak: MCL 257.722(8)."},"12":{"q":"Michigan'ın mevsimsel ağırlık azaltması (don yasası / frost law) tipik olarak hangi aylarda geçerlidir?","options":["Mart, Nisan ve Mayıs","Ocak, Şubat ve Mart","Kasım, Aralık ve Ocak","Nisan, Mayıs ve Haziran"],"explanation":"Michigan'ın mevsimsel aks yükü azaltmaları, yasal olarak Mart, Nisan ve Mayıs aylarına bağlı olan bahar çözülmesi sırasında geçerlidir; kesin başlangıç/bitiş tarihleri her yıl MDOT tarafından açıklanır. Kaynak: MCL 257.722(8); MDOT mevsimsel ağırlık kısıtlaması bildirimleri."},"13":{"q":"Michigan yasası, bir araç kombinasyonundaki yükün, ekstra uyarı gerekmeden önce aracın arkasından ne kadar uzanmasına izin verir?","options":["2 fit","3 fit","4 fit","6 fit"],"explanation":"Bir yük, arkadan 4 fite kadar (ve önden 3 fite kadar) uzanabilir; 4 fit veya daha fazla arka taşma, gündüz kırmızı bayrak ve gece kırmızı ışık gerektirir. Kaynak: MCL 257.719; MDOT yükleme boyutları kılavuzu."},"14":{"q":"Bir Michigan ticari aracının arkasından uzanan bir yük, taşma uzunluğu hangi değere ulaştığında geceleyin kırmızı ışık veya fener göstermek zorundadır?","options":["8 fit","2 fit","4 fit","6 fit"],"explanation":"Michigan, aracın arkasından 4 fit veya daha fazla uzanan herhangi bir yük için gündüz kırmızı bayrak ve gece kırmızı ışık veya fener gerektirir. Kaynak: MCL 257.719; MDOT yükleme boyutları kılavuzu."},"15":{"q":"Michigan eyalet ana hat (trunkline) otoyollarında seyahat için gabari aşımı/aşırı yük taşıma izinlerini kim verir?","options":["Federal Motor Carrier Safety Administration","Yalnızca Michigan State Police","Michigan Department of Transportation (MDOT)","Michigan Secretary of State"],"explanation":"MDOT, eyalet ana hatlarında aşırı boyut veya ağırlık için izin verirken, yerel yol kurumları kendi yetki alanlarındaki yolları yönetir. Kaynak: MCL 257.725; MDOT Oversize/Overweight Permits."},"16":{"q":"Michigan'da bir taşıyıcı, MDOT gabari aşımı/aşırı yük izni için hangi çevrimiçi sistem üzerinden başvuruda bulunur?","options":["CDLIS (Commercial Driver License Information System)","IRP (International Registration Plan portalı)","SAFER (Safety and Fitness Electronic Records)","MiTRIP (Michigan Transport Routing and Internet Permitting)"],"explanation":"Michigan taşıyıcıları, taşıma izinlerini MDOT'un çevrimiçi yönlendirme ve izin sistemi olan MiTRIP aracılığıyla elektronik olarak alır. Kaynak: MDOT Oversize/Overweight Permits; MCL 257.725."},"17":{"q":"Michigan'da tek seferlik bir gabari aşımı izni genellikle şu özelliklere sahip bir yükün ara sıra taşınması için verilir:","options":["Tamamen özel mülkte taşınıyor olması","Yasal sınırlara getirilmek üzere parçalanamaz veya yeniden düzenlenemez olması","Taşıyıcının yükü sadece daha küçük yüklere bölmemeyi tercih etmesi","Yasal sınırları yüzde birden az aşması"],"explanation":"Michigan izinleri, yalnızca yasal sınırlara uyacak şekilde makul ölçüde parçalanamayan, azaltılamayan veya yeniden düzenlenemeyen gabari aşımı veya aşırı yüklerin ara sıra taşınması için verilir. Kaynak: MCL 257.725; MDOT izin politikası."},"18":{"q":"Michigan'ın doğal gaz aracı hükmü kapsamında, doğal gazla çalışan bir araç, daha ağır yakıt sistemini hesaba katmak için geçerli ağırlık sınırlarını ne kadar aşabilir?","options":["5,000 pound","2,000 pound","550 pound","10,000 pound"],"explanation":"Michigan, yakıt sisteminin eklenen ağırlığını dengelemek için doğal gaz araçlarına, aksi takdirde geçerli olan ağırlık sınırlarının üzerinde 2,000 pounda kadar bir tolerans tanır. Kaynak: Michigan Vehicle Code; federal 23 U.S.C. 127 NGV toleransıyla uyumlu MDOT ağırlık kılavuzu."},"19":{"q":"İki çekili birim çeken bir çekici-kamyon gibi bir Michigan kombinasyonu için, bir izin gerekmeden önce azami toplam uzunluk (ilk çekili birimin önünden son birimin arkasına kadar ölçülen) nedir?","options":["75 fit","58 fit","65 fit","53 fit"],"explanation":"Michigan, çekili birimlerin ilkinin önünden sonuncusunun arkasına kadar ölçüldüğünde 58 fiti (her birim 28'6\"yi aşmayacak şekilde) geçmemesi koşuluyla, sabit bir toplam araç uzunluğu olmaksızın bu ikili kombinasyonlara izin verir. Kaynak: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"20":{"q":"Michigan'da, çekili birimin GVWR'sinin 10,000 poundun üzerinde olduğu, 26,001 pound veya daha fazla brüt kombinasyon ağırlık değerine (GCWR) sahip herhangi bir araç kombinasyonunu işletmek için hangi CDL grubu gereklidir?","options":["Grup A","Grup B","Grup C","Grup D"],"explanation":"Michigan, Grup (Sınıf) A CDL'yi, çekili birim(ler)in GVWR'sinin 10,000 lb'den fazla olması koşuluyla, 26,001 lb veya daha fazla GCWR'ye sahip herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: Michigan CDL Manual (Michigan SOS), Bölüm 1."},"21":{"q":"Michigan kurallarına göre, hangi CDL grubu, 26,001 pound veya daha fazla brüt araç ağırlık değerine (GVWR) sahip tek bir aracı (10,000 pound veya daha az bir birim çekebilir) kapsar?","options":["Grup A","Grup B","Grup C","Grup H"],"explanation":"Michigan'da Grup (Sınıf) B CDL, 26,001 lb veya daha fazla GVWR'ye sahip herhangi bir tek araç ya da 10,000 lb GVWR'yi aşmayan bir birim çeken böyle bir araç içindir. Kaynak: Michigan CDL Manual (Michigan SOS), Bölüm 1."},"22":{"q":"Michigan Grup (Sınıf) C CDL, daha küçük bir araç için (Sınıf A/B ağırlık eşiklerinin altında) yalnızca aşağıdakilerden hangisini taşımak için kullanıldığında gereklidir?","options":["5,000 poundu aşan herhangi bir kargo","Sürücü dahil 16 veya daha fazla yolcu ya da plakart gerektiren miktarlarda tehlikeli maddeler","Ağırlığı ne olursa olsun herhangi bir römork","Yalnızca okul çocukları"],"explanation":"Michigan Grup C CDL, Sınıf A/B ağırlık sınırlarının altında olan ve sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış ya da plakart gerektiren miktarlarda tehlikeli madde taşıyan araçlar için geçerlidir. Kaynak: Michigan CDL Manual (Michigan SOS), Bölüm 1."},"23":{"q":"EYALET İÇİ (yalnızca Michigan içinde) sürüş için Michigan CDL almanın asgari yaşı nedir?","options":["16 yaşında","18 yaşında","21 yaşında","25 yaşında"],"explanation":"Michigan, yalnızca eyalet içi (within-state) ticaret için 18 yaşında bir CDL'ye izin verir; eyaletler arası işletim 21 yaşını gerektirir. Kaynak: Michigan CDL Manual (Michigan SOS) / Michigan SOS CDL uygunluk."},"24":{"q":"EYALETLER ARASI (eyalet sınırları ötesinde) sürüşe izin veren bir Michigan CDL almanın asgari yaşı nedir?","options":["18 yaşında","19 yaşında","21 yaşında","23 yaşında"],"explanation":"Federal ve Michigan kuralları, eyaletler arası ticarette bir CMV işletmek için sürücünün en az 21 yaşında olmasını gerektirir; 18-20 yaş arası sürücüler eyalet içi işletimle sınırlıdır. Kaynak: Michigan CDL Manual (Michigan SOS); 49 CFR 391.11."},"25":{"q":"Michigan'da, bir başvuru sahibinin CDL yol becerileri sınavına girmesine izin verilmeden önce bir Ticari Öğrenme İzni (CLP) ne kadar süre elinde tutması gerekir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 60 gün"],"explanation":"Michigan, başvuru sahibinin CDL becerileri sınavına girebilmesinden önce CLP'nin en az 14 gün elde tutulmasını gerektiren federal kuralı izler. Kaynak: Michigan SOS (cdl-apply); 49 CFR 383.25."},"26":{"q":"Sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir aracı işletmek için bir Michigan CDL'sinde hangi onay (endorsement) gereklidir?","options":["P (Yolcu)","N (Tanker)","T (İkili/Üçlü)","H (Tehlikeli Maddeler)"],"explanation":"Michigan'da, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir aracı işletmek için P (Yolcu) onayı gereklidir. Kaynak: Michigan CDL Manual (Michigan SOS), onaylar bölümü."},"27":{"q":"Okul öncesi, ilkokul veya ortaokul öğrencilerini okula getirip götürmek için kullanılan bir ticari aracı sürmek için hangi Michigan CDL onayı gereklidir?","options":["P (Yolcu)","S (Okul Otobüsü)","T (İkili/Üçlü)","C (Çocuklar)"],"explanation":"Michigan'da öğrenci taşıyan bir okul otobüsünü sürmek için S (Okul Otobüsü) onayı gereklidir; başvuru sahiplerinin halihazırda P onayına sahip olması (veya almaları) ve okul otobüsü bilgi ve beceri sınavlarını geçmesi gerekir. Kaynak: Michigan CDL Manual (Michigan SOS)."},"28":{"q":"Bir Michigan CDL'sinde, bir sürücüye HEM Tanker (N) HEM DE Tehlikeli Maddeler (H) onayları verildiğinde hangi tek kod harfi görünür?","options":["X","Z","HN","K"],"explanation":"Michigan, bir sürücü hem tanker hem de tehlikeli maddeler onaylarına sahip olduğunda, ayrı N ve H kodları yerine ehliyete birleşik X kodunu yerleştirir. Kaynak: Michigan CDL Manual (Michigan SOS), onaylar bölümü."},"29":{"q":"Michigan T onayı, ikili ve üçlü römork kombinasyonlarını kapsar. Ancak, Michigan yollarındaki ÜÇLÜ römorklarla ilgili olarak, hangi ifade doğrudur?","options":["Üçlü römork kombinasyonlarına Michigan'da izin verilmez","Üçlü römorklara Michigan'da yalnızca eyaletler arası otoyollarda izin verilir","Üçlü römorklar Michigan'da ayrı bir Sınıf A-T izni gerektirir","Üçlü römorklara Michigan'da hiçbir kısıtlama olmaksızın eyalet genelinde izin verilir"],"explanation":"T (İkili/Üçlü) onayı mevcut olsa da, üçlü römork kombinasyonlarına Michigan yollarında izin verilmez. Kaynak: Michigan CDL Manual (Michigan SOS), onaylar bölümü."},"30":{"q":"Bir Michigan CDL başvuru sahibinin hangi onay için, parmak izi alma ve geçmiş kontrolü dahil olmak üzere bir Transportation Security Administration (TSA) Güvenlik Tehdit Değerlendirmesini geçmesi gerekir?","options":["N (Tanker)","T (İkili/Üçlü)","H (Tehlikeli Maddeler)","P (Yolcu)"],"explanation":"H (Tehlikeli Maddeler) onayı, HazMat bilgi sınavına ek olarak parmak izi ve geçmiş kontrolü içeren bir TSA Güvenlik Tehdit Değerlendirmesi gerektirir. Kaynak: Michigan SOS CDL bilgisi; TSA HME / 49 CFR 1572."},"31":{"q":"Michigan/federal tanımlara göre, N (Tanker) onayı genellikle, bireysel anma kapasitesi 119 galondan fazla ve toplam anma kapasitesi en az kaç galon olan bir tankta sıvı veya gaz taşımak için gereklidir?","options":["500 galon","1,000 galon","1,500 galon","3,000 galon"],"explanation":"Tanker (N) onayı, bireysel anma kapasitesi 119 galonun üzerinde ve toplam anma kapasitesi 1,000 galon veya daha fazla olan tanklar için geçerlidir. Kaynak: Michigan CDL Manual (Michigan SOS); 49 CFR 383.5."},"32":{"q":"Bir Michigan CDL sahibinin, bir Tehlikeli Maddeler (H) onayını geçerli tutmak için TSA Güvenlik Tehdit Değerlendirmesini ne sıklıkla yenilemesi gerekir?","options":["Her yıl","Her 3 yılda bir","Her 5 yılda bir","Her 10 yılda bir"],"explanation":"Bir HazMat onayı için TSA Güvenlik Tehdit Değerlendirmesi, yeni parmak izi alma ve geçmiş kontrolü dahil olmak üzere her 5 yılda bir yenilenmelidir. Kaynak: Michigan SOS CDL bilgisi; TSA HME (49 CFR 1572)."},"33":{"q":"7 Şubat 2022 itibarıyla, Michigan'da aşağıdakilerden hangisi için sınava girmeden önce Giriş Düzeyi Sürücü Eğitimi (ELDT) tamamlanmalıdır?","options":["İlk kez bir Sınıf A veya Sınıf B CDL, Sınıf B'den Sınıf A'ya bir yükseltme ya da ilk kez bir P, S veya H onayı","Yalnızca ilk kez bir Sınıf A CDL","Herhangi bir CDL yenilemesi","Yalnızca Tanker (N) onayı"],"explanation":"Michigan'da uygulanan federal ELDT, ilk kez bir Sınıf A veya Sınıf B CDL, Sınıf B'den A'ya bir yükseltme ve ilk kez Yolcu (P), Okul Otobüsü (S) veya Tehlikeli Maddeler (H) onayları için gereklidir. Kaynak: FMCSA ELDT kuralı (49 CFR 380); Michigan SOS."},"34":{"q":"Bir Michigan CDL başvuru sahibi, gerekli Giriş Düzeyi Sürücü Eğitimini (ELDT) hangi kuruluş aracılığıyla tamamlamalıdır?","options":["Başvuru sahibinin seçtiği herhangi bir sürüş eğitmeni","FMCSA Training Provider Registry (TPR) listesinde yer alan bir sağlayıcı","Doğrudan Michigan Secretary of State","Michigan State Police akademisi"],"explanation":"ELDT, FMCSA Training Provider Registry (TPR) listesinde yer alan bir okul veya kuruluş tarafından verilmelidir; tamamlanma, FMCSA'ya elektronik olarak bildirilir. Kaynak: FMCSA ELDT kuralı (49 CFR 380); Michigan SOS."},"35":{"q":"Bir Michigan CDL'sinde ilk kez alındığında hangi onay Giriş Düzeyi Sürücü Eğitimi (ELDT) gerektirmez?","options":["H (Tehlikeli Maddeler)","P (Yolcu)","S (Okul Otobüsü)","N (Tanker)"],"explanation":"ELDT, ilk kez H, P ve S onayları için zorunludur, ancak N (Tanker) onayı ELDT kuralı kapsamında değildir. Kaynak: FMCSA ELDT kuralı (49 CFR 380.603); Michigan SOS."},"36":{"q":"Bir Michigan CDL başvuru sahibinin uygunluğunu kanıtlamak için bir Secretary of State ofisinde hangi belge setini sunması gerekir?","options":["Yalnızca bir fotoğraf ve bir kredi kartı","Kimlik/yasal varlık kanıtı, Sosyal Güvenlik numarası kanıtı ve Michigan ikamet kanıtı","Yalnızca bir işveren mektubu","Yalnızca bir pasaport fotoğrafı ve nakit ödeme"],"explanation":"Michigan, bir CLP veya CDL düzenlemek için ABD'deki kimlik/yasal varlık kanıtı, Sosyal Güvenlik numarası kanıtı ve Michigan ikamet kanıtı gerektirir. Kaynak: Michigan SOS CDL/ehliyet belge gereksinimleri."},"37":{"q":"Michigan CDL öz-sertifikasyonunda, bir CMV'yi eyalet sınırları ötesinde işleten ve federal fiziksel yeterlilik kurallarından MUAF OLMAYAN bir sürücü hangi kategoride sertifika almalıdır?","options":["İstisnai Eyaletler Arası (Excepted Interstate)","İstisnai Olmayan Eyaletler Arası (Non-excepted Interstate)","İstisnai Eyalet İçi (Excepted Intrastate)","İstisnai Olmayan Eyalet İçi (Non-excepted Intrastate)"],"explanation":"Michigan dört öz-sertifikasyon kategorisi kullanır; tıbbi kurallara tabi olan eyaletler arası ticaretteki bir sürücü, İstisnai Olmayan Eyaletler Arası (Non-excepted Interstate) olarak sertifika alır ve geçerli bir tıbbi muayene sertifikası bulundurmak zorundadır. Kaynak: Michigan SOS CDL Self-Certification Form."},"38":{"q":"Hangi Michigan CDL öz-sertifikasyon kategorisi, sürücünün geçerli bir tıbbi muayene sertifikasını (DOT medical card) bulundurmasını ve Secretary of State'e sunmasını gerektirir?","options":["İstisnai Eyaletler Arası (Excepted Interstate)","İstisnai Eyalet İçi (Excepted Intrastate)","İstisnai Olmayan Eyaletler Arası (Non-excepted Interstate)","21 yaşın altındaki herhangi bir sürücü"],"explanation":"Dört kategoriden, 'istisnai olmayan' iki tür geçerli bir tıbbi muayene sertifikası gerektirir; istisnai olmayan eyaletler arası sürücü, Michigan SOS'te dosyada güncel bir DOT medical card bulundurmak zorundadır. Kaynak: Michigan SOS CDL Self-Certification (BFS-103)."},"39":{"q":"Bir Michigan başvuru sahibi, CDL bilgi sınavından önce eğitim gereksinimini karşılamak için ELDT teori (bilgi) değerlendirmesinde en az kaç puan almalıdır?","options":["%70","%75","%80","%90"],"explanation":"Michigan'da uygulanan federal ELDT, bir Training Provider Registry sağlayıcısından asgari %80 teori değerlendirme puanı gerektirir. Kaynak: FMCSA ELDT kuralı (49 CFR 380.609); Michigan SOS."},"40":{"q":"Bir CDL sahibinin Michigan'da ticari motorlu bir aracı işletmesi hangi kan alkol konsantrasyonunda (BAC) veya üzerinde yasaktır?","options":["0.08","0.04","0.02","0.10"],"explanation":"Bir CMV'yi 0.04 veya daha yüksek bir BAC ile işletmek Michigan'da büyük bir ihlaldir. Bu, sıradan sürücülere uygulanan 0.08 sınırının yarısıdır. Kaynak: Michigan CDL Manual (alkol/diskalifikasyon bölümü); 49 CFR 383.51 Tablo 1."},"41":{"q":"İlk büyük ihlal için (örneğin bir CMV'yi 0.04 veya daha yüksek BAC ile işletmek gibi), tehlikeli madde söz konusu olmadığında Michigan'da CDL diskalifikasyonu ne kadar sürer?","options":["60 gün","6 ay","1 yıl","3 yıl"],"explanation":"İlk büyük ihlal, Michigan'da 1 yıllık CDL diskalifikasyonuyla sonuçlanır. Kaynak: 49 CFR 383.51 Tablo 1, Michigan Vehicle Code (MCL 257.319b) aracılığıyla Michigan'da benimsenmiştir; Michigan CDL Manual."},"42":{"q":"Sürücünün tehlikeli maddeler için plakart taşıması gereken bir araç işletiyor olması durumunda, ilk büyük ihlal için CDL diskalifikasyonu ne kadar sürer?","options":["1 yıl","18 ay","3 yıl","5 yıl"],"explanation":"Plakartlı bir HazMat aracı işletilirken işlenen ilk büyük ihlal, standart 1 yıl yerine 3 yıllık bir diskalifikasyonla sonuçlanır. Kaynak: 49 CFR 383.51 Tablo 1; Michigan CDL Manual."},"43":{"q":"Michigan'da ikinci bir büyük ihlal için (örneğin ikinci bir alkolle ilgili mahkûmiyet) CDL diskalifikasyon süresi nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"İkinci bir büyük ihlal, Michigan'da ömür boyu CDL diskalifikasyonuyla sonuçlanır. Kaynak: 49 CFR 383.51 Tablo 1; Michigan CDL Manual; MCL 257.319b."},"44":{"q":"Michigan'ın zımni rıza (implied-consent) yasası uyarınca, yasal olarak talep edilen bir kimyasal (alkol) testini ilk kez reddeden bir CDL sahibi, bir CMV işletmekten ne kadar süre diskalifiye edilir?","options":["90 gün","1 yıl","3 yıl","Ömür boyu"],"explanation":"Gerekli bir alkol testine girmeyi ilk kez reddetmek, büyük bir ihlal gibi muamele görür ve sürücü ister bir CMV'de ister kişisel bir araçta olsun, 1 yıllık CDL diskalifikasyonuyla sonuçlanır. Kaynak: Michigan zımni rıza yasası (MCL 257.625c); 49 CFR 383.51 Tablo 1."},"45":{"q":"Aşağıdakilerden hangisi Michigan'da CDL amaçları için bir 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Bir CMV'yi 0.04 veya daha yüksek BAC ile işletmek","Belirlenen sınırın 15 mph veya üzerinde aşılması (hız aşımı)","Bir CMV'nin karıştığı bir kazada olay yerinden ayrılmak","Bir kimyasal testi reddetmek"],"explanation":"Belirlenen sınırı 15 mph veya daha fazla aşan hız aşımı, ciddi bir trafik ihlalidir. Diğer seçenekler büyük ihlallerdir, ciddi ihlal değildir. Kaynak: 49 CFR 383.51 Tablo 2; Michigan CDL Manual."},"46":{"q":"Bir CDL sahibi, 3 yıllık bir süre içinde ayrı olaylardan kaynaklanan İKİ ciddi trafik ihlalinden mahkûm olur. Michigan'da diskalifikasyon süresi nedir?","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde ayrı olaylarda iki ciddi trafik ihlali, 60 günlük CDL diskalifikasyonuyla sonuçlanır. Kaynak: 49 CFR 383.51 Tablo 2; Michigan CDL Manual."},"47":{"q":"Bir CDL sahibi, 3 yıllık bir süre içinde ayrı olaylardan kaynaklanan ÜÇ ciddi trafik ihlalinden mahkûm olur. Diskalifikasyon süresi nedir?","options":["60 gün","90 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde ayrı olaylarda üç veya daha fazla ciddi trafik ihlali, 120 günlük CDL diskalifikasyonuyla sonuçlanır. Kaynak: 49 CFR 383.51 Tablo 2; Michigan CDL Manual."},"48":{"q":"HERHANGİ BİR diskalifikasyonun başlaması için bir CDL sahibinin 3 yıllık bir süre içinde kaç ciddi trafik ihlali biriktirmesi gerekir?","options":["Bir","İki","Üç","Dört"],"explanation":"Tek bir ciddi trafik ihlali diskalifikasyonu tetiklemez; ilk diskalifikasyon (60 gün), 3 yıl içindeki İKİNCİ mahkûmiyette uygulanır. Kaynak: 49 CFR 383.51 Tablo 2; Michigan CDL Manual."},"49":{"q":"Ticari motorlu bir araçta işlenen hangi ihlal, Michigan'da 60/120 günlük diskalifikasyona doğru sayılabilecek belirlenmiş bir ciddi trafik ihlalidir?","options":["CMV'yi sürerken kısa mesaj (texting) yazmak","0.04 veya daha yüksek BAC ile işletmek","Bir suç işlemek için bir CMV kullanmak","Bir hizmet dışı bırakma (out-of-service) emrini ihlal etmek"],"explanation":"Bir CMV'yi sürerken kısa mesaj yazmak, ciddi bir trafik ihlali olarak listelenir. BAC 0.04+ ve bir suçta CMV kullanmak büyük ihlallerdir ve hizmet dışı bırakma emri ihlalinin kendi ayrı ceza programı vardır. Kaynak: 49 CFR 383.51 Tablo 2; Michigan CDL Manual."},"50":{"q":"Bir CMV'de İLK demiryolu-karayolu hemzemin geçit ihlalinden mahkûm olan bir sürücü, Michigan'da en az ne kadar süre diskalifiye edilir?","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, 60 günden az olmayan bir diskalifikasyon taşır. Kaynak: 49 CFR 383.51 Tablo 3; Michigan CDL Manual."},"51":{"q":"3 yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali için asgari CDL diskalifikasyonu nedir?","options":["60 gün","90 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali, 120 günden az olmayan bir diskalifikasyon taşır. Kaynak: 49 CFR 383.51 Tablo 3; Michigan CDL Manual."},"52":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali için asgari diskalifikasyon nedir?","options":["120 gün","180 gün","1 yıl","3 yıl"],"explanation":"3 yıl içinde üçüncü veya sonraki bir demiryolu-karayolu hemzemin geçit ihlali, 1 yıldan az olmayan bir diskalifikasyon taşır. Kaynak: 49 CFR 383.51 Tablo 3; Michigan CDL Manual."},"53":{"q":"Bir CMV işletilirken (HazMat olmayan, yolcu olmayan) bir sürücü veya araç hizmet dışı bırakma emrinin İLK ihlalinden mahkûm olunması için diskalifikasyon süresi nedir?","options":["30 günden az olmamak","90 günden az ancak 1 yıldan fazla olmamak","180 günden az ancak 1 yıldan fazla olmamak","1 yıldan az ancak 5 yıldan fazla olmamak"],"explanation":"İlk hizmet dışı bırakma emri ihlali, 180 günden az ve 1 yıldan fazla olmayan bir diskalifikasyonla sonuçlanır. Kaynak: 49 CFR 383.51 Tablo 4; Michigan CDL Manual."},"54":{"q":"10 yıllık bir süre içinde ayrı olaylarda İKİNCİ bir hizmet dışı bırakma emri ihlali için diskalifikasyon aralığı nedir?","options":["180 günden az ancak 1 yıldan fazla olmamak","1 yıldan az ancak 3 yıldan fazla olmamak","2 yıldan az ancak 5 yıldan fazla olmamak","3 yıldan az ancak 5 yıldan fazla olmamak"],"explanation":"10 yıl içinde ikinci bir hizmet dışı bırakma emri ihlali, 2 yıldan az ve 5 yıldan fazla olmayan bir diskalifikasyonla sonuçlanır. Kaynak: 49 CFR 383.51 Tablo 4; Michigan CDL Manual."},"55":{"q":"Bir sürücü, plakartlı tehlikeli maddeler taşırken veya 16 ya da daha fazla yolcu taşırken İLK kez bir hizmet dışı bırakma emrini ihlal eder. Diskalifikasyon aralığı nedir?","options":["90 günden az ancak 1 yıldan fazla olmamak","180 günden az ancak 2 yıldan fazla olmamak","1 yıldan az ancak 3 yıldan fazla olmamak","3 yıldan az ancak 5 yıldan fazla olmamak"],"explanation":"Plakartlı HazMat taşırken veya 16+ yolcu taşırken ilk hizmet dışı bırakma emri ihlali, 180 günden az ve 2 yıldan fazla olmayan bir diskalifikasyonla sonuçlanır. Kaynak: 49 CFR 383.51 Tablo 4; Michigan CDL Manual."},"56":{"q":"Michigan'da benimsenen federal kurallara göre, bir CMV sürücüsünün araç kullanırken elde tutulan bir cep telefonu kullanması veya kısa mesaj yazması nedeniyle karşılaşabileceği azami hukuki para cezası nedir?","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Bir sürücü, elde tutulan telefon veya kısa mesaj ihlali için en fazla $2,750 para cezasına çarptırılabilir; buna izin veren veya bunu gerektiren bir işveren en fazla $11,000 para cezasına çarptırılabilir. Kaynak: 49 CFR 392.80/392.82 ve FMCSA No-Texting/Hand-Held kuralı bilgi notu; Michigan CDL Manual."},"57":{"q":"Görev başındayken herhangi bir ölçülen veya tespit edilen alkolle bulunan ya da görev başına gitmeden önceki 4 saat içinde alkol kullanan veya bulunduran bir CMV sürücüsünün anlık sonucu nedir?","options":["Anlık 1 yıllık CDL diskalifikasyonu","24 saat boyunca hizmet dışı bırakılma","7 gün boyunca hizmet dışı bırakılma","Anlık ömür boyu diskalifikasyon"],"explanation":"Alkol yasağı uyarınca, böyle bir sürücü 24 saat boyunca hizmet dışı bırakılmalıdır. Bu, 0.04 büyük ihlal eşiğinden ayrıdır. Kaynak: 49 CFR 392.5; Michigan CDL Manual."},"58":{"q":"Bir CDL sahibi, KENDİ kişisel (ticari olmayan) aracını kullanırken alkolle ilgili bir sürüş ihlalinden mahkûm olur. Bu, Michigan'da CDL'yi nasıl etkiler?","options":["Hiçbir CMV söz konusu olmadığı için hiçbir etkisi yoktur","1 yıllık CDL diskalifikasyonuyla sonuçlanır","Yalnızca 60 günlük bir diskalifikasyonla sonuçlanır","Diskalifikasyonla değil, yalnızca cezai puanlarla sonuçlanır"],"explanation":"Alkol ihlalleri de dahil olmak üzere büyük ihlaller, kişisel bir araçta işlendiğinde bile CDL diskalifikasyonunu tetikler; bu tür ilk ihlal 1 yıllık bir diskalifikasyondur. Kaynak: 49 CFR 383.51 Tablo 1; Michigan CDL Manual."},"59":{"q":"Bir CMV sürücüsü 0.02 veya daha yüksek ancak 0.04'ten düşük bir BAC kaydeder. Michigan'da uygulanan kurallara göre sonucu en iyi hangi ifade tanımlar?","options":["1 yıllık diskalifikasyonla büyük bir ihlal olarak muamele görür","0.04'ün altında hiçbir sonuç yoktur","Sürücü 24 saat boyunca güvenlik açısından hassas işlevleri yerine getiremez","Otomatik bir hizmet dışı bırakma emri ihlalidir"],"explanation":"0.02 veya daha yüksek ancak 0.04'ün altında doğrulanmış bir alkol konsantrasyonu, sürücünün 24 saat boyunca güvenlik açısından hassas işlevleri yerine getirmesini engeller; diskalifiye edici bir büyük ihlal 0.04'te başlar. Kaynak: 49 CFR 382.505 ve 383.51; Michigan CDL Manual."},"60":{"q":"Michigan'in Move Over (Şerit Değiştir) yasasına göre, ışıkları yanan, sabit duran bir acil durum aracına yaklaşırken güvenli bir şekilde bir şerit yana geçemezseniz, hızınızı belirlenmiş hız sınırının ne kadar altına düşürmeniz gerekir?","options":["Belirlenmiş hız sınırının en az 10 mph altına","Belirlenmiş hız sınırının en az 5 mph altına","Belirlenmiş hız sınırının en az 15 mph altına","Belirlenmiş hız sınırının en az 20 mph altına"],"explanation":"Michigan'in Move Over yasası (MCL 257.653a), ışıkları yanan, sabit duran yetkili bir acil durum aracına yaklaşan sürücünün en az bir şerit yana geçmesini veya bu mümkün değilse hızını belirlenmiş hız sınırının en az 10 mph altına düşürüp gereken dikkatle geçmesini gerektirir. Kaynak: MCL 257.653a; Michigan State Police Move Over kampanyası."},"61":{"q":"Michigan'de tek yönde iki veya daha fazla seyir şeridi olan bir karayolunda, brüt ağırlığı 10.000 pound'dan fazla olan bir kamyon, bir çekici (truck-tractor) veya bir kombinasyon hangi şeritte sürülebilir?","options":["Yalnızca en sağdaki iki şeritten herhangi birinde","Tıpkı binek otomobiller gibi herhangi bir şeritte","Her zaman yalnızca en sağdaki tek şeritte","Birleşen trafikten kaçınmak için yalnızca orta şeritte"],"explanation":"Michigan yasası (MCL 257.634), tek yönde iki veya daha fazla şeridi olan bir karayolunda 10.000 lbs'den ağır bir kamyonun, bir çekicinin veya bir araç-römork kombinasyonunun yalnızca en sağdaki iki şeritten birinde sürülmesini gerektirir. Kaynak: MCL 257.634."},"62":{"q":"Michigan'de belirlenmiş hız sınırının 65 mph'den fazla olduğu sınırlı erişimli bir otoyolda (freeway), brüt ağırlığı 10.000 pound veya daha fazla olan bir kamyon için maksimum hız nedir?","options":["65 mph","60 mph","70 mph","55 mph"],"explanation":"MCL 257.627 uyarınca, belirlenmiş sınırın 65 mph'i aştığı yerlerde, 10.000 lbs veya daha ağır bir kamyon, bir çekici veya kombinasyon ya da bir okul otobüsü, sınırlı erişimli bir otoyolda veya eyalet ana hat karayolunda (state trunkline highway) 65 mph'i aşamaz. Bu, 2016 tarihli Public Act 445 ile yapılan değişikliği yansıtır. Kaynak: MCL 257.627."},"63":{"q":"Michigan'de, plakart taşıyan tehlikeli madde aracının sürücüsü, bir demiryolu rayını hemzemin geçitte geçmeden önce en yakın raya ne kadar mesafede durmalıdır?","options":["50 feet içinde ancak 15 feet'ten az olmamak üzere","100 feet içinde ancak 25 feet'ten az olmamak üzere","40 feet içinde ancak 10 feet'ten az olmamak üzere","75 feet içinde ancak 20 feet'ten az olmamak üzere"],"explanation":"MCL 257.669, plakart taşıyan araçların (ve 16 veya daha fazla yolcu ya da ücretli yolcu taşıyan araçların) sürücülerinin geçmeden önce dörtlü flaşörleri yakmasını ve en yakın raya 50 feet içinde ancak 15 feet'ten az olmamak üzere durmasını gerektirir. Kaynak: MCL 257.669; Michigan CDL Manual Bölüm 9."},"64":{"q":"Michigan'de, dönüşümlü olarak yanıp sönen iki kırmızı ışıkla durmuş bir okul otobüsüne yaklaşan veya onunla karşılaşan bir araç, otobüse en az ne kadar mesafede tam olarak durmalıdır?","options":["20 feet'ten az olmamak üzere","10 feet'ten az olmamak üzere","15 feet'ten az olmamak üzere","30 feet'ten az olmamak üzere"],"explanation":"MCL 257.682, yanıp sönen kırmızı ışıkları gösteren bir okul otobüsünü geçen veya onunla karşılaşan bir sürücünün otobüse 20 feet'ten az olmamak üzere durmasını ve otobüs hareket edene ya da sinyaller kapatılana kadar devam etmemesini gerektirir. Kaynak: MCL 257.682."},"65":{"q":"Michigan'de, yükseltilmiş bir ara boşluk veya fiziksel bariyerle iki yola bölünmüş bir karayolunda, karşı taraftaki, yanıp sönen kırmızı ışıkları gösteren bir okul otobüsü için hangi sürücülerin durması GEREKMEZ?","options":["Bariyerin karşısındaki diğer yoldan otobüsle karşılaşan sürücüler","Her iki yöndeki tüm sürücüler yine de durmalıdır","Yalnızca doğrudan otobüsün arkasındaki sürücüler","Yalnızca otobüse en yakın şeritteki sürücüler"],"explanation":"MCL 257.682(2) uyarınca, bir karayolu yükseltilmiş bir ara boşluk, fiziksel bariyer veya açıkça belirtilmiş bir ayırma bölümüyle iki yola bölünmüşse, o ayrımın karşısından otobüsle karşılaşan bir sürücünün durması gerekmez. Otobüsün arkasında aynı yolda seyreden sürücüler yine de durmalıdır. Kaynak: MCL 257.682(2)."},"66":{"q":"Bir Michigan CDL sürücüsü, ticari bir aracı tek yönlü veya bölünmüş bir karayolunun banketinde durdurduğunda, üç reflektörlü uyarı üçgeni nereye yerleştirilmelidir?","options":["Yaklaşan trafiğe doğru 10, 100 ve 200 feet mesafede","Aracın her iki tarafında 10, 100 ve 100 feet mesafede","Yaklaşan trafiğe doğru 25, 100 ve 250 feet mesafede","Yaklaşan trafiğe doğru 50, 150 ve 300 feet mesafede"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda, uyarı cihazları aracın arkasından yaklaşan trafiğe doğru 10, 100 ve 200 feet mesafelere yerleştirilir. Michigan CDL Manual, federal FMCSA standardını (49 CFR 392.22) izler. Kaynak: Michigan CDL Manual; 49 CFR 392.22."},"67":{"q":"İki şeritli, çift yönlü bir Michigan karayolunda, durmuş bir CMV sürücüsü üç uyarı üçgenini nasıl yerleştirmelidir?","options":["Biri yaklaşık 10 feet arkada, biri yaklaşık 100 feet arkada ve biri aracın yaklaşık 100 feet önünde","Üçü de aracın yaklaşık 100 feet arkasında bir sırada","Biri 10, biri 200 ve biri aracın 500 feet arkasında","Biri kaputun üzerinde ve ikisi aracın yaklaşık 50 feet arkasında"],"explanation":"İki şeritli, çift yönlü bir yolda, bir üçgeni arkaya doğru yaklaşan trafiğe doğru yaklaşık 10 feet, birini yaklaşık 100 feet arkaya ve birini aracın yaklaşık 100 feet önüne yerleştirin. Kaynak: Michigan CDL Manual; 49 CFR 392.22."},"68":{"q":"Michigan'in bahar 'don yasası' (frost law) mevsimsel ağırlık kısıtlamaları sırasında, Michigan Vehicle Code'da belirtildiği şekilde, kısıtlı bir rotada azaltılmış yük ağırlığı taşıyan ticari bir araç için maksimum hız nedir?","options":["35 mph","45 mph","25 mph","55 mph"],"explanation":"MCL 257.627, azaltılmış (mevsimsel) yük sınırlarının yürürlükte olduğu dönemlerde, bu azaltılmış yükler altında çalışan araçların 35 mph ile sınırlı olduğunu öngörür. Bu, Michigan'in ayırt edici don yasası programının bir parçasıdır. Kaynak: MCL 257.627; MDOT mevsimsel ağırlık kısıtlamaları."},"69":{"q":"Michigan'in mevsimsel ağırlık kısıtlamaları kapsamında, bahar çözülmesi sırasında yasal aks ağırlıklarında HİÇBİR azaltma yapılmayan rotalar olarak hangileri belirlenmiştir?","options":["MDOT Truck Operators Map üzerinde yeşil ve altın renkte gösterilen 'tüm mevsim' (all-season) rotaları","Tüm ilçe çakıl yolları","Yalnızca şehir sınırları içindeki eyaletler arası otoyollar","MDOT Truck Operators Map üzerinde düz veya kesik kırmızıyla gösterilen rotalar"],"explanation":"MDOT, yıl boyunca tam yasal aks ağırlıklarını koruyan 'tüm mevsim' (all-season) rotaları (MDOT Truck Operators Map üzerinde yeşil ve altın) belirler; 'mevsimsel' rotalar (düz veya kesik kırmızı) ise bahar aks ağırlığı azaltmalarına tabidir. Kaynak: MDOT Truck Operators Map / mevsimsel ağırlık kısıtlaması kılavuzu."},"70":{"q":"Michigan'in bahar ağırlık kısıtlamaları sırasında bir 'mevsimsel' rotada, esnek (asfalt) kaplamaya hangi aks ağırlığı azaltması uygulanır?","options":["yüzde 35","yüzde 25","yüzde 10","yüzde 50"],"explanation":"Bahar kısıtlamaları sırasında mevsimsel rotalarda MDOT, esnek (asfalt) kaplamada yüzde 35 ve sert (beton) kaplamada yüzde 25 aks ağırlığı azaltması uygular. Kaynak: MDOT mevsimsel ağırlık kısıtlaması kılavuzu."},"71":{"q":"Bir Michigan CDL sürücüsü, plakart taşıyan bir yük taşırken 'EXEMPT' (muaf) yazılı bir işaretle işaretlenmiş bir demiryolu geçidine yaklaşır. Michigan yasası ne gerektirir?","options":["'Exempt' olarak işaretlenmiş bir geçitte durmak gerekmez","Sürücü yine de en yakın raya 50 feet içinde durmalıdır","Sürücü durmalı ve uyarı üçgenleri yerleştirmelidir","Sürücü yalnızca dörtlü flaşörler kullanılamıyorsa durmalıdır"],"explanation":"MCL 257.669 uyarınca, plakart taşıyan araçlar için bile 'exempt' (muaf) yazılı bir işaretle işaretlenmiş bir demiryolu hemzemin geçidinde durmak gerekmez. Diğer tüm geçitlerde plakart taşıyan araç en yakın raya 15 ila 50 feet mesafede durmalıdır. Kaynak: MCL 257.669."},"72":{"q":"Michigan'de gabari aşımı (oversize) izni olmadan ticari bir aracın veya yükünün maksimum yasal genişliği nedir?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"MCL 257.717, Michigan'in maksimum yasal genişliğini 96 inches (8 feet) olarak belirler; daha geniş olan her şey bir oversize izni gerektirir. Bunun, diğer birçok eyalette kullanılan 102-inch standardından daha dar olduğunu unutmayın. Kaynak: MCL 257.717; MDOT Maximum Legal Truck Loadings and Dimensions."},"73":{"q":"Michigan'de izin olmadan, yüklü veya yüksüz olarak ticari bir aracın maksimum yasal yüksekliği nedir?","options":["13 feet 6 inches","14 feet 0 inches","13 feet 0 inches","12 feet 6 inches"],"explanation":"MCL 257.719, Michigan'in yüklü veya yüksüz maksimum yasal araç yüksekliğini 13 feet 6 inches olarak belirler. Kaynak: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions."},"74":{"q":"Aynı yönde üç veya daha fazla seyir şeridi olan bir Michigan otoyolunda (freeway), şerit kullanım yasası (MCL 257.634) bir aracın hangi şeridi kullanması gerektiği konusunda ne der?","options":["Bir aracın, aynı yönde üç veya daha fazla şeridi olan bir otoyolun herhangi bir şeridinde seyretmesi yasak değildir","Tüm araçlar geçiş yapmadıkça en sağdaki şeritte kalmalıdır","Kamyonlar yalnızca orta şeridi kullanmalıdır","Tüm araçlar yalnızca en soldaki iki şeridi kullanmalıdır"],"explanation":"MCL 257.634, sağda kalma gerekliliğinin bir aracın aynı yönde üç veya daha fazla şeridi olan bir otoyolun herhangi bir şeridinde seyretmesini yasaklamadığını öngörür. Ancak ağır kamyonlar yine de en sağdaki iki şeritle sınırlı kalır. Kaynak: MCL 257.634."},"75":{"q":"Michigan'de, bir demiryolu rayını hemzemin geçitte geçmeden önce, bir okul otobüsü sürücüsü en yakın raya 15 ila 50 feet mesafede durmanın yanı sıra aşağıdakilerden hangisini yapmalıdır?","options":["Dörtlü flaşörleri yakmak, yolcu kapısını ve sürücü camını açmak ve her iki yöne dinleyip bakmak","Devam etmeden önce kornaya üç kez basmak","Otobüsün 100 feet arkasına reflektörlü üçgenler yerleştirmek","Düşük vitese geçip hızlanarak geçmek"],"explanation":"MCL 257.1857, bir okul otobüsü sürücüsünün en yakın raya 15-50 feet mesafede durmasını, dörtlü uyarı flaşörlerini yakmasını, gürültü kaynaklarını kapatmasını, yolcu kapısını ve sürücü tarafındaki camı açmasını ve raylar üzerinde vites değiştirmeden devam etmeden önce her iki yöne bakıp dinlemesini gerektirir. Kaynak: MCL 257.1857."},"76":{"q":"Bir CDL sürücüsü, hız sınırı işareti olmayan iki şeritli bir Michigan ilçe karayolundadır. Geçerli olan genel yasal hız sınırı nedir?","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"MCL 257.627, başka bir sınır belirtilmemiş ana hat ve ilçe karayollarında 55 mph genel hız sınırı belirler (ve buna uyumlu bir 55 mph genel çakıl yolu hız sınırı). Ağır bir kamyon bunu aşamaz. Kaynak: MCL 257.627."},"77":{"q":"Michigan'de faaliyet gösteren ticari sürücüler için ücretli yollar (toll road) hakkında hangi ifade doğrudur?","options":["Michigan'de ücretli karayolu yoktur; ücretler yalnızca Mackinac, Blue Water ve International köprüleri gibi belirli köprü ve tünel geçişlerinde uygulanır","Tüm Michigan eyaletler arası otoyolları, bir transponder gerektiren ücretli yollardır","Kamyonlar I-94 ve I-75'te ücret öder ancak otomobiller ödemez","Michigan, kış aylarında tüm eyalet ana hat karayollarında ücret alır"],"explanation":"Michigan'in eyaletler arası ve eyalet karayolları ücretsizdir; ücretler yalnızca Mackinac Bridge, Blue Water Bridge ve Sault Ste. Marie'deki International Bridge gibi belirli sınır ve boğaz geçişlerinde alınır. Kaynak: MDOT köprü ücreti bilgisi."},"78":{"q":"Rutin periyodik araç muayeneleri açısından, Michigan'de kayıtlı ticari araçlar için ne doğrudur?","options":["Michigan, eyalet çapında periyodik bir güvenlik veya emisyon muayenesi gerektirmez, ancak CMV'ler yine de federal CMV muayene gerekliliklerini karşılamalıdır","Michigan, her ticari araç için yıllık emisyon testi gerektirir","Michigan, eyalet tarafından işletilen bir istasyonda iki yılda bir güvenlik muayenesi gerektirir","Michigan, her CDL yenilemesinden önce bir egzoz (smog) kontrolü gerektirir"],"explanation":"Michigan, araçlar için eyalet çapında periyodik bir güvenlik veya emisyon muayenesi zorunlu kılmaz. Ancak ticari motorlu araçlar, eyalet programının olmamasına bakılmaksızın federal FMCSA muayene ve bakım gerekliliklerine tabi olmaya devam eder. Kaynak: Michigan SOS / MDOT; 49 CFR Part 396."},"79":{"q":"Michigan'in Move Over yasasına göre, trafik koşulları sabit duran yetkili bir acil durum aracı için şerit değiştirmenize izin verdiğinde, ne kadar yana geçmeniz gerekir?","options":["Sabit duran araçtan en az bir seyir şeridi veya iki araç genişliği uzağa","Yolun tamamen dışına, en uzaktaki bankete","Sabit duran araçtan en az üç araç genişliği uzağa","Konumdan bağımsız olarak en soldaki şeride"],"explanation":"MCL 257.653a, sürücülerin mümkün olduğunda sabit duran yetkili acil durum aracından en az bir seyir şeridi veya iki araç genişliği uzaktaki bir şeride geçmesini ve aynı zamanda belirlenmiş sınırın en az 10 mph altına yavaşlamasını gerektirir. Kaynak: MCL 257.653a."},"80":{"q":"Michigan'de Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["Michigan State Police Commercial Vehicle Division","Michigan Department of Transportation (MDOT)","Michigan Department of State (Secretary of State)","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"Michigan'de CDL'ler, başında Secretary of State'in bulunduğu Michigan Department of State tarafından verilir; CDL bilgi testleri ve başvuruları SOS ofislerinde yürütülür. Kaynak: Michigan CDL Manual (SOS) ve michigan.gov SOS CDL sayfaları."},"81":{"q":"Michigan'de CDL yol ve temel araç kontrol becerisi testleri nerede yapılır?","options":["Herhangi bir Secretary of State şube ofisinde SOS personeli tarafından","FMCSA bölgesel test merkezlerinde","Michigan State Police motorlu taşıt memurları tarafından","MDOS onaylı üçüncü taraf sürücü test işletmeleri tarafından"],"explanation":"Michigan, CDL becerisi testlerini SOS şubelerinde yapmaz; üç bölümlü becerisi testi, Michigan Department of State (MDOS) onaylı üçüncü taraf sürücü test işletmeleri tarafından uygulanır. Kaynak: Michigan CDL Manual (SOS)."},"82":{"q":"Michigan CDL becerisi testi kaç bölümden oluşur?","options":["İki: yazılı bir test ve bir yol sürüş testi","Üç: sefer öncesi muayene, temel araç kontrolü ve yol sürüşü","İki: temel kontrol becerileri ve bir tehlikeli madde kontrolü","Dört: sefer öncesi, geri manevra, yol sürüşü ve yazılı bir güvenlik testi"],"explanation":"Michigan CDL becerisi testi üç bölümden oluşur: araç (sefer öncesi) muayene testi, temel araç kontrol becerisi testi ve yol sürüş testi; bunların hepsinin geçilmesi gerekir. Kaynak: Michigan CDL Manual (SOS)."},"83":{"q":"İlk kez CDL başvurusu yapan bir kişi Michigan'de becerisi testine girmeden önce hangi federal eğitimin tamamlanması gerekir?","options":["En az altı aylık, işveren sponsorluğunda bir çıraklık","40 saatlik bir tehlikeli madde güvenliği kursu","Kayıtlı bir sağlayıcıdan Entry-Level Driver Training (ELDT)","MDOT onaylı bir defansif sürüş kursu"],"explanation":"7 Şubat 2022'den bu yana, FMCSA Entry-Level Driver Training (ELDT) kuralı, ilk kez CDL başvurusu yapanların (ve belirli yükseltmeler/onayların) becerisi testinden önce FMCSA Training Provider Registry'de yer alan bir sağlayıcıdan ELDT tamamlamasını gerektirir. Kaynak: Michigan CDL Manual (SOS); FMCSA ELDT kuralı."},"84":{"q":"Bir CLP aldıktan sonra, bir Michigan başvuru sahibinin CDL becerisi testine girmeden önce ne kadar beklemesi gerekir?","options":["En az 7 gün","En az 60 gün","En az 14 gün","En az 30 gün"],"explanation":"Federal ve Michigan kuralları, başvuru sahibinin CDL becerisi testine girebilmesi için CLP'nin en az 14 gün boyunca elde tutulmasını gerektirir. Kaynak: Michigan CDL Manual (SOS); 49 CFR 383.25."},"85":{"q":"Bir Michigan CDL için sürüş türünü kendi beyan ederken (self-certify), başvuru sahibinin kaç federal kategoriden seçim yapması gerekir?","options":["İki","Beş","Üç","Dört"],"explanation":"Her Michigan CDL başvuru sahibi dört kategoriden birine kendi beyanda bulunmalıdır: non-excepted interstate, excepted interstate, non-excepted intrastate veya excepted intrastate. Kaynak: Michigan CDL Self-Certification Form (SOS); 49 CFR 383.71."},"86":{"q":"Hangi self-certification kategorisi, bir Michigan sürücüsünün federal DOT tıbbi muayene uzmanı sertifikasını (medical examiner's certificate) bulundurmasını gerektirir?","options":["Kategorilerin hiçbiri tıbbi sertifika gerektirmez","Non-excepted interstate","Excepted intrastate","Excepted interstate"],"explanation":"'Non-excepted interstate' olarak kendi beyanda bulunan bir sürücü eyaletler arası ticarette faaliyet gösterir ve geçerli bir DOT tıbbi muayene uzmanı sertifikası bulundurmalıdır; 'excepted' kategoriler aynı nedenle bunu gerektirmez. Kaynak: Michigan CDL Self-Certification Form (SOS); 49 CFR 383.71/391."},"87":{"q":"Bir Michigan sürücüsü 'excepted intrastate' olarak kendi beyanda bulunduğunda ne kastetmektedir?","options":["Eyalet sınırları arasında sürüş yaparlar ancak tüm federal kurallardan muaftırlar","Yalnızca Michigan içinde sürüş yaparlar ancak federal bir tıbbi kart bulundurmalıdırlar","Yalnızca Michigan içinde, eyaletin tıbbi sertifikasyon gerekliliklerinden muaf tuttuğu operasyonlarda sürüş yaparlar","Eyaletler arası sürüş yaparlar ve tıbbi kartlarını SOS'a kayıtlı tutmalıdırlar"],"explanation":"'Excepted intrastate', sürücünün bir CMV'yi yalnızca Michigan içinde, eyaletin tıbbi sertifikasyon gerekliliğinden muaf olduğunu belirlediği faaliyetlerde kullandığı anlamına gelir, dolayısıyla federal bir tıbbi kart gerekmez. Kaynak: Michigan CDL Self-Certification Form (SOS); 49 CFR 383.71."},"88":{"q":"Ticari bir motorlu aracı yalnızca Michigan içinde (intrastate) sürmek için bir CDL verilmesinin minimum yaşı nedir?","options":["21 yaşında","19 yaşında","18 yaşında","16 yaşında"],"explanation":"Bir başvuru sahibi, eyalet içi (yalnızca Michigan) ticari sürüş için bir CDL'ye sahip olmak üzere en az 18 yaşında olmalıdır; eyaletler arası operasyon genellikle 21 yaş gerektirir. Kaynak: Michigan CDL Manual (SOS); MCL 257.312e."},"89":{"q":"Michigan CDL bilgi testlerinde, araç sınıfından bağımsız olarak her CDL başvuru sahibinin geçmesi gereken test hangisidir?","options":["Genel bilgi testi","Yolcu taşıma testi","Tehlikeli madde testi","İkili/üçlü (doubles/triples) testi"],"explanation":"Tüm CDL başvuru sahipleri genel bilgi testini geçmelidir; ek bilgi testleri (örneğin, hava frenleri, kombinasyon, onaylar) talep edilen sınıfa ve onaylara bağlıdır. Kaynak: Michigan CDL Manual (SOS); 49 CFR 383.23."},"90":{"q":"Bir Secretary of State ofisinde Michigan CDL yenilemesinde, aşağıdakilerden hangisi standart sürecin bir parçasıdır?","options":["Tüm yenilemeler için zorunlu bir yazılı tehlikeli madde testi","Bir görme taraması ve başvuru sahibinin eyalet ve ulusal sürüş kaydının incelenmesi","SOS personeli tarafından otomatik olarak yapılan yeni bir DOT fiziksel muayenesi","Her döngüde tam üç bölümlü becerisi testinin yeniden alınması"],"explanation":"Yenilemede SOS ofisi bir görme testi yapar ve başvuru sahibinin eyalet ve ulusal (CDLIS) sürüş kayıtlarını kontrol eder; tam bir becerisi yeniden testi rutin olarak gerekmez. Not: kesin ücretler değişebilir. Kaynak: Michigan CDL Manual (SOS); michigan.gov SOS CDL yenileme sayfası."}},"es":{"0":{"q":"En las carreteras designadas de Míchigan, ¿cuál es el ancho máximo legal de un vehículo comercial (sin incluir los espejos ni cierto equipo de seguridad) antes de que se requiera un permiso de sobredimensión?","options":["108 pulgadas (9 pies)","96 pulgadas (8 pies)","120 pulgadas (10 pies)","102 pulgadas (8 pies 6 pulgadas)"],"explanation":"Míchigan limita el ancho del vehículo a 102 pulgadas (8'6\") en las carreteras designadas y a 96 pulgadas (8') en las demás vías, de acuerdo con la norma federal de la red nacional. Fuente: Código de Vehículos de Míchigan MCL 257.717; MDOT 'Maximum Legal Truck Loadings and Dimensions' (T-1)."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo y su carga en las carreteras de Míchigan sin un permiso especial de transporte?","options":["14 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 6 pulgadas","13 pies 0 pulgadas"],"explanation":"Míchigan establece la altura máxima del vehículo y la carga en 13 pies 6 pulgadas; cualquier cosa más alta requiere un permiso de sobredimensión. Fuente: MCL 257.718; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"2":{"q":"¿Cuál es la longitud máxima de un semirremolque (incluida la carga) que circula por las carreteras designadas de Míchigan sin un permiso?","options":["60 pies","48 pies","53 pies","57 pies"],"explanation":"Míchigan permite un semirremolque de hasta 53 pies, incluida la carga, en las carreteras designadas (50 pies en las vías no designadas). Fuente: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"3":{"q":"Según los límites federales que Míchigan aplica en el sistema interestatal, ¿cuál es el peso bruto vehicular máximo para una combinación estándar de 5 ejes sin un permiso?","options":["88,000 libras","76,000 libras","73,280 libras","80,000 libras"],"explanation":"En el sistema interestatal, Míchigan hace cumplir el tope federal de 80,000 libras de peso bruto para los vehículos sujetos a la fórmula federal de puentes. Fuente: 23 CFR 658.17 según se aplica en Míchigan; guía de peso de camiones del MDOT."},"4":{"q":"¿Cuál es el límite federal de peso por eje sencillo que se aplica a los vehículos que operan bajo la norma federal de 80,000 libras en las carreteras interestatales de Míchigan?","options":["24,000 libras","22,400 libras","18,000 libras","20,000 libras"],"explanation":"Para los vehículos regidos por la norma federal de 80,000 libras, el límite por eje sencillo es de 20,000 libras, la misma cifra que Míchigan aplica en la interestatal. Fuente: 23 CFR 658.17 según se aplica en Míchigan; guía de peso del MDOT."},"5":{"q":"Según la norma federal aplicada en el sistema interestatal de Míchigan, ¿cuál es el peso máximo permitido en un grupo de ejes en tándem?","options":["36,000 libras","40,000 libras","32,000 libras","34,000 libras"],"explanation":"El límite federal por eje en tándem que Míchigan hace cumplir en la interestatal es de 34,000 libras. Tenga en cuenta que las propias reglas estatales de ejes de Míchigan difieren (vea su máximo normal por eje de 18,000 libras). Fuente: 23 CFR 658.17; guía de peso del MDOT."},"6":{"q":"Debido a las reglas de carga por eje anteriores a los límites federales, ¿cuál es el peso bruto vehicular máximo que un camión configurado correctamente puede transportar legalmente en las vías de Míchigan fuera de la interestatal?","options":["80,000 libras","164,000 libras","105,500 libras","129,000 libras"],"explanation":"La ley de peso heredada (grandfathered) de Míchigan permite un peso bruto máximo de aproximadamente 164,000 libras cuando las cargas por eje y el espaciamiento cumplen, el más alto permitido de forma habitual en Norteamérica. Fuente: MCL 257.722; Michigan House Fiscal Agency, 'Michigan's Truck-Weight Law.'"},"7":{"q":"¿Cuál es el número máximo de ejes permitido en una combinación de camión y remolque de Míchigan que opera bajo las disposiciones estatales de peso pesado?","options":["8 ejes","11 ejes","9 ejes","13 ejes"],"explanation":"Desde 1967, Míchigan ha limitado estas combinaciones a 11 ejes, lo que, junto con los límites por eje, da como resultado el máximo de aproximadamente 164,000 libras. Fuente: MCL 257.722; análisis de peso de camiones de la Michigan House Fiscal Agency."},"8":{"q":"Según la propia ley de carga por eje de Míchigan, ¿cuál es el 'máximo de carga normal' para un eje sencillo separado 9 pies o más de los ejes adyacentes?","options":["16,000 libras","18,000 libras","20,000 libras","22,400 libras"],"explanation":"La ley de Míchigan establece la carga máxima normal por eje sencillo en 18,000 libras cuando el espaciamiento entre ejes es de 9 pies o más, lo cual es inferior a la cifra federal de 20,000 libras. Fuente: MCL 257.722(1)."},"9":{"q":"La ley estatal de ejes de Míchigan limita la carga máxima por rueda a un valor ligado al ancho del neumático. ¿Cuál es ese límite?","options":["500 libras por pulgada de ancho del neumático","700 libras por pulgada de ancho del neumático","600 libras por pulgada de ancho del neumático","850 libras por pulgada de ancho del neumático"],"explanation":"Míchigan limita la carga por rueda a 700 libras por pulgada de ancho del neumático, una norma que distribuye las cargas pesadas sobre más neumáticos y ejes. Fuente: MCL 257.722(7)."},"10":{"q":"Durante el período de deshielo primaveral (ley de heladas) de Míchigan, ¿en qué porcentaje se reducen las cargas máximas por eje en los pavimentos de concreto?","options":["25 por ciento","35 por ciento","10 por ciento","50 por ciento"],"explanation":"Durante marzo, abril y mayo, Míchigan reduce las cargas máximas por eje en un 25 por ciento en los pavimentos de concreto (y en un 35 por ciento en las demás vías) para proteger las bases de las carreteras en deshielo. Fuente: MCL 257.722(8)."},"11":{"q":"Durante las restricciones estacionales de la ley de heladas de Míchigan, ¿en qué porcentaje se reducen las cargas por eje en las vías que no son de pavimento de concreto?","options":["15 por ciento","45 por ciento","35 por ciento","25 por ciento"],"explanation":"En las vías que no son de concreto, las restricciones de peso primaverales de Míchigan reducen las cargas máximas por eje en un 35 por ciento durante el período de deshielo de marzo a mayo. Fuente: MCL 257.722(8)."},"12":{"q":"¿En qué meses se aplica normalmente la reducción estacional de peso (ley de heladas) de Míchigan?","options":["Marzo, abril y mayo","Enero, febrero y marzo","Noviembre, diciembre y enero","Abril, mayo y junio"],"explanation":"Las reducciones estacionales de carga por eje de Míchigan se aplican durante el deshielo primaveral, ligadas por ley a marzo, abril y mayo, con las fechas exactas de inicio y fin anunciadas por el MDOT cada año. Fuente: MCL 257.722(8); avisos de restricción estacional de peso del MDOT."},"13":{"q":"La ley de Míchigan permite que la carga de una combinación de vehículos se extienda hasta qué distancia más allá de la parte trasera del vehículo antes de requerir una advertencia adicional?","options":["2 pies","3 pies","4 pies","6 pies"],"explanation":"Una carga puede sobresalir hasta 4 pies más allá de la parte trasera (y 3 pies más allá del frente); un voladizo trasero de 4 pies o más requiere una bandera roja de día y una luz roja de noche. Fuente: MCL 257.719; guía de dimensiones de carga del MDOT."},"14":{"q":"Una carga que se extiende más allá de la parte trasera de un vehículo comercial de Míchigan debe mostrar una luz o linterna roja de noche una vez que el voladizo alcanza qué longitud?","options":["8 pies","2 pies","4 pies","6 pies"],"explanation":"Míchigan exige una bandera roja durante el día y una luz o linterna roja de noche para cualquier carga que sobresalga 4 pies o más más allá de la parte trasera del vehículo. Fuente: MCL 257.719; guía de dimensiones de carga del MDOT."},"15":{"q":"¿Quién emite los permisos de transporte de sobredimensión/sobrepeso para circular por las carreteras troncales estatales de Míchigan?","options":["La Administración Federal de Seguridad de Autotransportes (FMCSA)","Solo la Policía Estatal de Míchigan","El Departamento de Transporte de Míchigan (MDOT)","El Michigan Secretary of State"],"explanation":"El MDOT emite los permisos por exceso de tamaño o peso en las troncales estatales, mientras que las agencias viales locales se encargan de las vías bajo su jurisdicción. Fuente: MCL 257.725; permisos de sobredimensión/sobrepeso del MDOT."},"16":{"q":"¿A través de qué sistema en línea solicita un transportista un permiso de sobredimensión/sobrepeso del MDOT en Míchigan?","options":["CDLIS (Commercial Driver License Information System)","IRP (portal del International Registration Plan)","SAFER (Safety and Fitness Electronic Records)","MiTRIP (Michigan Transport Routing and Internet Permitting)"],"explanation":"Los transportistas de Míchigan obtienen los permisos de transporte de forma electrónica a través de MiTRIP, el sistema en línea de enrutamiento y emisión de permisos del MDOT. Fuente: permisos de sobredimensión/sobrepeso del MDOT; MCL 257.725."},"17":{"q":"Un permiso de sobredimensión para un solo viaje en Míchigan se emite generalmente para el movimiento ocasional de una carga que:","options":["Se transporta enteramente en propiedad privada","No puede desmontarse ni reorganizarse para entrar dentro de los límites legales","El transportista simplemente prefiere no dividir en cargas más pequeñas","Excede los límites legales en menos del uno por ciento"],"explanation":"Los permisos de Míchigan se emiten únicamente para el movimiento ocasional de cargas de sobredimensión o sobrepeso que no puedan razonablemente desmontarse, reducirse ni reorganizarse para cumplir con los límites legales. Fuente: MCL 257.725; política de permisos del MDOT."},"18":{"q":"Según la disposición de Míchigan para vehículos a gas natural, ¿en cuánto puede un vehículo propulsado por gas natural exceder los límites de peso aplicables para tener en cuenta el sistema de combustible más pesado?","options":["5,000 libras","2,000 libras","550 libras","10,000 libras"],"explanation":"Míchigan otorga a los vehículos a gas natural una tolerancia de hasta 2,000 libras por encima de los límites de peso que de otro modo serían aplicables, para compensar el peso adicional del sistema de combustible. Fuente: Código de Vehículos de Míchigan; guía de peso del MDOT acorde con la tolerancia federal para NGV de 23 U.S.C. 127."},"19":{"q":"Para una combinación de Míchigan como un tractocamión que remolca dos unidades, ¿cuál es la longitud total máxima (medida desde el frente de la primera unidad remolcada hasta la parte trasera de la última) antes de que se requiera un permiso?","options":["75 pies","58 pies","65 pies","53 pies"],"explanation":"Míchigan permite estas combinaciones dobles sin una longitud total fija del vehículo, siempre que las unidades remolcadas, medidas desde el frente de la primera hasta la parte trasera de la última, no excedan los 58 pies (cada unidad no más de 28'6\"). Fuente: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"20":{"q":"En Míchigan, ¿qué grupo de CDL se requiere para operar cualquier combinación de vehículos con una clasificación de peso bruto combinado (GCWR) de 26,001 libras o más, donde la unidad remolcada tiene un GVWR de más de 10,000 libras?","options":["Grupo A","Grupo B","Grupo C","Grupo D"],"explanation":"Míchigan define una CDL de Grupo (Clase) A como cualquier combinación de vehículos con un GCWR de 26,001 libras o más, siempre que el GVWR de la(s) unidad(es) remolcada(s) sea de más de 10,000 libras. Fuente: Manual de CDL de Míchigan (Michigan SOS), Sección 1."},"21":{"q":"Según las reglas de Míchigan, ¿qué grupo de CDL cubre un solo vehículo con una clasificación de peso bruto vehicular (GVWR) de 26,001 libras o más (que puede remolcar una unidad de 10,000 libras o menos)?","options":["Grupo A","Grupo B","Grupo C","Grupo H"],"explanation":"Una CDL de Grupo (Clase) B en Míchigan es para cualquier vehículo individual con un GVWR de 26,001 libras o más, o para tal vehículo que remolque una unidad de no más de 10,000 libras de GVWR. Fuente: Manual de CDL de Míchigan (Michigan SOS), Sección 1."},"22":{"q":"Una CDL de Grupo (Clase) C de Míchigan se requiere para un vehículo más pequeño (por debajo de los umbrales de peso de Clase A/B) únicamente cuando se utiliza para transportar ¿cuál de los siguientes?","options":["Cualquier carga que pese más de 5,000 libras","16 o más pasajeros (incluido el conductor), o materiales peligrosos en cantidades que requieran rótulos","Cualquier remolque sin importar el peso","Solo niños en edad escolar"],"explanation":"Una CDL de Grupo C de Míchigan se aplica a los vehículos por debajo de los límites de peso de Clase A/B que están diseñados para transportar 16 o más pasajeros incluido el conductor, o que transportan materiales peligrosos en cantidades que requieren rótulos. Fuente: Manual de CDL de Míchigan (Michigan SOS), Sección 1."},"23":{"q":"¿Cuál es la edad mínima para obtener una CDL de Míchigan para conducir INTRAESTATAL (operando únicamente dentro de Míchigan)?","options":["16 años","18 años","21 años","25 años"],"explanation":"Míchigan permite una CDL a los 18 años solo para el comercio intraestatal (dentro del estado); la operación interestatal requiere tener 21 años. Fuente: Manual de CDL de Míchigan (Michigan SOS) / elegibilidad de CDL del Michigan SOS."},"24":{"q":"¿Cuál es la edad mínima para obtener una CDL de Míchigan que permita conducir INTERESTATAL (a través de las fronteras estatales)?","options":["18 años","19 años","21 años","23 años"],"explanation":"Las reglas federales y de Míchigan exigen que un conductor tenga al menos 21 años para operar un CMV en el comercio interestatal; los conductores de 18 a 20 años están limitados a la operación intraestatal. Fuente: Manual de CDL de Míchigan (Michigan SOS); 49 CFR 391.11."},"25":{"q":"En Míchigan, ¿cuánto tiempo debe tener un solicitante un Permiso de Aprendiz Comercial (CLP) antes de que se le permita realizar la prueba de habilidades de manejo en carretera de la CDL?","options":["Un mínimo de 7 días","Un mínimo de 14 días","Un mínimo de 30 días","Un mínimo de 60 días"],"explanation":"Míchigan sigue la regla federal que exige que el CLP se posea un mínimo de 14 días antes de que el solicitante pueda realizar la prueba de habilidades de la CDL. Fuente: Michigan SOS (cdl-apply); 49 CFR 383.25."},"26":{"q":"¿Qué endoso se requiere en una CDL de Míchigan para operar un vehículo diseñado para transportar 16 o más personas, incluido el conductor?","options":["P (Pasajeros)","N (Tanque)","T (Dobles/Triples)","H (Materiales Peligrosos)"],"explanation":"El endoso P (Pasajeros) se requiere en Míchigan para operar un vehículo diseñado para transportar 16 o más personas incluido el conductor. Fuente: Manual de CDL de Míchigan (Michigan SOS), sección de endosos."},"27":{"q":"¿Qué endoso de la CDL de Míchigan se requiere para conducir un vehículo comercial utilizado para transportar estudiantes de preescolar, primaria o secundaria hacia y desde la escuela?","options":["P (Pasajeros)","S (Autobús Escolar)","T (Dobles/Triples)","C (Niños)"],"explanation":"El endoso S (Autobús Escolar) se requiere en Míchigan para conducir un autobús escolar que transporta estudiantes; los solicitantes ya deben tener (u obtener) el endoso P y aprobar las pruebas de conocimientos y habilidades de autobús escolar. Fuente: Manual de CDL de Míchigan (Michigan SOS)."},"28":{"q":"En una CDL de Míchigan, ¿qué letra de código único aparece cuando a un conductor se le han emitido AMBOS endosos, el de Tanque (N) y el de Materiales Peligrosos (H)?","options":["X","Z","HN","K"],"explanation":"Míchigan coloca el código combinado X en la licencia en lugar de los códigos N y H separados cuando un conductor tiene ambos endosos, el de tanque y el de materiales peligrosos. Fuente: Manual de CDL de Míchigan (Michigan SOS), sección de endosos."},"29":{"q":"El endoso T de Míchigan cubre las combinaciones de remolques dobles y triples. Sin embargo, en cuanto a los remolques TRIPLES en las vías de Míchigan, ¿qué afirmación es verdadera?","options":["Las combinaciones de remolques triples no están permitidas en Míchigan","Los remolques triples están permitidos solo en las carreteras interestatales en Míchigan","Los remolques triples requieren un permiso de Clase A-T separado en Míchigan","Los remolques triples están permitidos en todo el estado en Míchigan sin restricción"],"explanation":"Aunque existe el endoso T (Dobles/Triples), las combinaciones de remolques triples no están permitidas en las vías de Míchigan. Fuente: Manual de CDL de Míchigan (Michigan SOS), sección de endosos."},"30":{"q":"¿Para qué endoso debe un solicitante de CDL de Míchigan aprobar una Evaluación de Amenazas a la Seguridad de la Administración de Seguridad en el Transporte (TSA), que incluye toma de huellas dactilares y una verificación de antecedentes?","options":["N (Tanque)","T (Dobles/Triples)","H (Materiales Peligrosos)","P (Pasajeros)"],"explanation":"El endoso H (Materiales Peligrosos) requiere una Evaluación de Amenazas a la Seguridad de la TSA con huellas dactilares y una verificación de antecedentes, además de la prueba de conocimientos de HazMat. Fuente: información de CDL del Michigan SOS; TSA HME / 49 CFR 1572."},"31":{"q":"Según las definiciones de Míchigan/federales, el endoso N (Tanque) generalmente se requiere para transportar líquido o gas en un tanque con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de al menos cuántos galones?","options":["500 galones","1,000 galones","1,500 galones","3,000 galones"],"explanation":"El endoso de Tanque (N) se aplica a tanques con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de 1,000 galones o más. Fuente: Manual de CDL de Míchigan (Michigan SOS); 49 CFR 383.5."},"32":{"q":"¿Con qué frecuencia debe un titular de CDL de Míchigan renovar la Evaluación de Amenazas a la Seguridad de la TSA para mantener válido un endoso de Materiales Peligrosos (H)?","options":["Cada año","Cada 3 años","Cada 5 años","Cada 10 años"],"explanation":"La Evaluación de Amenazas a la Seguridad de la TSA para un endoso de HazMat debe renovarse cada 5 años, incluyendo una nueva toma de huellas dactilares y verificación de antecedentes. Fuente: información de CDL del Michigan SOS; TSA HME (49 CFR 1572)."},"33":{"q":"A partir del 7 de febrero de 2022, la Capacitación de Conductores de Nivel Inicial (ELDT) debe completarse antes de hacer la prueba para ¿cuál de los siguientes en Míchigan?","options":["Una CDL de Clase A o Clase B por primera vez, una mejora de Clase B a Clase A, o un endoso P, S o H por primera vez","Solo una CDL de Clase A por primera vez","Cualquier renovación de CDL","Solo el endoso de Tanque (N)"],"explanation":"La ELDT federal, aplicada en Míchigan, se requiere para una CDL de Clase A o Clase B por primera vez, una mejora de Clase B a A, y los endosos de Pasajeros (P), Autobús Escolar (S) o Materiales Peligrosos (H) por primera vez. Fuente: regla ELDT de la FMCSA (49 CFR 380); Michigan SOS."},"34":{"q":"Un solicitante de CDL de Míchigan debe completar la Capacitación de Conductores de Nivel Inicial (ELDT) requerida a través de ¿qué entidad?","options":["Cualquier instructor de manejo que elija el solicitante","Un proveedor incluido en el Registro de Proveedores de Capacitación (TPR) de la FMCSA","El Michigan Secretary of State directamente","La academia de la Policía Estatal de Míchigan"],"explanation":"La ELDT debe ser impartida por una escuela o entidad incluida en el Registro de Proveedores de Capacitación (TPR) de la FMCSA; la finalización se reporta electrónicamente a la FMCSA. Fuente: regla ELDT de la FMCSA (49 CFR 380); Michigan SOS."},"35":{"q":"¿Qué endoso NO requiere Capacitación de Conductores de Nivel Inicial (ELDT) cuando se obtiene por primera vez en una CDL de Míchigan?","options":["H (Materiales Peligrosos)","P (Pasajeros)","S (Autobús Escolar)","N (Tanque)"],"explanation":"La ELDT es obligatoria para los endosos H, P y S por primera vez, pero el endoso N (Tanque) no está cubierto por la regla de ELDT. Fuente: regla ELDT de la FMCSA (49 CFR 380.603); Michigan SOS."},"36":{"q":"¿Qué conjunto de documentos debe presentar un solicitante de CDL de Míchigan en una oficina del Secretary of State para establecer su elegibilidad?","options":["Solo una foto y una tarjeta de crédito","Prueba de identidad/presencia legal, prueba de número de Seguro Social y prueba de residencia en Míchigan","Solo una carta del empleador","Solo una foto tipo pasaporte y pago en efectivo"],"explanation":"Míchigan exige prueba de identidad/presencia legal en los EE. UU., prueba de número de Seguro Social y prueba de residencia en Míchigan para emitir un CLP o una CDL. Fuente: requisitos de documentos de CDL/licencia del Michigan SOS."},"37":{"q":"En la autocertificación de CDL de Míchigan, un conductor que opera un CMV a través de las fronteras estatales y que NO está exento de las reglas federales de calificación física debe certificarse en ¿qué categoría?","options":["Excepted Interstate","Non-excepted Interstate","Excepted Intrastate","Non-excepted Intrastate"],"explanation":"Míchigan usa cuatro categorías de autocertificación; un conductor en el comercio interestatal sujeto a las reglas médicas se certifica como Non-excepted Interstate y debe mantener un certificado válido de examinador médico. Fuente: Formulario de Autocertificación de CDL del Michigan SOS."},"38":{"q":"¿Qué categoría de autocertificación de CDL de Míchigan exige que el conductor mantenga y presente un certificado válido de examinador médico (tarjeta médica del DOT) al Secretary of State?","options":["Excepted Interstate","Excepted Intrastate","Non-excepted Interstate","Cualquier conductor menor de 21 años"],"explanation":"De las cuatro categorías, los dos tipos 'non-excepted' requieren un certificado válido de examinador médico; el conductor non-excepted interstate debe mantener una tarjeta médica del DOT vigente archivada con el Michigan SOS. Fuente: Autocertificación de CDL del Michigan SOS (BFS-103)."},"39":{"q":"Un solicitante de Míchigan debe obtener al menos qué puntuación en la evaluación teórica (de conocimientos) de la ELDT para cumplir con el requisito de capacitación antes de la prueba de conocimientos de la CDL?","options":["70%","75%","80%","90%"],"explanation":"La ELDT federal, aplicada en Míchigan, exige una puntuación mínima en la evaluación teórica del 80% de un proveedor del Registro de Proveedores de Capacitación. Fuente: regla ELDT de la FMCSA (49 CFR 380.609); Michigan SOS."},"40":{"q":"¿A partir de qué concentración de alcohol en la sangre (BAC) se le prohíbe a un titular de CDL operar un vehículo motorizado comercial en Míchigan?","options":["0.08","0.04","0.02","0.10"],"explanation":"Operar un CMV con un BAC de 0.04 o mayor es una infracción mayor en Míchigan. Esto es la mitad del límite de 0.08 que se aplica a los conductores comunes. Fuente: Manual de CDL de Míchigan (sección de alcohol/descalificación); 49 CFR 383.51 Tabla 1."},"41":{"q":"Para una primera infracción mayor (como operar un CMV con un BAC de 0.04 o mayor), ¿cuánto dura la descalificación de la CDL en Míchigan cuando no hay materiales peligrosos involucrados?","options":["60 días","6 meses","1 año","3 años"],"explanation":"Una primera infracción mayor resulta en una descalificación de la CDL de 1 año en Míchigan. Fuente: 49 CFR 383.51 Tabla 1, adoptada en Míchigan a través del Código de Vehículos de Míchigan (MCL 257.319b); Manual de CDL de Míchigan."},"42":{"q":"¿Cuánto dura la descalificación de la CDL para una primera infracción mayor si el conductor estaba operando un vehículo que requiere rótulos para materiales peligrosos?","options":["1 año","18 meses","3 años","5 años"],"explanation":"Una primera infracción mayor cometida mientras se opera un vehículo de HazMat con rótulos resulta en una descalificación de 3 años, en lugar del 1 año estándar. Fuente: 49 CFR 383.51 Tabla 1; Manual de CDL de Míchigan."},"43":{"q":"¿Cuál es el período de descalificación de la CDL para una segunda infracción mayor (por ejemplo, una segunda condena relacionada con el alcohol) en Míchigan?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Una segunda infracción mayor resulta en una descalificación de la CDL de por vida en Míchigan. Fuente: 49 CFR 383.51 Tabla 1; Manual de CDL de Míchigan; MCL 257.319b."},"44":{"q":"Según la ley de consentimiento implícito de Míchigan, un titular de CDL que se niega a una prueba química (de alcohol) solicitada legalmente por primera vez queda descalificado para operar un CMV por ¿cuánto tiempo?","options":["90 días","1 año","3 años","De por vida"],"explanation":"Una primera negativa a someterse a una prueba de alcohol requerida se trata como una infracción mayor y resulta en una descalificación de la CDL de 1 año, ya sea que el conductor estuviera en un CMV o en un vehículo personal. Fuente: ley de consentimiento implícito de Míchigan (MCL 257.625c); 49 CFR 383.51 Tabla 1."},"45":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción de tránsito grave' para fines de la CDL en Míchigan?","options":["Operar un CMV con un BAC de 0.04 o mayor","Exceder la velocidad en 15 mph o más sobre el límite publicado","Abandonar la escena de un accidente que involucra un CMV","Negarse a una prueba química"],"explanation":"Exceder la velocidad en 15 mph o más sobre el límite publicado es una infracción de tránsito grave. Las otras opciones son infracciones mayores, no infracciones graves. Fuente: 49 CFR 383.51 Tabla 2; Manual de CDL de Míchigan."},"46":{"q":"Un titular de CDL es condenado por DOS infracciones de tránsito graves derivadas de incidentes separados dentro de un período de 3 años. ¿Cuál es el período de descalificación en Míchigan?","options":["30 días","60 días","120 días","1 año"],"explanation":"Dos infracciones de tránsito graves en incidentes separados dentro de 3 años resultan en una descalificación de la CDL de 60 días. Fuente: 49 CFR 383.51 Tabla 2; Manual de CDL de Míchigan."},"47":{"q":"Un titular de CDL es condenado por TRES infracciones de tránsito graves de incidentes separados dentro de un período de 3 años. ¿Cuál es el período de descalificación?","options":["60 días","90 días","120 días","1 año"],"explanation":"Tres o más infracciones de tránsito graves en incidentes separados dentro de 3 años resultan en una descalificación de la CDL de 120 días. Fuente: 49 CFR 383.51 Tabla 2; Manual de CDL de Míchigan."},"48":{"q":"¿Cuántas infracciones de tránsito graves dentro de un período de 3 años debe acumular un titular de CDL antes de que comience CUALQUIER descalificación?","options":["Una","Dos","Tres","Cuatro"],"explanation":"Una sola infracción de tránsito grave no desencadena la descalificación; la primera descalificación (60 días) se aplica con la SEGUNDA condena dentro de 3 años. Fuente: 49 CFR 383.51 Tabla 2; Manual de CDL de Míchigan."},"49":{"q":"¿Qué infracción, cometida en un vehículo motorizado comercial, es una infracción de tránsito grave designada que puede contar para la descalificación de 60/120 días en Míchigan?","options":["Enviar mensajes de texto mientras se conduce el CMV","Operar con un BAC de 0.04 o mayor","Usar un CMV para cometer un delito grave","Violar una orden de fuera de servicio"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV figura como una infracción de tránsito grave. Un BAC de 0.04+ y usar un CMV en un delito grave son infracciones mayores, y la violación de una orden de fuera de servicio tiene su propio esquema de sanciones por separado. Fuente: 49 CFR 383.51 Tabla 2; Manual de CDL de Míchigan."},"50":{"q":"Un conductor condenado por una PRIMERA infracción de cruce a nivel de ferrocarril y carretera en un CMV queda descalificado en Míchigan por no menos de ¿cuánto tiempo?","options":["30 días","60 días","120 días","1 año"],"explanation":"Una primera infracción de cruce a nivel de ferrocarril y carretera conlleva una descalificación de no menos de 60 días. Fuente: 49 CFR 383.51 Tabla 3; Manual de CDL de Míchigan."},"51":{"q":"¿Cuál es la descalificación mínima de la CDL para una SEGUNDA infracción de cruce a nivel de ferrocarril y carretera dentro de un período de 3 años?","options":["60 días","90 días","120 días","1 año"],"explanation":"Una segunda infracción de cruce a nivel de ferrocarril y carretera dentro de 3 años conlleva una descalificación de no menos de 120 días. Fuente: 49 CFR 383.51 Tabla 3; Manual de CDL de Míchigan."},"52":{"q":"¿Cuál es la descalificación mínima para una TERCERA infracción de cruce a nivel de ferrocarril y carretera dentro de un período de 3 años?","options":["120 días","180 días","1 año","3 años"],"explanation":"Una tercera o subsiguiente infracción de cruce a nivel de ferrocarril y carretera dentro de 3 años conlleva una descalificación de no menos de 1 año. Fuente: 49 CFR 383.51 Tabla 3; Manual de CDL de Míchigan."},"53":{"q":"¿Cuál es el período de descalificación para una PRIMERA condena por violar una orden de fuera de servicio de conductor o de vehículo mientras se opera un CMV (sin HazMat, sin pasajeros)?","options":["No menos de 30 días","No menos de 90 días pero no más de 1 año","No menos de 180 días pero no más de 1 año","No menos de 1 año pero no más de 5 años"],"explanation":"Una primera violación de una orden de fuera de servicio resulta en una descalificación de no menos de 180 días y no más de 1 año. Fuente: 49 CFR 383.51 Tabla 4; Manual de CDL de Míchigan."},"54":{"q":"¿Cuál es el rango de descalificación para una SEGUNDA violación de una orden de fuera de servicio en incidentes separados dentro de un período de 10 años?","options":["No menos de 180 días pero no más de 1 año","No menos de 1 año pero no más de 3 años","No menos de 2 años pero no más de 5 años","No menos de 3 años pero no más de 5 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 años resulta en una descalificación de no menos de 2 años y no más de 5 años. Fuente: 49 CFR 383.51 Tabla 4; Manual de CDL de Míchigan."},"55":{"q":"Un conductor viola una orden de fuera de servicio por PRIMERA vez mientras transporta materiales peligrosos con rótulos o mientras lleva 16 o más pasajeros. ¿Cuál es el rango de descalificación?","options":["No menos de 90 días pero no más de 1 año","No menos de 180 días pero no más de 2 años","No menos de 1 año pero no más de 3 años","No menos de 3 años pero no más de 5 años"],"explanation":"Una primera violación de una orden de fuera de servicio mientras se transporta HazMat con rótulos o se llevan 16 o más pasajeros resulta en una descalificación de no menos de 180 días y no más de 2 años. Fuente: 49 CFR 383.51 Tabla 4; Manual de CDL de Míchigan."},"56":{"q":"Según las reglas federales adoptadas en Míchigan, ¿cuál es la sanción civil máxima que puede enfrentar un conductor de CMV por usar un teléfono móvil de mano o enviar mensajes de texto mientras conduce?","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Un conductor puede ser multado con hasta $2,750 por una infracción de teléfono de mano o mensajes de texto; un empleador que lo permita o lo exija puede ser multado con hasta $11,000. Fuente: 49 CFR 392.80/392.82 y la hoja informativa de la regla de No Mensajes de Texto/Teléfono de Mano de la FMCSA; Manual de CDL de Míchigan."},"57":{"q":"A un conductor de CMV se le detecta o mide cualquier cantidad de alcohol mientras está de servicio, o que usó o poseyó alcohol dentro de las 4 horas previas a entrar en servicio. ¿Cuál es la consecuencia inmediata?","options":["Descalificación inmediata de la CDL por 1 año","Puesto fuera de servicio por 24 horas","Puesto fuera de servicio por 7 días","Descalificación inmediata de por vida"],"explanation":"Bajo la prohibición de alcohol, dicho conductor debe ser puesto fuera de servicio por 24 horas. Esto es independiente del umbral de infracción mayor de 0.04. Fuente: 49 CFR 392.5; Manual de CDL de Míchigan."},"58":{"q":"Un titular de CDL es condenado por una infracción de manejo relacionada con el alcohol mientras conducía su PROPIO vehículo personal (no comercial). ¿Cómo afecta esto a la CDL en Míchigan?","options":["No tiene ningún efecto porque no hubo un CMV involucrado","Resulta en una descalificación de la CDL de 1 año","Resulta solo en una descalificación de 60 días","Resulta solo en puntos, no en descalificación"],"explanation":"Las infracciones mayores, incluidas las relacionadas con el alcohol, desencadenan la descalificación de la CDL incluso cuando se cometen en un vehículo personal; una primera infracción de este tipo conlleva una descalificación de 1 año. Fuente: 49 CFR 383.51 Tabla 1; Manual de CDL de Míchigan."},"59":{"q":"Un conductor de CMV registra un BAC de 0.02 o mayor pero menor de 0.04. ¿Qué afirmación describe mejor la consecuencia según las reglas aplicadas en Míchigan?","options":["Se trata como una infracción mayor con una descalificación de 1 año","No hay consecuencia por debajo de 0.04","El conductor no puede realizar funciones sensibles para la seguridad durante 24 horas","Es una violación automática de una orden de fuera de servicio"],"explanation":"Una concentración de alcohol confirmada de 0.02 o mayor pero por debajo de 0.04 prohíbe al conductor realizar funciones sensibles para la seguridad durante 24 horas; una infracción mayor descalificante comienza en 0.04. Fuente: 49 CFR 382.505 y 383.51; Manual de CDL de Míchigan."},"60":{"q":"Según la ley 'Move Over' (cámbiate de carril) de Michigan, cuando te acercas a un vehículo de emergencia detenido con las luces activadas y no puedes cambiarte de carril de forma segura, ¿en cuánto debes reducir tu velocidad por debajo del límite de velocidad indicado?","options":["Al menos 10 mph por debajo del límite de velocidad indicado","Al menos 5 mph por debajo del límite de velocidad indicado","Al menos 15 mph por debajo del límite de velocidad indicado","Al menos 20 mph por debajo del límite de velocidad indicado"],"explanation":"La ley 'Move Over' de Michigan (MCL 257.653a) exige que el conductor que se acerca a un vehículo de emergencia autorizado y detenido con las luces activadas se cambie al menos un carril, o si eso no es posible, reduzca la velocidad a al menos 10 mph por debajo del límite de velocidad indicado y pase con la debida precaución. Fuente: MCL 257.653a; campaña 'Move Over' de la Policía Estatal de Michigan."},"61":{"q":"En una carretera de Michigan con dos o más carriles de circulación en una dirección, ¿por dónde puede circular un camión con un peso bruto de más de 10,000 libras, un tractocamión o una combinación?","options":["Solo en cualquiera de los dos carriles más a la derecha","En cualquier carril, igual que los automóviles de pasajeros","Solo en el único carril del extremo derecho en todo momento","Solo en el carril central para evitar el tráfico que se incorpora"],"explanation":"La ley de Michigan (MCL 257.634) exige que en una carretera con dos o más carriles en una dirección, un camión de más de 10,000 lbs, un tractocamión o una combinación de vehículo y remolque circule únicamente en uno de los dos carriles más a la derecha. Fuente: MCL 257.634."},"62":{"q":"En una autopista de acceso limitado de Michigan donde el límite de velocidad indicado es mayor de 65 mph, ¿cuál es la velocidad máxima para un camión con un peso bruto de 10,000 libras o más?","options":["65 mph","60 mph","70 mph","55 mph"],"explanation":"Según el MCL 257.627, donde el límite indicado supera las 65 mph, un camión de 10,000 lbs o más, un tractocamión o combinación, o un autobús escolar no puede exceder las 65 mph en una autopista de acceso limitado o carretera troncal estatal. Esto refleja el cambio realizado por la Ley Pública 445 de 2016. Fuente: MCL 257.627."},"63":{"q":"En Michigan, ¿a qué distancia del riel más cercano debe detenerse el conductor de un vehículo con materiales peligrosos rotulado antes de cruzar una vía férrea a nivel?","options":["A menos de 50 pies pero no menos de 15 pies","A menos de 100 pies pero no menos de 25 pies","A menos de 40 pies pero no menos de 10 pies","A menos de 75 pies pero no menos de 20 pies"],"explanation":"El MCL 257.669 exige que los conductores de vehículos rotulados (y los vehículos que transportan 16 o más pasajeros o pasajeros pagados) activen las luces de emergencia y se detengan a menos de 50 pies pero no menos de 15 pies del riel más cercano antes de cruzar. Fuente: MCL 257.669; Manual CDL de Michigan, Sección 9."},"64":{"q":"En Michigan, un vehículo que se encuentra o que adelanta a un autobús escolar detenido con dos luces rojas que destellan alternadamente debe detenerse por completo ¿a qué distancia mínima del autobús?","options":["No menos de 20 pies","No menos de 10 pies","No menos de 15 pies","No menos de 30 pies"],"explanation":"El MCL 257.682 exige que el conductor que adelanta o que se encuentra con un autobús escolar que muestra luces rojas destellantes se detenga a no menos de 20 pies del autobús y no avance hasta que el autobús se mueva o se apaguen las señales. Fuente: MCL 257.682."},"65":{"q":"En Michigan, en una carretera dividida en dos calzadas por un espacio elevado intermedio o una barrera física, ¿qué conductores NO están obligados a detenerse ante un autobús escolar que muestra luces rojas destellantes en el lado opuesto?","options":["Los conductores que se cruzan con el autobús desde la calzada opuesta al otro lado de la barrera","Todos los conductores en ambas direcciones deben detenerse de todas formas","Solo los conductores que van directamente detrás del autobús","Solo los conductores en el carril más cercano al autobús"],"explanation":"Según el MCL 257.682(2), donde una carretera está dividida en dos calzadas por un espacio elevado intermedio, una barrera física o una sección divisoria claramente indicada, el conductor que se cruza con el autobús al otro lado de esa división no está obligado a detenerse. Los conductores que circulan detrás del autobús en la misma calzada sí deben detenerse. Fuente: MCL 257.682(2)."},"66":{"q":"Cuando un conductor con CDL de Michigan detiene un vehículo comercial en el acotamiento de una carretera de un solo sentido o dividida, ¿dónde deben colocarse los tres triángulos reflectantes de advertencia?","options":["A 10, 100 y 200 pies en dirección al tráfico que se aproxima","A 10, 100 y 100 pies a ambos lados del vehículo","A 25, 100 y 250 pies en dirección al tráfico que se aproxima","A 50, 150 y 300 pies en dirección al tráfico que se aproxima"],"explanation":"En una carretera de un solo sentido o dividida, los dispositivos de advertencia se colocan a 10, 100 y 200 pies de la parte trasera del vehículo en dirección al tráfico que se aproxima. El Manual CDL de Michigan sigue la norma federal de la FMCSA (49 CFR 392.22). Fuente: Manual CDL de Michigan; 49 CFR 392.22."},"67":{"q":"En una carretera de Michigan de dos carriles y doble sentido, ¿cómo debe colocar los tres triángulos de advertencia un conductor de un vehículo comercial detenido?","options":["Uno a unos 10 pies por detrás, uno a unos 100 pies por detrás y uno a unos 100 pies por delante del vehículo","Los tres a unos 100 pies por detrás del vehículo en fila","Uno a 10, uno a 200 y uno a 500 pies por detrás del vehículo","Uno sobre el cofre y dos a unos 50 pies por detrás del vehículo"],"explanation":"En una carretera de dos carriles y doble sentido, coloque un triángulo a unos 10 pies hacia atrás en dirección al tráfico que se aproxima, uno a unos 100 pies hacia atrás y uno a unos 100 pies hacia el frente del vehículo. Fuente: Manual CDL de Michigan; 49 CFR 392.22."},"68":{"q":"Durante las restricciones estacionales de peso de la 'ley de heladas' (frost law) de primavera en Michigan, ¿cuál es la velocidad máxima para un vehículo comercial que transporta una carga de peso reducido en una ruta restringida, según lo establece el Código de Vehículos de Michigan?","options":["35 mph","45 mph","25 mph","55 mph"],"explanation":"El MCL 257.627 dispone que durante los períodos en que están vigentes los límites de carga reducidos (estacionales), los vehículos que operan bajo esas cargas reducidas están limitados a 35 mph. Esto forma parte del distintivo programa de 'ley de heladas' de Michigan. Fuente: MCL 257.627; restricciones estacionales de peso de MDOT."},"69":{"q":"Según las restricciones estacionales de peso de Michigan, ¿qué rutas están designadas como SIN reducción de los pesos legales por eje durante el deshielo de primavera?","options":["Las rutas 'de todas las estaciones' (all-season), mostradas en verde y dorado en el Mapa de Operadores de Camiones de MDOT","Todos los caminos de grava del condado","Solo las autopistas interestatales dentro de los límites de la ciudad","Las rutas mostradas en rojo sólido o punteado en el Mapa de Operadores de Camiones de MDOT"],"explanation":"MDOT designa rutas 'de todas las estaciones' (verde y dorado en el Mapa de Operadores de Camiones de MDOT) que mantienen todo el peso legal por eje durante todo el año, mientras que las rutas 'estacionales' (rojo sólido o punteado) están sujetas a reducciones del peso por eje en primavera. Fuente: Mapa de Operadores de Camiones de MDOT / guía de restricciones estacionales de peso."},"70":{"q":"Durante las restricciones de peso de primavera en Michigan en una ruta 'estacional', ¿qué reducción del peso por eje se aplica al pavimento flexible (asfalto)?","options":["35 por ciento","25 por ciento","10 por ciento","50 por ciento"],"explanation":"En las rutas estacionales durante las restricciones de primavera, MDOT impone una reducción del 35 por ciento del peso por eje en el pavimento flexible (asfalto) y del 25 por ciento en el pavimento rígido (concreto). Fuente: guía de restricciones estacionales de peso de MDOT."},"71":{"q":"Un conductor con CDL de Michigan se acerca a un cruce ferroviario marcado con un letrero que dice 'EXEMPT' (exento) mientras transporta una carga rotulada. ¿Qué exige la ley de Michigan?","options":["No se requiere detenerse en un cruce marcado como 'exento'","El conductor debe detenerse de todos modos a menos de 50 pies del riel más cercano","El conductor debe detenerse y colocar los triángulos de advertencia","El conductor debe detenerse solo si no dispone de luces de emergencia"],"explanation":"Según el MCL 257.669, no se requiere detenerse en un cruce ferroviario a nivel marcado con un letrero que dice 'exento' (exempt), incluso para vehículos rotulados. En todos los demás cruces, el vehículo rotulado debe detenerse de 15 a 50 pies del riel más cercano. Fuente: MCL 257.669."},"72":{"q":"¿Cuál es el ancho legal máximo de un vehículo comercial o su carga en Michigan sin un permiso de sobredimensión?","options":["96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)","108 pulgadas (9 pies)","120 pulgadas (10 pies)"],"explanation":"El MCL 257.717 establece el ancho legal máximo de Michigan en 96 pulgadas (8 pies); cualquier cosa más ancha requiere un permiso de sobredimensión. Tenga en cuenta que esto es más estrecho que el estándar de 102 pulgadas usado por muchos otros estados. Fuente: MCL 257.717; Cargas y Dimensiones Legales Máximas de Camiones de MDOT."},"73":{"q":"¿Cuál es la altura legal máxima de un vehículo comercial, cargado o descargado, en Michigan sin un permiso?","options":["13 pies 6 pulgadas","14 pies 0 pulgadas","13 pies 0 pulgadas","12 pies 6 pulgadas"],"explanation":"El MCL 257.719 establece la altura legal máxima del vehículo en Michigan, cargado o descargado, en 13 pies 6 pulgadas. Fuente: MCL 257.719; Cargas y Dimensiones Legales Máximas de Camiones de MDOT."},"74":{"q":"En una autopista de Michigan con tres o más carriles de circulación en la misma dirección, ¿qué dice la ley de uso de carriles (MCL 257.634) sobre qué carril debe usar un vehículo?","options":["A un vehículo no se le prohíbe circular en ningún carril de una autopista que tenga tres o más carriles en la misma dirección","Todos los vehículos deben permanecer en el carril del extremo derecho a menos que estén rebasando","Los camiones deben usar solo el carril central","Todos los vehículos deben usar solo los dos carriles izquierdos"],"explanation":"El MCL 257.634 dispone que el requisito de mantenerse a la derecha no prohíbe que un vehículo circule en ningún carril de una autopista que tenga tres o más carriles en la misma dirección. Sin embargo, los camiones pesados siguen estando limitados a los dos carriles más a la derecha. Fuente: MCL 257.634."},"75":{"q":"En Michigan, antes de cruzar una vía férrea a nivel, el conductor de un autobús escolar debe hacer cuál de las siguientes acciones además de detenerse de 15 a 50 pies del riel más cercano?","options":["Activar las luces de emergencia, abrir la puerta de pasajeros y la ventanilla del conductor, y escuchar y mirar hacia ambos lados","Tocar el claxon tres veces antes de avanzar","Colocar triángulos reflectantes a 100 pies por detrás del autobús","Poner una marcha baja y cruzar mientras acelera"],"explanation":"El MCL 257.1857 exige que el conductor de un autobús escolar se detenga de 15 a 50 pies del riel más cercano, active las luces de advertencia de emergencia, apague las fuentes de ruido, abra la puerta de pasajeros y la ventanilla del lado del conductor, y mire y escuche hacia ambos lados antes de avanzar sin cambiar de marcha sobre las vías. Fuente: MCL 257.1857."},"76":{"q":"Un conductor con CDL está en una carretera de condado de dos carriles en Michigan sin letreros de límite de velocidad. ¿Cuál es el límite de velocidad general por ley que se aplica?","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"El MCL 257.627 establece un límite de velocidad general de 55 mph en las carreteras troncales y de condado donde no haya otro límite indicado (y un límite general de 55 mph correspondiente para caminos de grava). Un camión pesado no excedería esto. Fuente: MCL 257.627."},"77":{"q":"¿Qué afirmación sobre las carreteras de peaje es correcta para los conductores comerciales que operan en Michigan?","options":["Michigan no tiene autopistas de peaje; los peajes se aplican solo en ciertos cruces de puentes y túneles como los puentes Mackinac, Blue Water e International","Todas las autopistas interestatales de Michigan son de peaje y requieren un transpondedor","Los camiones pagan peaje en la I-94 y la I-75 pero los autos no","Michigan cobra peaje en todas las carreteras troncales estatales durante el invierno"],"explanation":"Las autopistas interestatales y estatales de Michigan son libres de peaje; los peajes se cobran solo en cruces fronterizos y de estrechos específicos como el Puente Mackinac, el Puente Blue Water y el International Bridge en Sault Ste. Marie. Fuente: información de peajes de puentes de MDOT."},"78":{"q":"Con respecto a las inspecciones periódicas de rutina de vehículos, ¿qué es cierto para los vehículos comerciales registrados en Michigan?","options":["Michigan no exige una inspección estatal periódica de seguridad o de emisiones, aunque los vehículos comerciales aún deben cumplir con los requisitos federales de inspección de vehículos comerciales","Michigan exige una prueba anual de emisiones para todos los vehículos comerciales","Michigan exige una inspección de seguridad bienal en una estación operada por el estado","Michigan exige una prueba de gases antes de cada renovación de CDL"],"explanation":"Michigan no exige una inspección estatal periódica de seguridad o de emisiones para los vehículos. Sin embargo, los vehículos comerciales siguen estando sujetos a los requisitos federales de inspección y mantenimiento de la FMCSA a pesar de la ausencia de un programa estatal. Fuente: Michigan SOS / MDOT; 49 CFR Parte 396."},"79":{"q":"Según la ley 'Move Over' de Michigan, cuando las condiciones del tráfico te permiten cambiar de carril ante un vehículo de emergencia autorizado y detenido, ¿cuánto debes alejarte?","options":["Al menos un carril de circulación o dos anchos de vehículo de distancia del vehículo detenido","Completamente fuera de la calzada hacia el acotamiento más lejano","Al menos tres anchos de vehículo de distancia del vehículo detenido","Al carril más a la izquierda sin importar la posición"],"explanation":"El MCL 257.653a exige que los conductores, cuando sea posible, se cambien a un carril que esté al menos un carril de circulación o dos anchos de vehículo de distancia del vehículo de emergencia autorizado y detenido, a la vez que reducen la velocidad a al menos 10 mph por debajo del límite indicado. Fuente: MCL 257.653a."},"80":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Michigan?","options":["La División de Vehículos Comerciales de la Policía Estatal de Michigan","El Departamento de Transporte de Michigan (MDOT)","El Departamento de Estado de Michigan (Secretary of State)","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"En Michigan, las CDL son emitidas por el Departamento de Estado de Michigan, encabezado por el Secretary of State; los exámenes de conocimientos y las solicitudes de CDL se gestionan en las oficinas del SOS. Fuente: Manual CDL de Michigan (SOS) y páginas de CDL del SOS en michigan.gov."},"81":{"q":"¿Dónde se administran en Michigan los exámenes de manejo en carretera y de control básico del vehículo para la CDL?","options":["En cualquier sucursal del Secretary of State por personal del SOS","En centros de pruebas regionales de la FMCSA","Por los oficiales de autotransportes de la Policía Estatal de Michigan","Por empresas de pruebas de conducción de terceros aprobadas por el MDOS"],"explanation":"Michigan no aplica los exámenes de habilidades de CDL en las sucursales del SOS; el examen de habilidades de tres partes lo administran empresas de pruebas de conducción de terceros aprobadas por el Departamento de Estado de Michigan (MDOS). Fuente: Manual CDL de Michigan (SOS)."},"82":{"q":"¿De cuántas partes consta el examen de habilidades de la CDL de Michigan?","options":["Dos: un examen escrito y un examen de manejo en carretera","Tres: inspección previaje, control básico del vehículo y manejo en carretera","Dos: habilidades de control básico y una verificación de materiales peligrosos","Cuatro: previaje, retroceso, manejo en carretera y un examen escrito de seguridad"],"explanation":"El examen de habilidades de la CDL de Michigan tiene tres partes: el examen de inspección del vehículo (previaje), el examen de habilidades de control básico del vehículo y el examen de manejo en carretera, todos los cuales deben aprobarse. Fuente: Manual CDL de Michigan (SOS)."},"83":{"q":"Antes de que un solicitante de CDL por primera vez pueda presentar el examen de habilidades en Michigan, ¿qué capacitación federal debe completar?","options":["Un aprendizaje patrocinado por el empleador de al menos seis meses","Un curso de seguridad de materiales peligrosos de 40 horas","Capacitación de Conductor de Nivel Inicial (ELDT) de un proveedor registrado","Un curso de manejo defensivo aprobado por el MDOT"],"explanation":"Desde el 7 de febrero de 2022, la regla de Capacitación de Conductor de Nivel Inicial (ELDT) de la FMCSA exige que los solicitantes de CDL por primera vez (y ciertas mejoras/avales) completen la ELDT de un proveedor que figure en el Registro de Proveedores de Capacitación de la FMCSA antes del examen de habilidades. Fuente: Manual CDL de Michigan (SOS); regla ELDT de la FMCSA."},"84":{"q":"Después de recibir un CLP, ¿cuánto tiempo debe esperar un solicitante de Michigan antes de presentar el examen de habilidades de la CDL?","options":["Al menos 7 días","Al menos 60 días","Al menos 14 días","Al menos 30 días"],"explanation":"Las reglas federales y de Michigan exigen que el CLP se mantenga durante al menos 14 días antes de que el solicitante pueda presentar el examen de habilidades de la CDL. Fuente: Manual CDL de Michigan (SOS); 49 CFR 383.25."},"85":{"q":"Al autocertificar su tipo de manejo para una CDL de Michigan, ¿entre cuántas categorías federales debe elegir un solicitante?","options":["Dos","Cinco","Tres","Cuatro"],"explanation":"Cada solicitante de CDL de Michigan debe autocertificarse en una de cuatro categorías: interestatal no exento, interestatal exento, intraestatal no exento o intraestatal exento. Fuente: Formulario de Autocertificación de CDL de Michigan (SOS); 49 CFR 383.71."},"86":{"q":"¿Qué categoría de autocertificación exige que un conductor de Michigan mantenga un certificado de examinador médico federal del DOT?","options":["Ninguna de las categorías exige un certificado médico","Interestatal no exento","Intraestatal exento","Interestatal exento"],"explanation":"Un conductor que se autocertifica como 'interestatal no exento' opera en el comercio interestatal y debe mantener un certificado de examinador médico del DOT válido; las categorías 'exentas' no lo exigen por la misma razón. Fuente: Formulario de Autocertificación de CDL de Michigan (SOS); 49 CFR 383.71/391."},"87":{"q":"¿Qué quiere decir un conductor de Michigan cuando se autocertifica como 'intraestatal exento'?","options":["Conduce a través de las fronteras estatales pero está exento de todas las reglas federales","Conduce solo dentro de Michigan pero debe tener una tarjeta médica federal","Conduce solo dentro de Michigan en operaciones que el estado ha exentado de los requisitos de certificación médica","Conduce de forma interestatal y debe mantener su tarjeta médica archivada en el SOS"],"explanation":"'Intraestatal exento' significa que el conductor opera un vehículo comercial solo dentro de Michigan en actividades que el estado ha determinado que están exentas del requisito de certificación médica, por lo que no se requiere una tarjeta médica federal. Fuente: Formulario de Autocertificación de CDL de Michigan (SOS); 49 CFR 383.71."},"88":{"q":"¿Cuál es la edad mínima para que se emita una CDL para conducir un vehículo comercial únicamente dentro de Michigan (intraestatal)?","options":["21 años","19 años","18 años","16 años"],"explanation":"Un solicitante debe tener al menos 18 años para tener una CDL para la conducción comercial intraestatal (solo dentro de Michigan); la operación interestatal generalmente requiere tener 21 años. Fuente: Manual CDL de Michigan (SOS); MCL 257.312e."},"89":{"q":"En los exámenes de conocimientos de la CDL de Michigan, ¿qué examen debe aprobar todo solicitante de CDL independientemente de la clase de vehículo?","options":["El examen de conocimientos generales","El examen de transporte de pasajeros","El examen de materiales peligrosos","El examen de dobles/triples"],"explanation":"Todos los solicitantes de CDL deben aprobar el examen de conocimientos generales; los exámenes de conocimientos adicionales (por ejemplo, frenos de aire, combinación, avales) dependen de la clase y los avales solicitados. Fuente: Manual CDL de Michigan (SOS); 49 CFR 383.23."},"90":{"q":"En una renovación de CDL de Michigan en una oficina del Secretary of State, ¿cuál de estas acciones forma parte del proceso estándar?","options":["Un examen escrito obligatorio de materiales peligrosos para todas las renovaciones","Un examen de la vista y una revisión del historial de manejo estatal y nacional del solicitante","Un nuevo examen físico del DOT automático realizado por personal del SOS","Volver a presentar el examen completo de habilidades de tres partes en cada ciclo"],"explanation":"En la renovación, la oficina del SOS realiza un examen de la vista y verifica los historiales de manejo estatal y nacional (CDLIS) del solicitante; normalmente no se requiere volver a presentar el examen completo de habilidades. Nota: las tarifas exactas pueden cambiar. Fuente: Manual CDL de Michigan (SOS); página de renovación de CDL del SOS en michigan.gov."}},"hi":{"0":{"q":"मिशिगन के निर्दिष्ट राजमार्गों पर, ओवरसाइज़ परमिट की आवश्यकता होने से पहले किसी वाणिज्यिक वाहन की अधिकतम कानूनी चौड़ाई (दर्पणों और कुछ सुरक्षा उपकरणों को छोड़कर) कितनी होती है?","options":["108 inches (9 feet)","96 inches (8 feet)","120 inches (10 feet)","102 inches (8 feet 6 inches)"],"explanation":"मिशिगन निर्दिष्ट राजमार्गों पर वाहन की चौड़ाई को 102 inches (8'6\") तक और अन्य सड़कों पर 96 inches (8') तक सीमित करता है, जो संघीय राष्ट्रीय-नेटवर्क मानक के अनुरूप है। स्रोत: Michigan Vehicle Code MCL 257.717; MDOT 'Maximum Legal Truck Loadings and Dimensions' (T-1)।"},"1":{"q":"विशेष परिवहन परमिट के बिना मिशिगन राजमार्गों पर किसी वाहन और उसके भार की अधिकतम कानूनी ऊँचाई कितनी होती है?","options":["14 feet 0 inches","13 feet 6 inches","14 feet 6 inches","13 feet 0 inches"],"explanation":"मिशिगन वाहन-और-भार की अधिकतम ऊँचाई 13 feet 6 inches निर्धारित करता है; इससे ऊँची किसी भी चीज़ के लिए ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: MCL 257.718; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)।"},"2":{"q":"मिशिगन के निर्दिष्ट राजमार्गों पर परमिट के बिना चलाए जाने वाले सेमीट्रेलर (भार सहित) की अधिकतम लंबाई कितनी होती है?","options":["60 feet","48 feet","53 feet","57 feet"],"explanation":"मिशिगन निर्दिष्ट राजमार्गों पर भार सहित 53 feet तक के सेमीट्रेलर की अनुमति देता है (गैर-निर्दिष्ट सड़कों पर 50 feet)। स्रोत: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)।"},"3":{"q":"इंटरस्टेट प्रणाली पर मिशिगन द्वारा लागू किए जाने वाले संघीय सीमाओं के तहत, परमिट के बिना एक मानक 5-धुरी संयोजन के लिए अधिकतम सकल वाहन भार कितना होता है?","options":["88,000 pounds","76,000 pounds","73,280 pounds","80,000 pounds"],"explanation":"इंटरस्टेट प्रणाली पर मिशिगन संघीय ब्रिज फॉर्मूला के अधीन वाहनों के लिए 80,000 pounds सकल की संघीय सीमा लागू करता है। स्रोत: 23 CFR 658.17 जैसा मिशिगन में लागू है; MDOT ट्रक भार मार्गदर्शन।"},"4":{"q":"मिशिगन के इंटरस्टेट राजमार्गों पर 80,000-pound संघीय मानक के तहत चलने वाले वाहनों पर लागू होने वाली संघीय एकल-धुरी भार सीमा कितनी है?","options":["24,000 pounds","22,400 pounds","18,000 pounds","20,000 pounds"],"explanation":"संघीय 80,000-pound मानक द्वारा शासित वाहनों के लिए, एकल-धुरी सीमा 20,000 pounds है, वही आँकड़ा जो मिशिगन इंटरस्टेट पर लागू करता है। स्रोत: 23 CFR 658.17 जैसा मिशिगन में लागू है; MDOT भार मार्गदर्शन।"},"5":{"q":"मिशिगन की इंटरस्टेट प्रणाली पर लागू संघीय मानक के तहत, एक टैंडम धुरी समूह पर अनुमत अधिकतम भार कितना होता है?","options":["36,000 pounds","40,000 pounds","32,000 pounds","34,000 pounds"],"explanation":"इंटरस्टेट पर मिशिगन जो संघीय टैंडम-धुरी सीमा लागू करता है वह 34,000 pounds है। ध्यान दें कि मिशिगन के अपने राज्य-कानून धुरी नियम भिन्न हैं (इसकी 18,000-lb सामान्य धुरी अधिकतम देखें)। स्रोत: 23 CFR 658.17; MDOT भार मार्गदर्शन।"},"6":{"q":"संघीय सीमाओं से पहले के धुरी-भार नियमों के कारण, एक उचित रूप से कॉन्फ़िगर किया गया ट्रक मिशिगन की सड़कों पर इंटरस्टेट से बाहर कानूनी रूप से अधिकतम कितना सकल वाहन भार ले जा सकता है?","options":["80,000 pounds","164,000 pounds","105,500 pounds","129,000 pounds"],"explanation":"मिशिगन का ग्रैंडफ़ादर किया गया भार कानून लगभग 164,000 pounds का अधिकतम सकल भार अनुमत करता है जब धुरी भार और दूरी अनुपालन करते हैं, जो उत्तरी अमेरिका में नियमित रूप से अनुमत सर्वाधिक है। स्रोत: MCL 257.722; Michigan House Fiscal Agency, 'Michigan's Truck-Weight Law।'"},"7":{"q":"राज्य के भारी-भार प्रावधानों के तहत चलने वाले मिशिगन ट्रक-ट्रेलर संयोजन पर अनुमत धुरियों की अधिकतम संख्या कितनी होती है?","options":["8 axles","11 axles","9 axles","13 axles"],"explanation":"1967 से मिशिगन ने इन संयोजनों को 11 axles तक सीमित किया है, जो प्रति-धुरी सीमाओं के साथ मिलकर लगभग 164,000-pound की अधिकतम सीमा देता है। स्रोत: MCL 257.722; Michigan House Fiscal Agency ट्रक-भार विश्लेषण।"},"8":{"q":"मिशिगन के अपने धुरी-भार कानून के तहत, आसन्न धुरियों से 9 feet या उससे अधिक की दूरी पर रखी गई एकल धुरी के लिए 'सामान्य लोडिंग अधिकतम' कितना होता है?","options":["16,000 pounds","18,000 pounds","20,000 pounds","22,400 pounds"],"explanation":"मिशिगन कानून सामान्य अधिकतम एकल-धुरी भार 18,000 pounds निर्धारित करता है जहाँ धुरी की दूरी 9 feet या उससे अधिक होती है, जो 20,000-lb के संघीय आँकड़े से कम है। स्रोत: MCL 257.722(1)।"},"9":{"q":"मिशिगन का राज्य धुरी कानून अधिकतम पहिया भार को टायर की चौड़ाई से जुड़े एक मान तक सीमित करता है। वह सीमा क्या है?","options":["500 pounds per inch of tire width","700 pounds per inch of tire width","600 pounds per inch of tire width","850 pounds per inch of tire width"],"explanation":"मिशिगन पहिया भार को 700 pounds per inch of tire width तक सीमित करता है, एक मानक जो भारी भार को अधिक टायरों और धुरियों पर वितरित करता है। स्रोत: MCL 257.722(7)।"},"10":{"q":"मिशिगन के वसंत पिघलाव (फ्रॉस्ट लॉ) अवधि के दौरान, कंक्रीट के फुटपाथों पर अधिकतम धुरी भार को कितने प्रतिशत तक कम किया जाता है?","options":["25 percent","35 percent","10 percent","50 percent"],"explanation":"मार्च, अप्रैल और मई के दौरान, मिशिगन पिघल रहे सड़क-आधारों की रक्षा के लिए कंक्रीट के फुटपाथों पर अधिकतम धुरी भार को 25 percent तक (और अन्य सड़कों पर 35 percent तक) कम करता है। स्रोत: MCL 257.722(8)।"},"11":{"q":"मिशिगन के मौसमी फ्रॉस्ट-लॉ प्रतिबंधों के दौरान, कंक्रीट फुटपाथ के अलावा अन्य सड़कों पर धुरी भार को कितने प्रतिशत तक कम किया जाता है?","options":["15 percent","45 percent","35 percent","25 percent"],"explanation":"गैर-कंक्रीट सड़कों पर, मिशिगन के वसंत भार प्रतिबंध मार्च-मई के पिघलाव काल के दौरान अधिकतम धुरी भार को 35 percent तक कम करते हैं। स्रोत: MCL 257.722(8)।"},"12":{"q":"मिशिगन की मौसमी भार कटौती (फ्रॉस्ट लॉ) आमतौर पर किन महीनों में लागू होती है?","options":["March, April, and May","January, February, and March","November, December, and January","April, May, and June"],"explanation":"मिशिगन की मौसमी धुरी-भार कटौती वसंत पिघलाव के दौरान लागू होती है, जो वैधानिक रूप से March, April, and May से जुड़ी है, और सटीक प्रारंभ/समाप्ति तिथियाँ MDOT द्वारा हर साल घोषित की जाती हैं। स्रोत: MCL 257.722(8); MDOT मौसमी भार प्रतिबंध सूचनाएँ।"},"13":{"q":"मिशिगन कानून किसी वाहन संयोजन के भार को अतिरिक्त चेतावनी की आवश्यकता होने से पहले वाहन के पिछले हिस्से से कितनी दूर तक बढ़ने की अनुमति देता है?","options":["2 feet","3 feet","4 feet","6 feet"],"explanation":"भार पीछे की ओर 4 feet तक (और सामने की ओर 3 feet तक) फैल सकता है; 4 feet या उससे अधिक के पिछले ओवरहैंग के लिए दिन में लाल झंडा और रात में लाल बत्ती की आवश्यकता होती है। स्रोत: MCL 257.719; MDOT लोडिंग आयाम मार्गदर्शन।"},"14":{"q":"मिशिगन वाणिज्यिक वाहन के पिछले हिस्से से आगे बढ़ने वाले भार को ओवरहैंग कितनी लंबाई तक पहुँचने पर रात में लाल बत्ती या लालटेन प्रदर्शित करनी होती है?","options":["8 feet","2 feet","4 feet","6 feet"],"explanation":"मिशिगन किसी भी भार के लिए जो वाहन के पिछले हिस्से से 4 feet या उससे अधिक फैलता है, दिन के उजाले में लाल झंडा और रात में लाल बत्ती या लालटेन की आवश्यकता रखता है। स्रोत: MCL 257.719; MDOT लोडिंग आयाम मार्गदर्शन।"},"15":{"q":"मिशिगन राज्य ट्रंकलाइन राजमार्गों पर यात्रा के लिए ओवरसाइज़/ओवरवेट परिवहन परमिट कौन जारी करता है?","options":["The Federal Motor Carrier Safety Administration","The Michigan State Police only","The Michigan Department of Transportation (MDOT)","The Michigan Secretary of State"],"explanation":"MDOT राज्य ट्रंकलाइनों पर अतिरिक्त आकार या भार के लिए परमिट जारी करता है, जबकि स्थानीय सड़क एजेंसियाँ अपने क्षेत्राधिकार के अंतर्गत सड़कों को संभालती हैं। स्रोत: MCL 257.725; MDOT Oversize/Overweight Permits।"},"16":{"q":"मिशिगन में एक कैरियर किस ऑनलाइन प्रणाली के माध्यम से MDOT ओवरसाइज़/ओवरवेट परमिट के लिए आवेदन करता है?","options":["CDLIS (Commercial Driver License Information System)","IRP (International Registration Plan portal)","SAFER (Safety and Fitness Electronic Records)","MiTRIP (Michigan Transport Routing and Internet Permitting)"],"explanation":"मिशिगन कैरियर परिवहन परमिट इलेक्ट्रॉनिक रूप से MiTRIP, MDOT की ऑनलाइन रूटिंग और परमिटिंग प्रणाली के माध्यम से प्राप्त करते हैं। स्रोत: MDOT Oversize/Overweight Permits; MCL 257.725।"},"17":{"q":"मिशिगन में एक सिंगल-ट्रिप ओवरसाइज़ परमिट आम तौर पर ऐसे भार की कभी-कभार आवाजाही के लिए जारी किया जाता है जो:","options":["पूरी तरह से निजी संपत्ति पर ले जाया जा रहा है","कानूनी सीमाओं के भीतर आने के लिए जिसे तोड़ा या पुनर्व्यवस्थित नहीं किया जा सकता","कैरियर बस इसे छोटे भारों में तोड़ना पसंद नहीं करता","कानूनी सीमाओं से एक प्रतिशत से कम अधिक होता है"],"explanation":"मिशिगन परमिट केवल ऐसे ओवरसाइज़ या ओवरवेट भारों की कभी-कभार आवाजाही के लिए जारी किए जाते हैं जिन्हें कानूनी सीमाओं को पूरा करने के लिए उचित रूप से तोड़ा, घटाया, या पुनर्व्यवस्थित नहीं किया जा सकता। स्रोत: MCL 257.725; MDOT परमिट नीति।"},"18":{"q":"मिशिगन के प्राकृतिक गैस वाहन प्रावधान के तहत, प्राकृतिक गैस से चलने वाला वाहन भारी ईंधन प्रणाली की भरपाई के लिए लागू भार सीमाओं को कितना अधिक कर सकता है?","options":["5,000 pounds","2,000 pounds","550 pounds","10,000 pounds"],"explanation":"मिशिगन ईंधन प्रणाली के अतिरिक्त भार की भरपाई के लिए प्राकृतिक गैस वाहनों को अन्यथा लागू भार सीमाओं से 2,000 pounds तक की छूट देता है। स्रोत: Michigan Vehicle Code; संघीय 23 U.S.C. 127 NGV छूट के अनुरूप MDOT भार मार्गदर्शन।"},"19":{"q":"मिशिगन संयोजन के लिए जैसे कि एक ट्रक-ट्रैक्टर दो टोवड यूनिट खींच रहा हो, परमिट की आवश्यकता होने से पहले अधिकतम कुल लंबाई (पहली टोवड यूनिट के सामने से अंतिम के पीछे तक मापी गई) कितनी होती है?","options":["75 feet","58 feet","65 feet","53 feet"],"explanation":"मिशिगन इन डबल संयोजनों को बिना किसी निश्चित कुल वाहन लंबाई के अनुमति देता है जब तक कि टोवड यूनिट, पहली के सामने से अंतिम के पीछे तक मापी जाएँ, 58 feet से अधिक न हों (प्रत्येक यूनिट 28'6\" से अधिक नहीं)। स्रोत: MCL 257.719; MDOT Maximum Legal Truck Loadings and Dimensions (T-1)।"},"20":{"q":"मिशिगन में, 26,001 pounds या उससे अधिक के सकल संयोजन भार रेटिंग (GCWR) वाले वाहनों के किसी भी संयोजन को चलाने के लिए कौन सा CDL समूह आवश्यक है, जहाँ टोवड यूनिट का GVWR 10,000 pounds से अधिक हो?","options":["Group A","Group B","Group C","Group D"],"explanation":"मिशिगन एक Group (Class) A CDL को 26,001 lbs या उससे अधिक GCWR वाले वाहनों के किसी भी संयोजन के रूप में परिभाषित करता है, बशर्ते टोवड यूनिट(यों) का GVWR 10,000 lbs से अधिक हो। स्रोत: Michigan CDL Manual (Michigan SOS), Section 1।"},"21":{"q":"मिशिगन नियमों के तहत, कौन सा CDL समूह 26,001 pounds या उससे अधिक के सकल वाहन भार रेटिंग (GVWR) वाले एकल वाहन (जो 10,000 pounds या उससे कम की यूनिट खींच सकता है) को कवर करता है?","options":["Group A","Group B","Group C","Group H"],"explanation":"मिशिगन में एक Group (Class) B CDL 26,001 lbs या उससे अधिक GVWR वाले किसी भी एकल वाहन के लिए है, या ऐसे वाहन के लिए जो 10,000 lbs GVWR से अधिक न होने वाली यूनिट खींच रहा हो। स्रोत: Michigan CDL Manual (Michigan SOS), Section 1।"},"22":{"q":"एक मिशिगन Group (Class) C CDL एक छोटे वाहन (Class A/B भार सीमाओं से कम) के लिए केवल तभी आवश्यक होता है जब इसका उपयोग निम्नलिखित में से किसके परिवहन के लिए किया जाता है?","options":["5,000 pounds से अधिक वजन का कोई भी माल","16 या अधिक यात्री (चालक सहित), या प्लेकार्ड वाली मात्रा में खतरनाक सामग्री","किसी भी वजन का कोई भी ट्रेलर","केवल स्कूली बच्चे"],"explanation":"एक मिशिगन Group C CDL उन वाहनों पर लागू होता है जो Class A/B भार सीमाओं से कम हैं और जिन्हें चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है, या जो प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक सामग्री ले जाते हैं। स्रोत: Michigan CDL Manual (Michigan SOS), Section 1।"},"23":{"q":"इंट्रास्टेट ड्राइविंग (केवल मिशिगन के भीतर संचालन) के लिए मिशिगन CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"मिशिगन केवल इंट्रास्टेट (राज्य-के-भीतर) वाणिज्य के लिए 18 वर्ष की आयु में CDL की अनुमति देता है; इंटरस्टेट संचालन के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Michigan CDL Manual (Michigan SOS) / Michigan SOS CDL पात्रता।"},"24":{"q":"इंटरस्टेट ड्राइविंग (राज्य की सीमाओं के पार) की अनुमति देने वाला मिशिगन CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"संघीय और मिशिगन नियमों के अनुसार इंटरस्टेट वाणिज्य में CMV संचालित करने के लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है; 18-20 वर्ष की आयु के चालक इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: Michigan CDL Manual (Michigan SOS); 49 CFR 391.11।"},"25":{"q":"मिशिगन में, CDL ऑन-रोड कौशल परीक्षा देने की अनुमति मिलने से पहले एक आवेदक को कितने समय तक Commercial Learner's Permit (CLP) रखना आवश्यक है?","options":["न्यूनतम 7 दिन","न्यूनतम 14 दिन","न्यूनतम 30 दिन","न्यूनतम 60 दिन"],"explanation":"मिशिगन संघीय नियम का पालन करता है जिसके अनुसार आवेदक द्वारा CDL कौशल परीक्षा देने से पहले CLP को न्यूनतम 14 दिन रखा जाना आवश्यक है। स्रोत: Michigan SOS (cdl-apply); 49 CFR 383.25।"},"26":{"q":"चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए मिशिगन CDL पर कौन सा एंडोर्समेंट आवश्यक है?","options":["P (Passenger)","N (Tank)","T (Doubles/Triples)","H (Hazardous Materials)"],"explanation":"मिशिगन में चालक सहित 16 या अधिक व्यक्तियों के परिवहन के लिए डिज़ाइन किए गए वाहन को चलाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है। स्रोत: Michigan CDL Manual (Michigan SOS), एंडोर्समेंट अनुभाग।"},"27":{"q":"पूर्व-प्राथमिक, प्राथमिक, या माध्यमिक स्कूल के छात्रों को स्कूल आने-जाने के लिए ले जाने वाले वाणिज्यिक वाहन को चलाने के लिए कौन सा मिशिगन CDL एंडोर्समेंट आवश्यक है?","options":["P (Passenger)","S (School Bus)","T (Doubles/Triples)","C (Children)"],"explanation":"मिशिगन में छात्रों को ले जाने वाली स्कूल बस चलाने के लिए S (School Bus) एंडोर्समेंट आवश्यक है; आवेदकों के पास पहले से P एंडोर्समेंट होना चाहिए (या प्राप्त करना चाहिए) और स्कूल बस ज्ञान और कौशल परीक्षाएँ उत्तीर्ण करनी चाहिए। स्रोत: Michigan CDL Manual (Michigan SOS)।"},"28":{"q":"मिशिगन CDL पर, जब किसी चालक को Tank (N) और Hazardous Materials (H) दोनों एंडोर्समेंट जारी किए गए हों तो कौन सा एकल कोड अक्षर दिखाई देता है?","options":["X","Z","HN","K"],"explanation":"मिशिगन जब कोई चालक टैंक और खतरनाक सामग्री दोनों एंडोर्समेंट रखता है तो अलग-अलग N और H कोड के बजाय लाइसेंस पर संयुक्त कोड X लगाता है। स्रोत: Michigan CDL Manual (Michigan SOS), एंडोर्समेंट अनुभाग।"},"29":{"q":"मिशिगन T एंडोर्समेंट डबल और ट्रिपल ट्रेलर संयोजनों को कवर करता है। हालाँकि, मिशिगन की सड़कों पर ट्रिपल ट्रेलरों के संबंध में, कौन सा कथन सत्य है?","options":["मिशिगन में ट्रिपल ट्रेलर संयोजनों की अनुमति नहीं है","मिशिगन में ट्रिपल ट्रेलरों की अनुमति केवल इंटरस्टेट राजमार्गों पर है","मिशिगन में ट्रिपल ट्रेलरों के लिए एक अलग Class A-T परमिट की आवश्यकता होती है","मिशिगन में ट्रिपल ट्रेलरों की पूरे राज्य में बिना किसी प्रतिबंध के अनुमति है"],"explanation":"हालाँकि T (Doubles/Triples) एंडोर्समेंट मौजूद है, मिशिगन की सड़कों पर ट्रिपल ट्रेलर संयोजनों की अनुमति नहीं है। स्रोत: Michigan CDL Manual (Michigan SOS), एंडोर्समेंट अनुभाग।"},"30":{"q":"किस एंडोर्समेंट के लिए एक मिशिगन CDL आवेदक को फिंगरप्रिंटिंग और पृष्ठभूमि जाँच सहित Transportation Security Administration (TSA) Security Threat Assessment उत्तीर्ण करना आवश्यक है?","options":["N (Tank)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"explanation":"H (Hazardous Materials) एंडोर्समेंट के लिए HazMat ज्ञान परीक्षा के अतिरिक्त फिंगरप्रिंट और पृष्ठभूमि जाँच के साथ एक TSA Security Threat Assessment आवश्यक है। स्रोत: Michigan SOS CDL जानकारी; TSA HME / 49 CFR 1572।"},"31":{"q":"मिशिगन/संघीय परिभाषाओं के तहत, N (Tank) एंडोर्समेंट आम तौर पर 119 gallons से अधिक की व्यक्तिगत रेटेड क्षमता वाले टैंक में तरल या गैस ले जाने के लिए और कम से कम कितने gallons की कुल रेटेड क्षमता के लिए आवश्यक होता है?","options":["500 gallons","1,000 gallons","1,500 gallons","3,000 gallons"],"explanation":"Tank (N) एंडोर्समेंट 119 gallons से अधिक की व्यक्तिगत रेटेड क्षमता और 1,000 gallons या उससे अधिक की कुल रेटेड क्षमता वाले टैंकों पर लागू होता है। स्रोत: Michigan CDL Manual (Michigan SOS); 49 CFR 383.5।"},"32":{"q":"एक मिशिगन CDL धारक को Hazardous Materials (H) एंडोर्समेंट को वैध रखने के लिए TSA Security Threat Assessment को कितनी बार नवीनीकृत करना होता है?","options":["हर साल","हर 3 साल","हर 5 साल","हर 10 साल"],"explanation":"HazMat एंडोर्समेंट के लिए TSA Security Threat Assessment को नई फिंगरप्रिंटिंग और पृष्ठभूमि जाँच सहित हर 5 साल में नवीनीकृत किया जाना चाहिए। स्रोत: Michigan SOS CDL जानकारी; TSA HME (49 CFR 1572)।"},"33":{"q":"7 February 2022 से प्रभावी, मिशिगन में निम्नलिखित में से किसके लिए परीक्षा देने से पहले Entry-Level Driver Training (ELDT) पूरा करना आवश्यक है?","options":["पहली बार Class A या Class B CDL, Class B से Class A में अपग्रेड, या पहली बार P, S, या H एंडोर्समेंट","केवल पहली बार Class A CDL","कोई भी CDL नवीनीकरण","केवल Tank (N) एंडोर्समेंट"],"explanation":"संघीय ELDT, जो मिशिगन में लागू है, पहली बार Class A या Class B CDL, Class B-से-A अपग्रेड, और पहली बार Passenger (P), School Bus (S), या Hazardous Materials (H) एंडोर्समेंट के लिए आवश्यक है। स्रोत: FMCSA ELDT rule (49 CFR 380); Michigan SOS।"},"34":{"q":"एक मिशिगन CDL आवेदक को आवश्यक Entry-Level Driver Training (ELDT) किस संस्था के माध्यम से पूरा करना चाहिए?","options":["आवेदक की पसंद का कोई भी ड्राइविंग प्रशिक्षक","FMCSA Training Provider Registry (TPR) पर सूचीबद्ध एक प्रदाता","सीधे Michigan Secretary of State","Michigan State Police अकादमी"],"explanation":"ELDT को FMCSA Training Provider Registry (TPR) पर सूचीबद्ध किसी स्कूल या संस्था द्वारा प्रदान किया जाना चाहिए; पूर्णता की रिपोर्ट इलेक्ट्रॉनिक रूप से FMCSA को दी जाती है। स्रोत: FMCSA ELDT rule (49 CFR 380); Michigan SOS।"},"35":{"q":"मिशिगन CDL पर पहली बार प्राप्त किए जाने पर किस एंडोर्समेंट के लिए Entry-Level Driver Training (ELDT) की आवश्यकता नहीं होती?","options":["H (Hazardous Materials)","P (Passenger)","S (School Bus)","N (Tank)"],"explanation":"ELDT पहली बार H, P, और S एंडोर्समेंट के लिए अनिवार्य है, लेकिन N (Tank) एंडोर्समेंट ELDT नियम द्वारा कवर नहीं किया जाता। स्रोत: FMCSA ELDT rule (49 CFR 380.603); Michigan SOS।"},"36":{"q":"पात्रता स्थापित करने के लिए एक मिशिगन CDL आवेदक को Secretary of State कार्यालय में दस्तावेजों का कौन सा सेट प्रस्तुत करना होता है?","options":["केवल एक फोटो और एक क्रेडिट कार्ड","पहचान/कानूनी उपस्थिति का प्रमाण, Social Security number का प्रमाण, और मिशिगन निवास का प्रमाण","केवल एक नियोक्ता पत्र","केवल एक पासपोर्ट फोटो और नकद भुगतान"],"explanation":"मिशिगन CLP या CDL जारी करने के लिए अमेरिका में पहचान/कानूनी उपस्थिति का प्रमाण, Social Security number का प्रमाण, और मिशिगन निवास का प्रमाण आवश्यक करता है। स्रोत: Michigan SOS CDL/लाइसेंस दस्तावेज़ आवश्यकताएँ।"},"37":{"q":"मिशिगन CDL स्व-प्रमाणन पर, एक चालक जो राज्य की सीमाओं के पार CMV संचालित करता है और संघीय शारीरिक योग्यता नियमों से छूट प्राप्त नहीं है, उसे किस श्रेणी में प्रमाणित करना चाहिए?","options":["Excepted Interstate","Non-excepted Interstate","Excepted Intrastate","Non-excepted Intrastate"],"explanation":"मिशिगन चार स्व-प्रमाणन श्रेणियों का उपयोग करता है; चिकित्सा नियमों के अधीन इंटरस्टेट वाणिज्य में एक चालक Non-excepted Interstate के रूप में प्रमाणित करता है और उसे एक वैध medical examiner's certificate बनाए रखना चाहिए। स्रोत: Michigan SOS CDL Self-Certification Form।"},"38":{"q":"किस मिशिगन CDL स्व-प्रमाणन श्रेणी के लिए चालक को Secretary of State को एक वैध medical examiner's certificate (DOT medical card) बनाए रखना और प्रस्तुत करना आवश्यक है?","options":["Excepted Interstate","Excepted Intrastate","Non-excepted Interstate","21 वर्ष से कम आयु का कोई भी चालक"],"explanation":"चार श्रेणियों में से, दो 'non-excepted' प्रकारों के लिए एक वैध medical examiner's certificate आवश्यक है; non-excepted interstate चालक को Michigan SOS के पास एक वर्तमान DOT medical card रखना चाहिए। स्रोत: Michigan SOS CDL Self-Certification (BFS-103)।"},"39":{"q":"CDL ज्ञान परीक्षा से पहले प्रशिक्षण आवश्यकता को पूरा करने के लिए एक मिशिगन आवेदक को ELDT सिद्धांत (ज्ञान) मूल्यांकन पर कम से कम कितना स्कोर प्राप्त करना होता है?","options":["70%","75%","80%","90%"],"explanation":"संघीय ELDT, जो मिशिगन में लागू है, किसी Training Provider Registry प्रदाता से न्यूनतम 80% सिद्धांत मूल्यांकन स्कोर आवश्यक करता है। स्रोत: FMCSA ELDT rule (49 CFR 380.609); Michigan SOS।"},"40":{"q":"किस रक्त अल्कोहल सांद्रता (BAC) पर या उससे अधिक पर एक CDL धारक को मिशिगन में वाणिज्यिक मोटर वाहन संचालित करने से प्रतिबंधित किया जाता है?","options":["0.08","0.04","0.02","0.10"],"explanation":"0.04 या उससे अधिक BAC के साथ CMV संचालित करना मिशिगन में एक प्रमुख अपराध है। यह सामान्य चालकों पर लागू होने वाली 0.08 सीमा का आधा है। स्रोत: Michigan CDL Manual (अल्कोहल/अयोग्यता अनुभाग); 49 CFR 383.51 Table 1।"},"41":{"q":"पहले प्रमुख अपराध (जैसे 0.04 या उससे अधिक BAC के साथ CMV संचालित करना) के लिए, जब कोई खतरनाक सामग्री शामिल न हो तो मिशिगन में CDL अयोग्यता कितने समय की होती है?","options":["60 days","6 months","1 year","3 years"],"explanation":"पहले प्रमुख अपराध के परिणामस्वरूप मिशिगन में 1-year CDL अयोग्यता होती है। स्रोत: 49 CFR 383.51 Table 1, जो Michigan Vehicle Code (MCL 257.319b) के माध्यम से मिशिगन में अपनाई गई; Michigan CDL Manual।"},"42":{"q":"यदि चालक खतरनाक सामग्री के लिए प्लेकार्ड वाले वाहन को संचालित कर रहा था तो पहले प्रमुख अपराध के लिए CDL अयोग्यता कितने समय की होती है?","options":["1 year","18 months","3 years","5 years"],"explanation":"प्लेकार्ड वाले HazMat वाहन को संचालित करते समय किए गए पहले प्रमुख अपराध के परिणामस्वरूप मानक 1 year के बजाय 3-year अयोग्यता होती है। स्रोत: 49 CFR 383.51 Table 1; Michigan CDL Manual।"},"43":{"q":"मिशिगन में दूसरे प्रमुख अपराध (उदाहरण के लिए, दूसरी अल्कोहल-संबंधित दोषसिद्धि) के लिए CDL अयोग्यता अवधि क्या है?","options":["3 years","5 years","10 years","Lifetime"],"explanation":"दूसरे प्रमुख अपराध के परिणामस्वरूप मिशिगन में आजीवन CDL अयोग्यता होती है। स्रोत: 49 CFR 383.51 Table 1; Michigan CDL Manual; MCL 257.319b।"},"44":{"q":"मिशिगन के निहित-सहमति कानून के तहत, एक CDL धारक जो पहली बार कानूनी रूप से अनुरोधित रासायनिक (अल्कोहल) परीक्षण से इनकार करता है, उसे CMV संचालित करने से कितने समय के लिए अयोग्य ठहराया जाता है?","options":["90 days","1 year","3 years","Lifetime"],"explanation":"आवश्यक अल्कोहल परीक्षण से इनकार करने को एक प्रमुख अपराध की तरह माना जाता है और इसके परिणामस्वरूप 1-year CDL अयोग्यता होती है, चाहे चालक CMV में हो या निजी वाहन में। स्रोत: Michigan implied-consent law (MCL 257.625c); 49 CFR 383.51 Table 1।"},"45":{"q":"मिशिगन में CDL प्रयोजनों के लिए निम्नलिखित में से किसे 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत किया गया है?","options":["0.04 या उससे अधिक BAC के साथ CMV संचालित करना","निर्धारित सीमा से 15 mph या अधिक गति से वाहन चलाना","CMV से जुड़ी दुर्घटना के स्थान को छोड़ना","रासायनिक परीक्षण से इनकार करना"],"explanation":"निर्धारित सीमा से 15 mph या अधिक गति से वाहन चलाना एक गंभीर यातायात उल्लंघन है। अन्य विकल्प प्रमुख अपराध हैं, गंभीर उल्लंघन नहीं। स्रोत: 49 CFR 383.51 Table 2; Michigan CDL Manual।"},"46":{"q":"एक CDL धारक को 3-year अवधि के भीतर अलग-अलग घटनाओं से उत्पन्न दो गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया जाता है। मिशिगन में अयोग्यता अवधि क्या है?","options":["30 days","60 days","120 days","1 year"],"explanation":"3 years के भीतर अलग-अलग घटनाओं में दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप 60-day CDL अयोग्यता होती है। स्रोत: 49 CFR 383.51 Table 2; Michigan CDL Manual।"},"47":{"q":"एक CDL धारक को 3-year अवधि के भीतर अलग-अलग घटनाओं से तीन गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया जाता है। अयोग्यता अवधि क्या है?","options":["60 days","90 days","120 days","1 year"],"explanation":"3 years के भीतर अलग-अलग घटनाओं में तीन या अधिक गंभीर यातायात उल्लंघनों के परिणामस्वरूप 120-day CDL अयोग्यता होती है। स्रोत: 49 CFR 383.51 Table 2; Michigan CDL Manual।"},"48":{"q":"किसी भी अयोग्यता शुरू होने से पहले एक CDL धारक को 3-year अवधि के भीतर कितने गंभीर यातायात उल्लंघन जमा करने होते हैं?","options":["एक","दो","तीन","चार"],"explanation":"एक अकेला गंभीर यातायात उल्लंघन अयोग्यता को ट्रिगर नहीं करता; पहली अयोग्यता (60 days) 3 years के भीतर दूसरी दोषसिद्धि पर लागू होती है। स्रोत: 49 CFR 383.51 Table 2; Michigan CDL Manual।"},"49":{"q":"वाणिज्यिक मोटर वाहन में किया गया कौन सा उल्लंघन एक निर्दिष्ट गंभीर यातायात उल्लंघन है जो मिशिगन में 60/120-day अयोग्यता की ओर गिना जा सकता है?","options":["CMV चलाते समय टेक्स्टिंग करना","0.04 या उससे अधिक BAC के साथ संचालन करना","अपराध करने के लिए CMV का उपयोग करना","out-of-service order का उल्लंघन करना"],"explanation":"CMV चलाते समय टेक्स्टिंग करना एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध है। BAC 0.04+ और अपराध में CMV का उपयोग प्रमुख अपराध हैं, और एक out-of-service order उल्लंघन की अपनी अलग दंड अनुसूची है। स्रोत: 49 CFR 383.51 Table 2; Michigan CDL Manual।"},"50":{"q":"CMV में पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए दोषी पाए गए चालक को मिशिगन में कम से कम कितने समय के लिए अयोग्य ठहराया जाता है?","options":["30 days","60 days","120 days","1 year"],"explanation":"पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन 60 days से कम नहीं की अयोग्यता रखता है। स्रोत: 49 CFR 383.51 Table 3; Michigan CDL Manual।"},"51":{"q":"3-year अवधि के भीतर दूसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["60 days","90 days","120 days","1 year"],"explanation":"3 years के भीतर दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन 120 days से कम नहीं की अयोग्यता रखता है। स्रोत: 49 CFR 383.51 Table 3; Michigan CDL Manual।"},"52":{"q":"3-year अवधि के भीतर तीसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["120 days","180 days","1 year","3 years"],"explanation":"3 years के भीतर तीसरा या बाद का रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन 1 year से कम नहीं की अयोग्यता रखता है। स्रोत: 49 CFR 383.51 Table 3; Michigan CDL Manual।"},"53":{"q":"CMV संचालित करते समय (गैर-HazMat, गैर-यात्री) किसी चालक या वाहन out-of-service order का उल्लंघन करने की पहली दोषसिद्धि के लिए अयोग्यता अवधि क्या है?","options":["30 days से कम नहीं","90 days से कम नहीं लेकिन 1 year से अधिक नहीं","180 days से कम नहीं लेकिन 1 year से अधिक नहीं","1 year से कम नहीं लेकिन 5 years से अधिक नहीं"],"explanation":"पहला out-of-service order उल्लंघन 180 days से कम नहीं और 1 year से अधिक नहीं की अयोग्यता में परिणत होता है। स्रोत: 49 CFR 383.51 Table 4; Michigan CDL Manual।"},"54":{"q":"10-year अवधि के भीतर अलग-अलग घटनाओं में दूसरे out-of-service order उल्लंघन के लिए अयोग्यता सीमा क्या है?","options":["180 days से कम नहीं लेकिन 1 year से अधिक नहीं","1 year से कम नहीं लेकिन 3 years से अधिक नहीं","2 years से कम नहीं लेकिन 5 years से अधिक नहीं","3 years से कम नहीं लेकिन 5 years से अधिक नहीं"],"explanation":"10 years के भीतर दूसरा out-of-service order उल्लंघन 2 years से कम नहीं और 5 years से अधिक नहीं की अयोग्यता में परिणत होता है। स्रोत: 49 CFR 383.51 Table 4; Michigan CDL Manual।"},"55":{"q":"एक चालक प्लेकार्ड वाली खतरनाक सामग्री का परिवहन करते समय या 16 या अधिक यात्रियों को ले जाते समय पहली बार out-of-service order का उल्लंघन करता है। अयोग्यता सीमा क्या है?","options":["90 days से कम नहीं लेकिन 1 year से अधिक नहीं","180 days से कम नहीं लेकिन 2 years से अधिक नहीं","1 year से कम नहीं लेकिन 3 years से अधिक नहीं","3 years से कम नहीं लेकिन 5 years से अधिक नहीं"],"explanation":"प्लेकार्ड वाली HazMat ले जाते समय या 16+ यात्रियों को ले जाते समय पहला out-of-service order उल्लंघन 180 days से कम नहीं और 2 years से अधिक नहीं की अयोग्यता में परिणत होता है। स्रोत: 49 CFR 383.51 Table 4; Michigan CDL Manual।"},"56":{"q":"मिशिगन में अपनाए गए संघीय नियमों के तहत, वाहन चलाते समय हैंड-हेल्ड मोबाइल फोन का उपयोग करने या टेक्स्टिंग करने के लिए एक CMV चालक को अधिकतम कितना नागरिक दंड भुगतना पड़ सकता है?","options":["$500","$1,000","$2,750","$11,000"],"explanation":"एक चालक को हैंड-हेल्ड फोन या टेक्स्टिंग उल्लंघन के लिए $2,750 तक जुर्माना लग सकता है; एक नियोक्ता जो इसकी अनुमति देता है या इसकी आवश्यकता रखता है उसे $11,000 तक जुर्माना लग सकता है। स्रोत: 49 CFR 392.80/392.82 और FMCSA No-Texting/Hand-Held rule fact sheet; Michigan CDL Manual।"},"57":{"q":"एक CMV चालक ड्यूटी पर रहते हुए कोई मापी गई या पता लगाई गई अल्कोहल के साथ पाया जाता है, या जिसने ड्यूटी पर जाने से 4 घंटे पहले अल्कोहल का उपयोग या रखाव किया था। तत्काल परिणाम क्या है?","options":["तत्काल 1-year CDL अयोग्यता","24 घंटे के लिए out of service रखा जाना","7 दिनों के लिए out of service रखा जाना","तत्काल आजीवन अयोग्यता"],"explanation":"अल्कोहल निषेध के तहत, ऐसे चालक को 24 घंटे के लिए out of service रखा जाना चाहिए। यह 0.04 प्रमुख-अपराध सीमा से अलग है। स्रोत: 49 CFR 392.5; Michigan CDL Manual।"},"58":{"q":"एक CDL धारक को अपने खुद के निजी (गैर-वाणिज्यिक) वाहन को चलाते समय अल्कोहल-संबंधित ड्राइविंग अपराध के लिए दोषी ठहराया जाता है। यह मिशिगन में CDL को कैसे प्रभावित करता है?","options":["इसका कोई प्रभाव नहीं होता क्योंकि कोई CMV शामिल नहीं था","इसके परिणामस्वरूप 1-year CDL अयोग्यता होती है","इसके परिणामस्वरूप केवल 60-day अयोग्यता होती है","इसके परिणामस्वरूप केवल अंक होते हैं, अयोग्यता नहीं"],"explanation":"प्रमुख अपराध, जिनमें अल्कोहल अपराध शामिल हैं, निजी वाहन में किए जाने पर भी CDL अयोग्यता को ट्रिगर करते हैं; पहला ऐसा अपराध 1-year अयोग्यता है। स्रोत: 49 CFR 383.51 Table 1; Michigan CDL Manual।"},"59":{"q":"एक CMV चालक 0.02 या उससे अधिक लेकिन 0.04 से कम का BAC दर्ज करता है। मिशिगन में लागू नियमों के तहत कौन सा कथन परिणाम का सबसे अच्छा वर्णन करता है?","options":["इसे 1-year अयोग्यता के साथ एक प्रमुख अपराध के रूप में माना जाता है","0.04 से नीचे कोई परिणाम नहीं है","चालक 24 घंटे तक सुरक्षा-संवेदनशील कार्य नहीं कर सकता","यह एक स्वतः out-of-service order उल्लंघन है"],"explanation":"0.02 या उससे अधिक लेकिन 0.04 से नीचे की एक पुष्ट अल्कोहल सांद्रता चालक को 24 घंटे तक सुरक्षा-संवेदनशील कार्य करने से रोकती है; एक अयोग्य ठहराने वाला प्रमुख अपराध 0.04 से शुरू होता है। स्रोत: 49 CFR 382.505 और 383.51; Michigan CDL Manual।"},"60":{"q":"मिशिगन के 'मूव ओवर' कानून के तहत, जब आप लाइट जलाए हुए किसी स्थिर आपातकालीन वाहन के पास पहुँच रहे हों और आप सुरक्षित रूप से एक लेन बगल में नहीं हट सकते, तो आपको पोस्ट की गई गति सीमा से कितनी गति कम करनी चाहिए?","options":["पोस्ट की गई गति सीमा से कम से कम 10 mph कम","पोस्ट की गई गति सीमा से कम से कम 5 mph कम","पोस्ट की गई गति सीमा से कम से कम 15 mph कम","पोस्ट की गई गति सीमा से कम से कम 20 mph कम"],"explanation":"मिशिगन का 'मूव ओवर' कानून (MCL 257.653a) किसी लाइट जलाए हुए स्थिर अधिकृत आपातकालीन वाहन के पास पहुँचने वाले चालक से अपेक्षा करता है कि वह कम से कम एक लेन बगल में हट जाए, या यदि वह संभव न हो, तो गति को पोस्ट की गई गति सीमा से कम से कम 10 mph कम कर दे और उचित सावधानी के साथ आगे बढ़े। स्रोत: MCL 257.653a; मिशिगन स्टेट पुलिस मूव ओवर अभियान।"},"61":{"q":"एक दिशा में यात्रा के लिए दो या अधिक लेन वाली मिशिगन की सड़क पर, 10,000 पाउंड से अधिक सकल वजन वाला ट्रक, ट्रक-ट्रैक्टर, या संयोजन वाहन कहाँ चलाया जा सकता है?","options":["केवल दाहिनी ओर की दो सबसे दूर की लेनों में से किसी एक में","किसी भी लेन में, यात्री कारों के समान","हर समय केवल सबसे दाहिनी ओर की एकमात्र लेन में","विलय करने वाले यातायात से बचने के लिए केवल बीच की लेन में"],"explanation":"मिशिगन कानून (MCL 257.634) के अनुसार एक दिशा में दो या अधिक लेन वाली सड़क पर, 10,000 lbs से अधिक का ट्रक, ट्रक-ट्रैक्टर, या वाहन-और-ट्रेलर संयोजन को केवल दाहिनी ओर की दो सबसे दूर की लेनों में से किसी एक में ही चलाया जाना चाहिए। स्रोत: MCL 257.634।"},"62":{"q":"मिशिगन के सीमित-पहुँच फ्रीवे पर जहाँ पोस्ट की गई गति सीमा 65 mph से अधिक है, वहाँ 10,000 पाउंड या उससे अधिक सकल वजन वाले ट्रक के लिए अधिकतम गति क्या है?","options":["65 mph","60 mph","70 mph","55 mph"],"explanation":"MCL 257.627 के तहत, जहाँ पोस्ट की गई सीमा 65 mph से अधिक है, वहाँ 10,000 lbs या उससे अधिक का ट्रक, ट्रक-ट्रैक्टर या संयोजन, या स्कूल बस किसी सीमित-पहुँच फ्रीवे या स्टेट ट्रंकलाइन हाईवे पर 65 mph से अधिक नहीं चल सकती। यह 2016 के Public Act 445 द्वारा किए गए बदलाव को दर्शाता है। स्रोत: MCL 257.627।"},"63":{"q":"मिशिगन में, प्लेकार्ड लगे खतरनाक-सामग्री वाहन के चालक को रेलमार्ग ट्रैक को समतल पर पार करने से पहले निकटतम रेल से कितनी दूरी पर रुकना चाहिए?","options":["50 फीट के भीतर लेकिन 15 फीट से कम नहीं","100 फीट के भीतर लेकिन 25 फीट से कम नहीं","40 फीट के भीतर लेकिन 10 फीट से कम नहीं","75 फीट के भीतर लेकिन 20 फीट से कम नहीं"],"explanation":"MCL 257.669 के अनुसार प्लेकार्ड लगे वाहनों (और 16+ यात्रियों या किराए के यात्रियों को ले जाने वाले वाहनों) के चालकों को हैज़र्ड लाइट चालू करनी चाहिए और पार करने से पहले निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं की दूरी पर रुकना चाहिए। स्रोत: MCL 257.669; मिशिगन CDL मैनुअल सेक्शन 9।"},"64":{"q":"मिशिगन में, दो बारी-बारी से चमकती लाल लाइटों के साथ रुकी हुई स्कूल बस के सामने आने वाले या उसे ओवरटेक करने वाले वाहन को बस से कम से कम कितनी दूरी पर पूरी तरह रुकना चाहिए?","options":["20 फीट से कम नहीं","10 फीट से कम नहीं","15 फीट से कम नहीं","30 फीट से कम नहीं"],"explanation":"MCL 257.682 के अनुसार चमकती लाल लाइटें दिखाने वाली स्कूल बस को ओवरटेक करने वाले या उसके सामने आने वाले चालक को बस से 20 फीट से कम नहीं की दूरी पर रुकना चाहिए और तब तक आगे नहीं बढ़ना चाहिए जब तक बस आगे न बढ़े या संकेत बंद न हो जाएँ। स्रोत: MCL 257.682।"},"65":{"q":"मिशिगन में, ऊँचे बीच के स्थान या भौतिक अवरोध द्वारा दो सड़कों में विभाजित हाईवे पर, कौन से चालकों को विपरीत ओर चमकती लाल लाइटें दिखाने वाली स्कूल बस के लिए रुकने की आवश्यकता नहीं है?","options":["अवरोध के पार विपरीत सड़क से बस के सामने आने वाले चालक","दोनों दिशाओं के सभी चालकों को फिर भी रुकना चाहिए","केवल बस के ठीक पीछे के चालक","केवल बस के निकटतम लेन के चालक"],"explanation":"MCL 257.682(2) के तहत, जहाँ कोई हाईवे किसी ऊँचे बीच के स्थान, भौतिक अवरोध, या स्पष्ट रूप से चिह्नित विभाजन खंड द्वारा दो सड़कों में विभाजित होता है, वहाँ उस विभाजन के पार बस के सामने आने वाले चालक को रुकने की आवश्यकता नहीं है। उसी सड़क पर बस के पीछे यात्रा करने वाले चालकों को फिर भी रुकना चाहिए। स्रोत: MCL 257.682(2)।"},"66":{"q":"जब कोई मिशिगन CDL चालक किसी एक-तरफ़ा या विभाजित हाईवे के किनारे (शोल्डर) पर वाणिज्यिक वाहन रोकता है, तो तीन परावर्तक चेतावनी त्रिकोण कहाँ रखे जाने चाहिए?","options":["आने वाले यातायात की ओर 10, 100, और 200 फीट पर","वाहन के दोनों ओर 10, 100, और 100 फीट पर","आने वाले यातायात की ओर 25, 100, और 250 फीट पर","आने वाले यातायात की ओर 50, 150, और 300 फीट पर"],"explanation":"एक-तरफ़ा या विभाजित हाईवे पर, चेतावनी उपकरण वाहन के पीछे से आने वाले यातायात की ओर 10, 100, और 200 फीट पर रखे जाते हैं। मिशिगन CDL मैनुअल संघीय FMCSA मानक (49 CFR 392.22) का पालन करता है। स्रोत: मिशिगन CDL मैनुअल; 49 CFR 392.22।"},"67":{"q":"दो-लेन, दो-तरफ़ा मिशिगन हाईवे पर, रुके हुए CMV चालक को तीन चेतावनी त्रिकोण कैसे रखने चाहिए?","options":["एक लगभग 10 फीट पीछे, एक लगभग 100 फीट पीछे, और एक वाहन के लगभग 100 फीट आगे","तीनों वाहन के लगभग 100 फीट पीछे एक पंक्ति में","एक 10 पर, एक 200 पर, और एक वाहन के 500 फीट पीछे","एक हुड पर और दो वाहन के लगभग 50 फीट पीछे"],"explanation":"दो-लेन, दो-तरफ़ा सड़क पर, एक त्रिकोण आने वाले यातायात की ओर पीछे लगभग 10 फीट पर, एक लगभग 100 फीट पीछे, और एक वाहन के लगभग 100 फीट आगे रखें। स्रोत: मिशिगन CDL मैनुअल; 49 CFR 392.22।"},"68":{"q":"मिशिगन की वसंत ऋतु की 'फ्रॉस्ट लॉ' मौसमी वजन प्रतिबंधों के दौरान, मिशिगन व्हीकल कोड में निर्धारित अनुसार, प्रतिबंधित मार्ग पर कम भार वाला वाणिज्यिक वाहन ले जाने के लिए अधिकतम गति क्या है?","options":["35 mph","45 mph","25 mph","55 mph"],"explanation":"MCL 257.627 के अनुसार जब कम (मौसमी) भार सीमाएँ लागू होती हैं, तब उन कम भारों के तहत संचालित वाहन 35 mph तक सीमित होते हैं। यह मिशिगन के विशिष्ट फ्रॉस्ट-लॉ कार्यक्रम का हिस्सा है। स्रोत: MCL 257.627; MDOT मौसमी वजन प्रतिबंध।"},"69":{"q":"मिशिगन के मौसमी वजन प्रतिबंधों के तहत, वसंत के पिघलाव के दौरान कानूनी धुरी (एक्सल) वजन में कोई कमी न होने के रूप में कौन से मार्ग निर्धारित हैं?","options":["'सर्व-ऋतु' (all-season) मार्ग, जो MDOT ट्रक ऑपरेटर्स मैप पर हरे और सुनहरे रंग में दिखाए गए हैं","सभी काउंटी बजरी सड़कें","केवल शहर की सीमा के भीतर इंटरस्टेट फ्रीवे","MDOT ट्रक ऑपरेटर्स मैप पर ठोस या बिंदीदार लाल रंग में दिखाए गए मार्ग"],"explanation":"MDOT 'सर्व-ऋतु' (all-season) मार्ग (MDOT ट्रक ऑपरेटर्स मैप पर हरे और सुनहरे) निर्धारित करता है जो साल भर पूर्ण कानूनी धुरी वजन बनाए रखते हैं, जबकि 'मौसमी' मार्ग (ठोस या बिंदीदार लाल) वसंत में धुरी-वजन में कमी के अधीन होते हैं। स्रोत: MDOT ट्रक ऑपरेटर्स मैप / मौसमी वजन प्रतिबंध मार्गदर्शन।"},"70":{"q":"मिशिगन के 'मौसमी' मार्ग पर वसंत के वजन प्रतिबंधों के दौरान, लचीली (डामर/asphalt) सतह पर कौन सी धुरी-वजन में कमी लागू होती है?","options":["35 प्रतिशत","25 प्रतिशत","10 प्रतिशत","50 प्रतिशत"],"explanation":"मौसमी मार्गों पर वसंत प्रतिबंधों के दौरान, MDOT लचीली (डामर) सतह पर 35 प्रतिशत और कठोर (कंक्रीट) सतह पर 25 प्रतिशत धुरी-वजन में कमी लगाता है। स्रोत: MDOT मौसमी वजन प्रतिबंध मार्गदर्शन।"},"71":{"q":"एक मिशिगन CDL चालक प्लेकार्ड लगा भार ले जाते समय 'EXEMPT' लिखे संकेत वाले रेलमार्ग क्रॉसिंग के पास पहुँचता है। मिशिगन कानून क्या अपेक्षा करता है?","options":["'exempt' चिह्नित क्रॉसिंग पर रुकना आवश्यक नहीं है","चालक को फिर भी निकटतम रेल से 50 फीट के भीतर रुकना चाहिए","चालक को रुकना चाहिए और चेतावनी त्रिकोण निकालकर रखने चाहिए","चालक को केवल तभी रुकना चाहिए जब हैज़र्ड लाइट उपलब्ध न हो"],"explanation":"MCL 257.669 के तहत, 'exempt' लिखे संकेत वाले रेलमार्ग समतल क्रॉसिंग पर रुकना आवश्यक नहीं है, यहाँ तक कि प्लेकार्ड लगे वाहनों के लिए भी। अन्य सभी क्रॉसिंग पर प्लेकार्ड लगे वाहन को निकटतम रेल से 15 से 50 फीट की दूरी पर रुकना चाहिए। स्रोत: MCL 257.669।"},"72":{"q":"मिशिगन में बिना ओवरसाइज़ परमिट के किसी वाणिज्यिक वाहन या उसके भार की अधिकतम कानूनी चौड़ाई क्या है?","options":["96 इंच (8 फीट)","102 इंच (8 फीट 6 इंच)","108 इंच (9 फीट)","120 इंच (10 फीट)"],"explanation":"MCL 257.717 मिशिगन की अधिकतम कानूनी चौड़ाई 96 इंच (8 फीट) निर्धारित करता है; इससे अधिक चौड़ी किसी भी चीज़ के लिए ओवरसाइज़ परमिट की आवश्यकता होती है। ध्यान दें कि यह कई अन्य राज्यों द्वारा उपयोग किए जाने वाले 102-इंच मानक से संकरा है। स्रोत: MCL 257.717; MDOT अधिकतम कानूनी ट्रक भार और आयाम।"},"73":{"q":"मिशिगन में बिना परमिट के किसी वाणिज्यिक वाहन की, भरे या खाली, अधिकतम कानूनी ऊँचाई क्या है?","options":["13 फीट 6 इंच","14 फीट 0 इंच","13 फीट 0 इंच","12 फीट 6 इंच"],"explanation":"MCL 257.719 मिशिगन की अधिकतम कानूनी वाहन ऊँचाई, भरे या खाली, 13 फीट 6 इंच निर्धारित करता है। स्रोत: MCL 257.719; MDOT अधिकतम कानूनी ट्रक भार और आयाम।"},"74":{"q":"एक ही दिशा में यात्रा के लिए तीन या अधिक लेन वाले मिशिगन फ्रीवे पर, लेन-उपयोग कानून (MCL 257.634) किस लेन का उपयोग वाहन को करना चाहिए, इस बारे में क्या कहता है?","options":["एक ही दिशा में तीन या अधिक लेन वाले फ्रीवे की किसी भी लेन में यात्रा करने से वाहन को मना नहीं किया गया है","सभी वाहनों को ओवरटेक करते समय छोड़कर सबसे दाहिनी लेन में ही रहना चाहिए","ट्रकों को केवल बीच की लेन का उपयोग करना चाहिए","सभी वाहनों को केवल दो बाईं लेनों का उपयोग करना चाहिए"],"explanation":"MCL 257.634 के अनुसार दाएँ-रहने की आवश्यकता किसी वाहन को एक ही दिशा में तीन या अधिक लेन वाले फ्रीवे की किसी भी लेन में यात्रा करने से नहीं रोकती। हालाँकि, भारी ट्रक दाहिनी ओर की दो लेनों तक सीमित रहते हैं। स्रोत: MCL 257.634।"},"75":{"q":"मिशिगन में, रेलमार्ग ट्रैक को समतल पर पार करने से पहले, निकटतम रेल से 15 से 50 फीट की दूरी पर रुकने के अतिरिक्त स्कूल बस के चालक को निम्नलिखित में से क्या करना चाहिए?","options":["हैज़र्ड लाइट चालू करें, यात्री दरवाज़ा और चालक की खिड़की खोलें, और दोनों ओर देखें और सुनें","आगे बढ़ने से पहले हॉर्न तीन बार बजाएँ","बस के 100 फीट पीछे परावर्तक त्रिकोण रखें","कम गियर में डालें और तेज़ करते हुए पार करें"],"explanation":"MCL 257.1857 के अनुसार स्कूल बस चालक को निकटतम रेल से 15-50 फीट की दूरी पर रुकना चाहिए, हैज़र्ड चेतावनी लाइट चालू करनी चाहिए, शोर के स्रोत बंद करने चाहिए, यात्री दरवाज़ा और चालक-ओर की खिड़की खोलनी चाहिए, और ट्रैक पर गियर बदले बिना आगे बढ़ने से पहले दोनों ओर देखना और सुनना चाहिए। स्रोत: MCL 257.1857।"},"76":{"q":"एक CDL चालक बिना किसी पोस्ट की गई गति सीमा के संकेत वाले मिशिगन के दो-लेन काउंटी हाईवे पर है। कौन सी सामान्य वैधानिक गति सीमा लागू होती है?","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"MCL 257.627 ट्रंकलाइन और काउंटी हाईवे पर जहाँ कोई अन्य सीमा पोस्ट नहीं की गई है, वहाँ 55 mph की सामान्य गति सीमा निर्धारित करता है (और मेल खाती हुई 55 mph की सामान्य बजरी-सड़क गति सीमा)। एक भारी ट्रक इससे अधिक नहीं चलेगा। स्रोत: MCL 257.627।"},"77":{"q":"मिशिगन में संचालन करने वाले वाणिज्यिक चालकों के लिए टोल सड़कों के बारे में कौन सा कथन सही है?","options":["मिशिगन में कोई टोल हाईवे नहीं है; टोल केवल कुछ पुल और सुरंग क्रॉसिंग जैसे मैकिनैक, ब्लू वाटर, और इंटरनेशनल पुलों पर लागू होते हैं","मिशिगन के सभी इंटरस्टेट फ्रीवे टोल सड़कें हैं जिनके लिए ट्रांसपोंडर आवश्यक है","ट्रक I-94 और I-75 पर टोल देते हैं लेकिन कारें नहीं देतीं","मिशिगन सर्दियों के दौरान सभी स्टेट ट्रंकलाइन हाईवे पर टोल वसूलता है"],"explanation":"मिशिगन के इंटरस्टेट और स्टेट हाईवे टोल-मुक्त हैं; टोल केवल विशिष्ट सीमा और जलडमरूमध्य क्रॉसिंग जैसे मैकिनैक ब्रिज, ब्लू वाटर ब्रिज, और सॉल्ट स्टे. मैरी के इंटरनेशनल ब्रिज पर वसूले जाते हैं। स्रोत: MDOT पुल टोल जानकारी।"},"78":{"q":"नियमित आवधिक वाहन निरीक्षण के संबंध में, मिशिगन में पंजीकृत वाणिज्यिक वाहनों के लिए क्या सही है?","options":["मिशिगन में राज्यव्यापी आवधिक सुरक्षा या उत्सर्जन निरीक्षण की आवश्यकता नहीं है, हालाँकि CMVs को फिर भी संघीय CMV निरीक्षण आवश्यकताओं को पूरा करना होगा","मिशिगन में हर वाणिज्यिक वाहन के लिए वार्षिक उत्सर्जन परीक्षण आवश्यक है","मिशिगन में राज्य-संचालित स्टेशन पर हर दो साल में सुरक्षा निरीक्षण आवश्यक है","मिशिगन में हर CDL नवीनीकरण से पहले स्मॉग जाँच आवश्यक है"],"explanation":"मिशिगन वाहनों के लिए राज्यव्यापी आवधिक सुरक्षा या उत्सर्जन निरीक्षण अनिवार्य नहीं करता। हालाँकि, वाणिज्यिक मोटर वाहन राज्य कार्यक्रम के अभाव के बावजूद संघीय FMCSA निरीक्षण और रखरखाव आवश्यकताओं के अधीन रहते हैं। स्रोत: Michigan SOS / MDOT; 49 CFR Part 396।"},"79":{"q":"मिशिगन के 'मूव ओवर' कानून के तहत, जब यातायात की स्थिति आपको किसी स्थिर अधिकृत आपातकालीन वाहन के लिए लेन बदलने की अनुमति देती है, तो आपको कितनी दूर हटना चाहिए?","options":["स्थिर वाहन से कम से कम एक चलती लेन या दो वाहन-चौड़ाई दूर","पूरी तरह सड़क से हटकर दूर के किनारे (शोल्डर) पर","स्थिर वाहन से कम से कम तीन वाहन-चौड़ाई दूर","स्थिति की परवाह किए बिना सबसे बाईं लेन में"],"explanation":"MCL 257.653a के अनुसार चालकों को, जब संभव हो, स्थिर अधिकृत आपातकालीन वाहन से कम से कम एक चलती लेन या दो वाहन-चौड़ाई दूर की लेन में हटना चाहिए, साथ ही पोस्ट की गई सीमा से कम से कम 10 mph कम गति पर भी धीमा होना चाहिए। स्रोत: MCL 257.653a।"},"80":{"q":"मिशिगन में वाणिज्यिक चालक लाइसेंस (CDLs) कौन सी एजेंसी जारी करती है?","options":["मिशिगन स्टेट पुलिस कमर्शियल व्हीकल डिवीज़न","मिशिगन डिपार्टमेंट ऑफ ट्रांसपोर्टेशन (MDOT)","मिशिगन डिपार्टमेंट ऑफ स्टेट (सेक्रेटरी ऑफ स्टेट)","फेडरल मोटर कैरियर सेफ्टी एडमिनिस्ट्रेशन (FMCSA)"],"explanation":"मिशिगन में, CDLs मिशिगन डिपार्टमेंट ऑफ स्टेट द्वारा जारी किए जाते हैं, जिसका नेतृत्व सेक्रेटरी ऑफ स्टेट करते हैं; CDL ज्ञान परीक्षण और आवेदन SOS कार्यालयों में संभाले जाते हैं। स्रोत: मिशिगन CDL मैनुअल (SOS) और michigan.gov SOS CDL पृष्ठ।"},"81":{"q":"मिशिगन में CDL ऑन-रोड और बुनियादी नियंत्रण कौशल परीक्षण कहाँ आयोजित किए जाते हैं?","options":["किसी भी सेक्रेटरी ऑफ स्टेट शाखा कार्यालय में SOS कर्मचारियों द्वारा","FMCSA क्षेत्रीय परीक्षण केंद्रों पर","मिशिगन स्टेट पुलिस मोटर कैरियर अधिकारियों द्वारा","MDOS-अनुमोदित तृतीय-पक्ष चालक परीक्षण व्यवसायों द्वारा"],"explanation":"मिशिगन SOS शाखाओं में CDL कौशल परीक्षण नहीं देता; तीन-भाग वाला कौशल परीक्षण मिशिगन डिपार्टमेंट ऑफ स्टेट (MDOS)-अनुमोदित तृतीय-पक्ष चालक परीक्षण व्यवसायों द्वारा आयोजित किया जाता है। स्रोत: मिशिगन CDL मैनुअल (SOS)।"},"82":{"q":"मिशिगन CDL कौशल परीक्षण कितने भागों से मिलकर बना है?","options":["दो: एक लिखित परीक्षण और एक ऑन-रोड ड्राइविंग परीक्षण","तीन: प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड ड्राइविंग","दो: बुनियादी नियंत्रण कौशल और एक खतरनाक सामग्री जाँच","चार: प्री-ट्रिप, बैकिंग, ऑन-रोड, और एक लिखित सुरक्षा परीक्षण"],"explanation":"मिशिगन CDL कौशल परीक्षण के तीन भाग हैं: वाहन (प्री-ट्रिप) निरीक्षण परीक्षण, बुनियादी वाहन नियंत्रण कौशल परीक्षण, और ऑन-रोड ड्राइविंग परीक्षण, जिन सभी को पास करना होगा। स्रोत: मिशिगन CDL मैनुअल (SOS)।"},"83":{"q":"मिशिगन में पहली बार CDL आवेदक के कौशल परीक्षण देने से पहले, कौन सा संघीय प्रशिक्षण पूरा होना चाहिए?","options":["कम से कम छह महीने की नियोक्ता-प्रायोजित प्रशिक्षुता (apprenticeship)","40-घंटे का खतरनाक सामग्री सुरक्षा पाठ्यक्रम","किसी पंजीकृत प्रदाता से एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT)","MDOT द्वारा अनुमोदित एक रक्षात्मक ड्राइविंग पाठ्यक्रम"],"explanation":"7 फरवरी 2022 से, FMCSA की एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) नियम पहली बार CDL आवेदकों (और कुछ अपग्रेड/एंडोर्समेंट) से अपेक्षा करता है कि वे कौशल परीक्षण से पहले FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री पर मौजूद किसी प्रदाता से ELDT पूरा करें। स्रोत: मिशिगन CDL मैनुअल (SOS); FMCSA ELDT नियम।"},"84":{"q":"CLP प्राप्त करने के बाद, मिशिगन आवेदक को CDL कौशल परीक्षण देने से पहले कितनी देर प्रतीक्षा करनी चाहिए?","options":["कम से कम 7 दिन","कम से कम 60 दिन","कम से कम 14 दिन","कम से कम 30 दिन"],"explanation":"संघीय और मिशिगन नियमों के अनुसार आवेदक के CDL कौशल परीक्षण देने से पहले CLP को कम से कम 14 दिन तक रखना आवश्यक है। स्रोत: मिशिगन CDL मैनुअल (SOS); 49 CFR 383.25।"},"85":{"q":"मिशिगन CDL के लिए अपने ड्राइविंग के प्रकार को स्व-प्रमाणित (self-certify) करते समय, आवेदक को कितनी संघीय श्रेणियों में से चुनना होता है?","options":["दो","पाँच","तीन","चार"],"explanation":"प्रत्येक मिशिगन CDL आवेदक को चार श्रेणियों में से किसी एक को स्व-प्रमाणित करना होगा: non-excepted interstate, excepted interstate, non-excepted intrastate, या excepted intrastate। स्रोत: मिशिगन CDL स्व-प्रमाणन फॉर्म (SOS); 49 CFR 383.71।"},"86":{"q":"कौन सी स्व-प्रमाणन श्रेणी के लिए मिशिगन चालक को संघीय DOT चिकित्सा परीक्षक प्रमाणपत्र बनाए रखना आवश्यक है?","options":["किसी भी श्रेणी के लिए चिकित्सा प्रमाणपत्र आवश्यक नहीं है","Non-excepted interstate","Excepted intrastate","Excepted interstate"],"explanation":"'Non-excepted interstate' के रूप में स्व-प्रमाणित करने वाला चालक अंतरराज्यीय वाणिज्य में संचालन करता है और उसे एक वैध DOT चिकित्सा परीक्षक प्रमाणपत्र बनाए रखना होगा; इसी कारण से 'excepted' श्रेणियों के लिए इसकी आवश्यकता नहीं होती। स्रोत: मिशिगन CDL स्व-प्रमाणन फॉर्म (SOS); 49 CFR 383.71/391।"},"87":{"q":"जब कोई मिशिगन चालक 'excepted intrastate' के रूप में स्व-प्रमाणित करता है तो उसका क्या अर्थ होता है?","options":["वे राज्य की सीमाओं के पार ड्राइव करते हैं लेकिन सभी संघीय नियमों से छूट प्राप्त हैं","वे केवल मिशिगन के भीतर ड्राइव करते हैं लेकिन उन्हें एक संघीय चिकित्सा कार्ड रखना होगा","वे केवल मिशिगन के भीतर उन संचालनों में ड्राइव करते हैं जिन्हें राज्य ने चिकित्सा प्रमाणन आवश्यकताओं से छूट दी है","वे अंतरराज्यीय ड्राइव करते हैं और उन्हें अपना चिकित्सा कार्ड SOS के पास फाइल पर रखना होगा"],"explanation":"'Excepted intrastate' का अर्थ है कि चालक केवल मिशिगन के भीतर उन गतिविधियों में CMV संचालित करता है जिन्हें राज्य ने चिकित्सा प्रमाणन आवश्यकता से छूट दिया है, इसलिए संघीय चिकित्सा कार्ड आवश्यक नहीं है। स्रोत: मिशिगन CDL स्व-प्रमाणन फॉर्म (SOS); 49 CFR 383.71।"},"88":{"q":"केवल मिशिगन के भीतर (intrastate) वाणिज्यिक मोटर वाहन चलाने के लिए CDL जारी किए जाने हेतु न्यूनतम आयु क्या है?","options":["21 वर्ष","19 वर्ष","18 वर्ष","16 वर्ष"],"explanation":"intrastate (केवल मिशिगन) वाणिज्यिक ड्राइविंग के लिए CDL रखने हेतु आवेदक की आयु कम से कम 18 वर्ष होनी चाहिए; अंतरराज्यीय संचालन के लिए आमतौर पर 21 वर्ष की आयु आवश्यक होती है। स्रोत: मिशिगन CDL मैनुअल (SOS); MCL 257.312e।"},"89":{"q":"मिशिगन CDL ज्ञान परीक्षणों पर, वाहन वर्ग की परवाह किए बिना हर CDL आवेदक को कौन सा परीक्षण पास करना होगा?","options":["सामान्य ज्ञान परीक्षण","यात्री परिवहन परीक्षण","खतरनाक सामग्री परीक्षण","डबल्स/ट्रिपल्स परीक्षण"],"explanation":"सभी CDL आवेदकों को सामान्य ज्ञान परीक्षण पास करना होगा; अतिरिक्त ज्ञान परीक्षण (जैसे, एयर ब्रेक, संयोजन, एंडोर्समेंट) मांगे गए वर्ग और एंडोर्समेंट पर निर्भर करते हैं। स्रोत: मिशिगन CDL मैनुअल (SOS); 49 CFR 383.23।"},"90":{"q":"सेक्रेटरी ऑफ स्टेट कार्यालय में मिशिगन CDL नवीनीकरण पर, इनमें से कौन सी मानक प्रक्रिया का हिस्सा है?","options":["सभी नवीनीकरणों के लिए अनिवार्य लिखित खतरनाक सामग्री परीक्षण","एक दृष्टि जाँच और आवेदक के राज्य और राष्ट्रीय ड्राइविंग रिकॉर्ड की समीक्षा","SOS कर्मचारियों द्वारा किया गया एक स्वचालित नया DOT शारीरिक परीक्षण","हर चक्र में पूरा तीन-भाग वाला कौशल परीक्षण फिर से देना"],"explanation":"नवीनीकरण पर SOS कार्यालय एक दृष्टि परीक्षण करता है और आवेदक के राज्य तथा राष्ट्रीय (CDLIS) ड्राइविंग रिकॉर्ड की जाँच करता है; पूरा कौशल पुनः परीक्षण आमतौर पर आवश्यक नहीं होता। ध्यान दें: सटीक शुल्क बदल सकते हैं। स्रोत: मिशिगन CDL मैनुअल (SOS); michigan.gov SOS CDL नवीनीकरण पृष्ठ।"}},"ar":{"0":{"q":"على الطرق السريعة المخصصة في ميشيغان، ما هو الحد الأقصى القانوني لعرض المركبة التجارية (باستثناء المرايا وبعض معدات السلامة) قبل أن يصبح تصريح الحجم الزائد مطلوباً؟","options":["108 بوصة (9 أقدام)","96 بوصة (8 أقدام)","120 بوصة (10 أقدام)","102 بوصة (8 أقدام و6 بوصات)"],"explanation":"تحدد ميشيغان عرض المركبة بـ 102 بوصة (8'6\") على الطرق السريعة المخصصة و96 بوصة (8') على الطرق الأخرى، بما يتوافق مع المعيار الفيدرالي للشبكة الوطنية. المصدر: قانون مركبات ميشيغان MCL 257.717؛ MDOT 'Maximum Legal Truck Loadings and Dimensions' (T-1)."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة وحمولتها على الطرق السريعة في ميشيغان دون تصريح نقل خاص؟","options":["14 قدماً و0 بوصة","13 قدماً و6 بوصات","14 قدماً و6 بوصات","13 قدماً و0 بوصة"],"explanation":"تحدد ميشيغان الحد الأقصى لارتفاع المركبة والحمولة بـ 13 قدماً و6 بوصات؛ وأي ارتفاع أكبر يتطلب تصريح حجم زائد. المصدر: MCL 257.718؛ MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"2":{"q":"ما هو الحد الأقصى لطول المقطورة النصفية (بما في ذلك الحمولة) التي تُشغَّل على الطرق السريعة المخصصة في ميشيغان دون تصريح؟","options":["60 قدماً","48 قدماً","53 قدماً","57 قدماً"],"explanation":"تسمح ميشيغان بمقطورة نصفية يصل طولها إلى 53 قدماً، بما في ذلك الحمولة، على الطرق السريعة المخصصة (50 قدماً على الطرق غير المخصصة). المصدر: MCL 257.719؛ MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"3":{"q":"بموجب الحدود الفيدرالية التي تطبقها ميشيغان على نظام الطرق السريعة بين الولايات، ما هو الحد الأقصى للوزن الإجمالي للمركبة بالنسبة لتركيبة قياسية من 5 محاور دون تصريح؟","options":["88,000 رطل","76,000 رطل","73,280 رطلاً","80,000 رطل"],"explanation":"على نظام الطرق السريعة بين الولايات، تطبّق ميشيغان السقف الفيدرالي البالغ 80,000 رطل كوزن إجمالي للمركبات الخاضعة للمعادلة الفيدرالية للجسور. المصدر: 23 CFR 658.17 كما تُطبَّق في ميشيغان؛ إرشادات MDOT بشأن أوزان الشاحنات."},"4":{"q":"ما هو الحد الفيدرالي لوزن المحور الواحد الذي ينطبق على المركبات العاملة بموجب المعيار الفيدرالي البالغ 80,000 رطل على الطرق السريعة بين الولايات في ميشيغان؟","options":["24,000 رطل","22,400 رطل","18,000 رطل","20,000 رطل"],"explanation":"بالنسبة للمركبات الخاضعة للمعيار الفيدرالي البالغ 80,000 رطل، يبلغ حد المحور الواحد 20,000 رطل، وهو الرقم نفسه الذي تطبقه ميشيغان على الطرق السريعة بين الولايات. المصدر: 23 CFR 658.17 كما تُطبَّق في ميشيغان؛ إرشادات MDOT بشأن الأوزان."},"5":{"q":"بموجب المعيار الفيدرالي المطبَّق على نظام الطرق السريعة بين الولايات في ميشيغان، ما هو الحد الأقصى للوزن المسموح به على مجموعة المحاور المزدوجة (الترادفية)؟","options":["36,000 رطل","40,000 رطل","32,000 رطل","34,000 رطل"],"explanation":"حد المحور المزدوج الفيدرالي الذي تطبقه ميشيغان على الطرق السريعة بين الولايات هو 34,000 رطل. لاحظ أن قواعد المحاور في قانون ميشيغان الخاص تختلف (انظر الحد الأقصى الطبيعي للمحور البالغ 18,000 رطل). المصدر: 23 CFR 658.17؛ إرشادات MDOT بشأن الأوزان."},"6":{"q":"بسبب قواعد حمولة المحاور التي تسبق الحدود الفيدرالية، ما هو الحد الأقصى للوزن الإجمالي للمركبة الذي يمكن لشاحنة مهيأة بشكل صحيح أن تحمله قانونياً على طرق ميشيغان خارج الطرق السريعة بين الولايات؟","options":["80,000 رطل","164,000 رطل","105,500 رطل","129,000 رطل"],"explanation":"يسمح قانون الأوزان الموروث في ميشيغان بوزن إجمالي أقصى يبلغ نحو 164,000 رطل عندما تتوافق حمولات المحاور والمسافات بينها، وهو الأعلى المسموح به اعتيادياً في أمريكا الشمالية. المصدر: MCL 257.722؛ وكالة مجلس النواب المالية في ميشيغان، 'Michigan's Truck-Weight Law.'"},"7":{"q":"ما هو الحد الأقصى لعدد المحاور المسموح به على تركيبة شاحنة ومقطورة في ميشيغان تعمل بموجب أحكام الوزن الثقيل في الولاية؟","options":["8 محاور","11 محوراً","9 محاور","13 محوراً"],"explanation":"منذ عام 1967، حدّدت ميشيغان هذه التركيبات بـ 11 محوراً، وهو ما ينتج عنه مع حدود كل محور الحد الأقصى البالغ نحو 164,000 رطل. المصدر: MCL 257.722؛ تحليل وكالة مجلس النواب المالية في ميشيغان لأوزان الشاحنات."},"8":{"q":"بموجب قانون حمولة المحاور الخاص بميشيغان، ما هو 'الحد الأقصى للتحميل الطبيعي' لمحور واحد يبعد 9 أقدام أو أكثر عن المحاور المجاورة؟","options":["16,000 رطل","18,000 رطل","20,000 رطل","22,400 رطل"],"explanation":"يحدد قانون ميشيغان الحد الأقصى الطبيعي لحمولة المحور الواحد بـ 18,000 رطل حيث تبلغ المسافة بين المحاور 9 أقدام أو أكثر، وهو أقل من الرقم الفيدرالي البالغ 20,000 رطل. المصدر: MCL 257.722(1)."},"9":{"q":"يحدّ قانون المحاور في ولاية ميشيغان الحمولة القصوى للعجلة بقيمة مرتبطة بعرض الإطار. ما هو هذا الحد؟","options":["500 رطل لكل بوصة من عرض الإطار","700 رطل لكل بوصة من عرض الإطار","600 رطل لكل بوصة من عرض الإطار","850 رطل لكل بوصة من عرض الإطار"],"explanation":"تحدّ ميشيغان حمولة العجلة بـ 700 رطل لكل بوصة من عرض الإطار، وهو معيار يوزّع الحمولات الثقيلة على مزيد من الإطارات والمحاور. المصدر: MCL 257.722(7)."},"10":{"q":"خلال فترة ذوبان الجليد الربيعي في ميشيغان (قانون الصقيع)، بأي نسبة مئوية تُخفَّض الحمولات القصوى للمحاور على الأرصفة الخرسانية؟","options":["25 بالمئة","35 بالمئة","10 بالمئة","50 بالمئة"],"explanation":"خلال أشهر مارس وأبريل ومايو، تخفّض ميشيغان الحمولات القصوى للمحاور بنسبة 25 بالمئة على الأرصفة الخرسانية (وبنسبة 35 بالمئة على الطرق الأخرى) لحماية أسرّة الطرق أثناء الذوبان. المصدر: MCL 257.722(8)."},"11":{"q":"خلال القيود الموسمية لقانون الصقيع في ميشيغان، بأي نسبة مئوية تُخفَّض حمولات المحاور على الطرق غير الخرسانية؟","options":["15 بالمئة","45 بالمئة","35 بالمئة","25 بالمئة"],"explanation":"على الطرق غير الخرسانية، تخفّض قيود الوزن الربيعية في ميشيغان الحمولات القصوى للمحاور بنسبة 35 بالمئة خلال فترة الذوبان من مارس إلى مايو. المصدر: MCL 257.722(8)."},"12":{"q":"في أي أشهر يُطبَّق عادةً تخفيض الوزن الموسمي (قانون الصقيع) في ميشيغان؟","options":["مارس وأبريل ومايو","يناير وفبراير ومارس","نوفمبر وديسمبر ويناير","أبريل ومايو ويونيو"],"explanation":"تُطبَّق تخفيضات حمولة المحاور الموسمية في ميشيغان خلال ذوبان الجليد الربيعي، وهي مرتبطة قانونياً بأشهر مارس وأبريل ومايو، مع إعلان MDOT تواريخ البدء/الانتهاء الدقيقة كل عام. المصدر: MCL 257.722(8)؛ إشعارات MDOT بقيود الوزن الموسمية."},"13":{"q":"يسمح قانون ميشيغان بأن تمتد الحمولة على تركيبة من المركبات إلى أي مسافة خلف مؤخرة المركبة قبل أن يصبح التحذير الإضافي مطلوباً؟","options":["2 قدم","3 أقدام","4 أقدام","6 أقدام"],"explanation":"يجوز أن تبرز الحمولة حتى 4 أقدام خلف المؤخرة (و3 أقدام أمام المقدمة)؛ ويتطلب بروز المؤخرة بمقدار 4 أقدام أو أكثر علماً أحمر نهاراً وضوءاً أحمر ليلاً. المصدر: MCL 257.719؛ إرشادات MDOT بشأن أبعاد التحميل."},"14":{"q":"يجب أن تعرض الحمولة الممتدة خلف مؤخرة مركبة تجارية في ميشيغان ضوءاً أحمر أو فانوساً ليلاً عندما يبلغ البروز أي طول؟","options":["8 أقدام","2 قدم","4 أقدام","6 أقدام"],"explanation":"تشترط ميشيغان علماً أحمر في ضوء النهار وضوءاً أحمر أو فانوساً ليلاً لأي حمولة تبرز 4 أقدام أو أكثر خلف مؤخرة المركبة. المصدر: MCL 257.719؛ إرشادات MDOT بشأن أبعاد التحميل."},"15":{"q":"من يصدر تصاريح النقل ذات الحجم الزائد/الوزن الزائد للسفر على الطرق السريعة الرئيسية التابعة للولاية في ميشيغان؟","options":["الإدارة الفيدرالية لسلامة شركات النقل بالمركبات الآلية","شرطة ولاية ميشيغان فقط","وزارة النقل في ميشيغان (MDOT)","وزير الخارجية في ميشيغان (Michigan Secretary of State)"],"explanation":"تصدر MDOT تصاريح الحجم أو الوزن الزائد على الطرق الرئيسية التابعة للولاية، بينما تتولى وكالات الطرق المحلية الطرق الخاضعة لولايتها القضائية. المصدر: MCL 257.725؛ MDOT Oversize/Overweight Permits."},"16":{"q":"من خلال أي نظام إلكتروني تتقدم شركة النقل بطلب الحصول على تصريح الحجم الزائد/الوزن الزائد من MDOT في ميشيغان؟","options":["CDLIS (نظام معلومات رخص القيادة التجارية)","IRP (بوابة خطة التسجيل الدولية)","SAFER (السجلات الإلكترونية للسلامة واللياقة)","MiTRIP (نظام توجيه النقل والتصاريح عبر الإنترنت في ميشيغان)"],"explanation":"تحصل شركات النقل في ميشيغان على تصاريح النقل إلكترونياً من خلال MiTRIP، وهو نظام MDOT للتوجيه وإصدار التصاريح عبر الإنترنت. المصدر: MDOT Oversize/Overweight Permits؛ MCL 257.725."},"17":{"q":"يُصدَر تصريح الحجم الزائد لرحلة واحدة في ميشيغان عموماً للنقل العَرَضي لحمولة:","options":["يجري نقلها بالكامل على ملكية خاصة","لا يمكن تفكيكها أو إعادة ترتيبها للوصول إلى الحدود القانونية","تفضل شركة النقل ببساطة عدم تجزئتها إلى حمولات أصغر","تتجاوز الحدود القانونية بأقل من واحد بالمئة"],"explanation":"تُصدَر تصاريح ميشيغان فقط للنقل العَرَضي للحمولات ذات الحجم الزائد أو الوزن الزائد التي لا يمكن بشكل معقول تفكيكها أو تقليلها أو إعادة ترتيبها لتتوافق مع الحدود القانونية. المصدر: MCL 257.725؛ سياسة تصاريح MDOT."},"18":{"q":"بموجب حكم مركبات الغاز الطبيعي في ميشيغان، يجوز للمركبة التي تعمل بالغاز الطبيعي أن تتجاوز حدود الوزن المعمول بها بأي مقدار لمراعاة نظام الوقود الأثقل؟","options":["5,000 رطل","2,000 رطل","550 رطلاً","10,000 رطل"],"explanation":"تمنح ميشيغان مركبات الغاز الطبيعي بدلاً يصل إلى 2,000 رطل فوق حدود الوزن المعمول بها لتعويض الوزن المضاف لنظام الوقود. المصدر: قانون مركبات ميشيغان؛ إرشادات MDOT بشأن الأوزان بما يتوافق مع بدل مركبات الغاز الطبيعي الفيدرالي 23 U.S.C. 127."},"19":{"q":"بالنسبة لتركيبة في ميشيغان مثل جرّار شاحنة يسحب وحدتين مقطورتين، ما هو الحد الأقصى للطول الإجمالي (المقاس من مقدمة الوحدة المقطورة الأولى إلى مؤخرة الأخيرة) قبل أن يصبح التصريح مطلوباً؟","options":["75 قدماً","58 قدماً","65 قدماً","53 قدماً"],"explanation":"تسمح ميشيغان بهذه التركيبات المزدوجة دون طول إجمالي ثابت للمركبة طالما أن الوحدات المقطورة، مقاسةً من مقدمة الأولى إلى مؤخرة الأخيرة، لا تتجاوز 58 قدماً (وكل وحدة لا تزيد عن 28'6\"). المصدر: MCL 257.719؛ MDOT Maximum Legal Truck Loadings and Dimensions (T-1)."},"20":{"q":"في ميشيغان، أي مجموعة من رخصة القيادة التجارية CDL مطلوبة لتشغيل أي تركيبة من المركبات بتصنيف وزن إجمالي للتركيبة (GCWR) يبلغ 26,001 رطلاً أو أكثر، حيث يزيد تصنيف الوزن الإجمالي للمركبة (GVWR) للوحدة المقطورة عن 10,000 رطل؟","options":["المجموعة A","المجموعة B","المجموعة C","المجموعة D"],"explanation":"تعرّف ميشيغان رخصة CDL من المجموعة (الفئة) A بأنها أي تركيبة من المركبات بتصنيف GCWR يبلغ 26,001 رطلاً أو أكثر، شريطة أن يزيد تصنيف GVWR للوحدة (الوحدات) المقطورة عن 10,000 رطل. المصدر: دليل CDL في ميشيغان (Michigan SOS)، القسم 1."},"21":{"q":"بموجب قواعد ميشيغان، أي مجموعة من رخصة CDL تشمل مركبة واحدة بتصنيف وزن إجمالي للمركبة (GVWR) يبلغ 26,001 رطلاً أو أكثر (والتي يجوز أن تسحب وحدة بوزن 10,000 رطل أو أقل)؟","options":["المجموعة A","المجموعة B","المجموعة C","المجموعة H"],"explanation":"رخصة CDL من المجموعة (الفئة) B في ميشيغان مخصصة لأي مركبة واحدة بتصنيف GVWR يبلغ 26,001 رطلاً أو أكثر، أو مركبة كهذه تسحب وحدة لا يزيد تصنيف GVWR لها عن 10,000 رطل. المصدر: دليل CDL في ميشيغان (Michigan SOS)، القسم 1."},"22":{"q":"تُطلَب رخصة CDL من المجموعة (الفئة) C في ميشيغان لمركبة أصغر (دون حدود الوزن للفئة A/B) فقط عند استخدامها لنقل أي مما يلي؟","options":["أي حمولة يزيد وزنها عن 5,000 رطل","16 راكباً أو أكثر (بما في ذلك السائق)، أو مواد خطرة بكميات تتطلب لافتات","أي مقطورة بغض النظر عن الوزن","أطفال المدارس فقط"],"explanation":"تنطبق رخصة CDL من المجموعة C في ميشيغان على المركبات الأقل من حدود وزن الفئة A/B والمصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق، أو التي تحمل مواد خطرة بكميات تتطلب لافتات. المصدر: دليل CDL في ميشيغان (Michigan SOS)، القسم 1."},"23":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في ميشيغان للقيادة داخل الولاية (التشغيل داخل ميشيغان فقط)؟","options":["16 عاماً","18 عاماً","21 عاماً","25 عاماً"],"explanation":"تسمح ميشيغان بالحصول على رخصة CDL في سن 18 عاماً للتجارة داخل الولاية فقط؛ أما التشغيل بين الولايات فيتطلب سن 21 عاماً. المصدر: دليل CDL في ميشيغان (Michigan SOS) / أهلية CDL لدى Michigan SOS."},"24":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في ميشيغان تسمح بالقيادة بين الولايات (عبر حدود الولايات)؟","options":["18 عاماً","19 عاماً","21 عاماً","23 عاماً"],"explanation":"تشترط القواعد الفيدرالية وقواعد ميشيغان أن يكون عمر السائق 21 عاماً على الأقل لتشغيل مركبة تجارية CMV في التجارة بين الولايات؛ ويقتصر السائقون من سن 18 إلى 20 عاماً على التشغيل داخل الولاية. المصدر: دليل CDL في ميشيغان (Michigan SOS)؛ 49 CFR 391.11."},"25":{"q":"في ميشيغان، كم من الوقت يجب أن يحتفظ مقدم الطلب بتصريح المتعلم التجاري (CLP) قبل السماح له بإجراء اختبار المهارات على الطريق لرخصة CDL؟","options":["7 أيام كحد أدنى","14 يوماً كحد أدنى","30 يوماً كحد أدنى","60 يوماً كحد أدنى"],"explanation":"تتبع ميشيغان القاعدة الفيدرالية التي تشترط الاحتفاظ بتصريح CLP لمدة 14 يوماً كحد أدنى قبل أن يتمكن مقدم الطلب من إجراء اختبار مهارات CDL. المصدر: Michigan SOS (cdl-apply)؛ 49 CFR 383.25."},"26":{"q":"أي تظهير مطلوب على رخصة CDL في ميشيغان لتشغيل مركبة مصممة لنقل 16 شخصاً أو أكثر، بما في ذلك السائق؟","options":["P (الركاب)","N (الصهريج)","T (المزدوجة/الثلاثية)","H (المواد الخطرة)"],"explanation":"تظهير P (الركاب) مطلوب في ميشيغان لتشغيل مركبة مصممة لنقل 16 شخصاً أو أكثر بما في ذلك السائق. المصدر: دليل CDL في ميشيغان (Michigan SOS)، قسم التظهيرات."},"27":{"q":"أي تظهير لرخصة CDL في ميشيغان مطلوب لقيادة مركبة تجارية تُستخدم لنقل طلاب المرحلة ما قبل الابتدائية أو الابتدائية أو الثانوية من المدرسة وإليها؟","options":["P (الركاب)","S (الحافلة المدرسية)","T (المزدوجة/الثلاثية)","C (الأطفال)"],"explanation":"تظهير S (الحافلة المدرسية) مطلوب في ميشيغان لقيادة حافلة مدرسية تنقل الطلاب؛ ويجب على مقدمي الطلبات أن يكونوا حاصلين بالفعل على تظهير P (أو يحصلوا عليه) واجتياز اختباري المعرفة والمهارات للحافلة المدرسية. المصدر: دليل CDL في ميشيغان (Michigan SOS)."},"28":{"q":"على رخصة CDL في ميشيغان، أي حرف رمز واحد يظهر عندما يُمنَح السائق كلاً من تظهير الصهريج (N) وتظهير المواد الخطرة (H)؟","options":["X","Z","HN","K"],"explanation":"تضع ميشيغان الرمز المدمج X على الرخصة بدلاً من رمزي N وH المنفصلين عندما يحمل السائق كلاً من تظهير الصهريج والمواد الخطرة. المصدر: دليل CDL في ميشيغان (Michigan SOS)، قسم التظهيرات."},"29":{"q":"يشمل تظهير T في ميشيغان تركيبات المقطورات المزدوجة والثلاثية. ومع ذلك، فيما يتعلق بالمقطورات الثلاثية على طرق ميشيغان، أي عبارة صحيحة؟","options":["تركيبات المقطورات الثلاثية غير مسموح بها في ميشيغان","المقطورات الثلاثية مسموح بها فقط على الطرق السريعة بين الولايات في ميشيغان","تتطلب المقطورات الثلاثية تصريح Class A-T منفصلاً في ميشيغان","المقطورات الثلاثية مسموح بها على مستوى الولاية في ميشيغان دون قيود"],"explanation":"على الرغم من وجود تظهير T (المزدوجة/الثلاثية)، فإن تركيبات المقطورات الثلاثية غير مسموح بها على طرق ميشيغان. المصدر: دليل CDL في ميشيغان (Michigan SOS)، قسم التظهيرات."},"30":{"q":"لأي تظهير يجب على مقدم طلب رخصة CDL في ميشيغان اجتياز تقييم تهديد أمني (Security Threat Assessment) من إدارة أمن النقل (TSA)، بما في ذلك بصمات الأصابع والتحقق من الخلفية؟","options":["N (الصهريج)","T (المزدوجة/الثلاثية)","H (المواد الخطرة)","P (الركاب)"],"explanation":"يتطلب تظهير H (المواد الخطرة) إجراء تقييم تهديد أمني من TSA مع بصمات الأصابع والتحقق من الخلفية، بالإضافة إلى اختبار معرفة المواد الخطرة HazMat. المصدر: معلومات CDL لدى Michigan SOS؛ TSA HME / 49 CFR 1572."},"31":{"q":"بموجب التعريفات الفيدرالية/الخاصة بميشيغان، يكون تظهير N (الصهريج) مطلوباً عموماً لنقل سائل أو غاز في صهريج بسعة فردية مقدّرة تزيد عن 119 غالوناً وسعة إجمالية مقدّرة لا تقل عن كم غالون؟","options":["500 غالون","1,000 غالون","1,500 غالون","3,000 غالون"],"explanation":"ينطبق تظهير الصهريج (N) على الصهاريج ذات السعة الفردية المقدّرة التي تزيد عن 119 غالوناً وسعة إجمالية مقدّرة تبلغ 1,000 غالون أو أكثر. المصدر: دليل CDL في ميشيغان (Michigan SOS)؛ 49 CFR 383.5."},"32":{"q":"كم مرة يجب على حامل رخصة CDL في ميشيغان تجديد تقييم التهديد الأمني من TSA للحفاظ على صلاحية تظهير المواد الخطرة (H)؟","options":["كل عام","كل 3 سنوات","كل 5 سنوات","كل 10 سنوات"],"explanation":"يجب تجديد تقييم التهديد الأمني من TSA لتظهير المواد الخطرة كل 5 سنوات، بما في ذلك بصمات أصابع وتحقق من الخلفية جديدان. المصدر: معلومات CDL لدى Michigan SOS؛ TSA HME (49 CFR 1572)."},"33":{"q":"اعتباراً من 7 فبراير 2022، يجب إكمال تدريب السائق المبتدئ (ELDT) قبل الاختبار لأي مما يلي في ميشيغان؟","options":["رخصة CDL من الفئة A أو الفئة B لأول مرة، أو الترقية من الفئة B إلى الفئة A، أو تظهير P أو S أو H لأول مرة","فقط رخصة CDL من الفئة A لأول مرة","أي تجديد لرخصة CDL","فقط تظهير الصهريج (N)"],"explanation":"يُطلَب تدريب ELDT الفيدرالي، المطبَّق في ميشيغان، للحصول على رخصة CDL من الفئة A أو الفئة B لأول مرة، والترقية من الفئة B إلى A، وتظهيرات الركاب (P) أو الحافلة المدرسية (S) أو المواد الخطرة (H) لأول مرة. المصدر: قاعدة FMCSA ELDT (49 CFR 380)؛ Michigan SOS."},"34":{"q":"يجب على مقدم طلب رخصة CDL في ميشيغان إكمال تدريب السائق المبتدئ المطلوب (ELDT) من خلال أي جهة؟","options":["أي مدرّب قيادة يختاره مقدم الطلب","مزوّد مُدرَج في سجل مزوّدي التدريب لدى FMCSA (TPR)","وزير الخارجية في ميشيغان (Michigan Secretary of State) مباشرة","أكاديمية شرطة ولاية ميشيغان"],"explanation":"يجب تقديم تدريب ELDT من قبل مدرسة أو جهة مُدرَجة في سجل مزوّدي التدريب لدى FMCSA (TPR)؛ ويُبلَّغ عن الإكمال إلكترونياً إلى FMCSA. المصدر: قاعدة FMCSA ELDT (49 CFR 380)؛ Michigan SOS."},"35":{"q":"أي تظهير لا يتطلب تدريب السائق المبتدئ (ELDT) عند الحصول عليه لأول مرة على رخصة CDL في ميشيغان؟","options":["H (المواد الخطرة)","P (الركاب)","S (الحافلة المدرسية)","N (الصهريج)"],"explanation":"تدريب ELDT إلزامي لتظهيرات H وP وS لأول مرة، لكن تظهير N (الصهريج) غير مشمول بقاعدة ELDT. المصدر: قاعدة FMCSA ELDT (49 CFR 380.603)؛ Michigan SOS."},"36":{"q":"أي مجموعة من المستندات يجب على مقدم طلب رخصة CDL في ميشيغان تقديمها في مكتب وزير الخارجية (Secretary of State) لإثبات الأهلية؟","options":["فقط صورة وبطاقة ائتمان","إثبات الهوية/الوجود القانوني، وإثبات رقم الضمان الاجتماعي، وإثبات الإقامة في ميشيغان","فقط رسالة من صاحب العمل","فقط صورة جواز سفر ودفع نقدي"],"explanation":"تشترط ميشيغان إثبات الهوية/الوجود القانوني في الولايات المتحدة، وإثبات رقم الضمان الاجتماعي، وإثبات الإقامة في ميشيغان لإصدار تصريح CLP أو رخصة CDL. المصدر: متطلبات مستندات CDL/الرخصة لدى Michigan SOS."},"37":{"q":"في إقرار التصنيف الذاتي لرخصة CDL في ميشيغان، يجب على السائق الذي يشغّل مركبة تجارية CMV عبر حدود الولايات وليس معفى من قواعد التأهيل البدني الفيدرالية أن يقرّ بأي فئة؟","options":["بين الولايات معفى (Excepted Interstate)","بين الولايات غير معفى (Non-excepted Interstate)","داخل الولاية معفى (Excepted Intrastate)","داخل الولاية غير معفى (Non-excepted Intrastate)"],"explanation":"تستخدم ميشيغان أربع فئات للتصنيف الذاتي؛ والسائق في التجارة بين الولايات الخاضع للقواعد الطبية يقرّ بفئة 'بين الولايات غير معفى' (Non-excepted Interstate) ويجب أن يحتفظ بشهادة فاحص طبي سارية. المصدر: نموذج التصنيف الذاتي لرخصة CDL لدى Michigan SOS."},"38":{"q":"أي فئة من فئات التصنيف الذاتي لرخصة CDL في ميشيغان تتطلب من السائق الاحتفاظ بشهادة فاحص طبي سارية (بطاقة طبية DOT) وتقديمها إلى وزير الخارجية (Secretary of State)؟","options":["بين الولايات معفى (Excepted Interstate)","داخل الولاية معفى (Excepted Intrastate)","بين الولايات غير معفى (Non-excepted Interstate)","أي سائق دون سن 21 عاماً"],"explanation":"من بين الفئات الأربع، تتطلب الفئتان 'غير المعفاتين' شهادة فاحص طبي سارية؛ ويجب على السائق بين الولايات غير المعفى الاحتفاظ ببطاقة طبية DOT حالية مودَعة لدى Michigan SOS. المصدر: التصنيف الذاتي لرخصة CDL لدى Michigan SOS (BFS-103)."},"39":{"q":"يجب على مقدم الطلب في ميشيغان تحقيق درجة لا تقل عن كم في تقييم نظرية (معرفة) ELDT للوفاء بمتطلب التدريب قبل اختبار معرفة CDL؟","options":["70%","75%","80%","90%"],"explanation":"يتطلب تدريب ELDT الفيدرالي، المطبَّق في ميشيغان، درجة دنيا في التقييم النظري قدرها 80% من مزوّد مُدرَج في سجل مزوّدي التدريب. المصدر: قاعدة FMCSA ELDT (49 CFR 380.609)؛ Michigan SOS."},"40":{"q":"عند أي تركيز للكحول في الدم (BAC) أو أعلى منه يُمنَع حامل رخصة CDL من تشغيل مركبة تجارية في ميشيغان؟","options":["0.08","0.04","0.02","0.10"],"explanation":"يُعَد تشغيل مركبة تجارية CMV بتركيز كحول في الدم BAC قدره 0.04 أو أكثر مخالفة كبرى في ميشيغان. وهذا نصف حد 0.08 المطبَّق على السائقين العاديين. المصدر: دليل CDL في ميشيغان (قسم الكحول/إسقاط الأهلية)؛ 49 CFR 383.51 Table 1."},"41":{"q":"بالنسبة للمخالفة الكبرى الأولى (مثل تشغيل مركبة تجارية CMV بتركيز كحول في الدم BAC قدره 0.04 أو أكثر)، كم تبلغ مدة إسقاط أهلية CDL في ميشيغان عندما لا تكون هناك مواد خطرة معنية؟","options":["60 يوماً","6 أشهر","سنة واحدة","3 سنوات"],"explanation":"تؤدي المخالفة الكبرى الأولى إلى إسقاط أهلية CDL لمدة سنة واحدة في ميشيغان. المصدر: 49 CFR 383.51 Table 1، المعتمد في ميشيغان عبر قانون مركبات ميشيغان (MCL 257.319b)؛ دليل CDL في ميشيغان."},"42":{"q":"كم تبلغ مدة إسقاط أهلية CDL بالنسبة للمخالفة الكبرى الأولى إذا كان السائق يشغّل مركبة يُشترَط وضع لافتات عليها للمواد الخطرة؟","options":["سنة واحدة","18 شهراً","3 سنوات","5 سنوات"],"explanation":"تؤدي المخالفة الكبرى الأولى المرتكبة أثناء تشغيل مركبة مواد خطرة موضوعة عليها لافتات إلى إسقاط الأهلية لمدة 3 سنوات، بدلاً من السنة الواحدة المعتادة. المصدر: 49 CFR 383.51 Table 1؛ دليل CDL في ميشيغان."},"43":{"q":"ما هي مدة إسقاط أهلية CDL بالنسبة للمخالفة الكبرى الثانية (على سبيل المثال، إدانة ثانية متعلقة بالكحول) في ميشيغان؟","options":["3 سنوات","5 سنوات","10 سنوات","مدى الحياة"],"explanation":"تؤدي المخالفة الكبرى الثانية إلى إسقاط أهلية CDL مدى الحياة في ميشيغان. المصدر: 49 CFR 383.51 Table 1؛ دليل CDL في ميشيغان؛ MCL 257.319b."},"44":{"q":"بموجب قانون الموافقة الضمنية في ميشيغان، يُسقَط حق حامل رخصة CDL الذي يرفض اختباراً كيميائياً (للكحول) مطلوباً قانونياً لأول مرة في تشغيل مركبة تجارية لأي مدة؟","options":["90 يوماً","سنة واحدة","3 سنوات","مدى الحياة"],"explanation":"يُعامَل أول رفض للخضوع لاختبار كحول مطلوب معاملة المخالفة الكبرى ويؤدي إلى إسقاط أهلية CDL لمدة سنة واحدة، سواء كان السائق في مركبة تجارية CMV أو مركبة شخصية. المصدر: قانون الموافقة الضمنية في ميشيغان (MCL 257.625c)؛ 49 CFR 383.51 Table 1."},"45":{"q":"أي مما يلي يُصنَّف على أنه 'مخالفة مرورية خطيرة' لأغراض رخصة CDL في ميشيغان؟","options":["تشغيل مركبة تجارية CMV بتركيز كحول في الدم BAC قدره 0.04 أو أكثر","تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد المقرر","مغادرة موقع حادث يتضمن مركبة تجارية CMV","رفض اختبار كيميائي"],"explanation":"تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد المقرر هو مخالفة مرورية خطيرة. أما الخيارات الأخرى فهي مخالفات كبرى، وليست مخالفات خطيرة. المصدر: 49 CFR 383.51 Table 2؛ دليل CDL في ميشيغان."},"46":{"q":"أُدين حامل رخصة CDL بمخالفتين مروريتين خطيرتين نشأتا عن حادثتين منفصلتين خلال فترة 3 سنوات. ما هي مدة إسقاط الأهلية في ميشيغان؟","options":["30 يوماً","60 يوماً","120 يوماً","سنة واحدة"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان في حادثتين منفصلتين خلال 3 سنوات إلى إسقاط أهلية CDL لمدة 60 يوماً. المصدر: 49 CFR 383.51 Table 2؛ دليل CDL في ميشيغان."},"47":{"q":"أُدين حامل رخصة CDL بثلاث مخالفات مرورية خطيرة من حوادث منفصلة خلال فترة 3 سنوات. ما هي مدة إسقاط الأهلية؟","options":["60 يوماً","90 يوماً","120 يوماً","سنة واحدة"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة أو أكثر في حوادث منفصلة خلال 3 سنوات إلى إسقاط أهلية CDL لمدة 120 يوماً. المصدر: 49 CFR 383.51 Table 2؛ دليل CDL في ميشيغان."},"48":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة 3 سنوات التي يجب أن يراكمها حامل رخصة CDL قبل أن يبدأ أي إسقاط للأهلية؟","options":["واحدة","اثنتان","ثلاث","أربع"],"explanation":"لا تؤدي مخالفة مرورية خطيرة واحدة إلى إسقاط الأهلية؛ بل ينطبق أول إسقاط للأهلية (60 يوماً) عند الإدانة الثانية خلال 3 سنوات. المصدر: 49 CFR 383.51 Table 2؛ دليل CDL في ميشيغان."},"49":{"q":"أي مخالفة، تُرتكَب في مركبة تجارية، تُعَد مخالفة مرورية خطيرة محددة يمكن أن تُحتسَب ضمن إسقاط الأهلية لمدة 60/120 يوماً في ميشيغان؟","options":["الرسائل النصية أثناء قيادة المركبة التجارية CMV","التشغيل بتركيز كحول في الدم BAC قدره 0.04 أو أكثر","استخدام مركبة تجارية CMV لارتكاب جناية","انتهاك أمر إخراج من الخدمة (out-of-service order)"],"explanation":"تُدرَج الرسائل النصية أثناء قيادة مركبة تجارية CMV كمخالفة مرورية خطيرة. أما تركيز BAC قدره 0.04 أو أكثر واستخدام مركبة تجارية CMV في جناية فهما مخالفتان كبريان، ولانتهاك أمر الإخراج من الخدمة جدول عقوبات منفصل خاص به. المصدر: 49 CFR 383.51 Table 2؛ دليل CDL في ميشيغان."},"50":{"q":"يُسقَط حق السائق المُدان بأول مخالفة لمعبر سكة حديد مع الطريق السريع في مركبة تجارية CMV في ميشيغان لمدة لا تقل عن كم؟","options":["30 يوماً","60 يوماً","120 يوماً","سنة واحدة"],"explanation":"تحمل أول مخالفة لمعبر سكة حديد مع الطريق السريع إسقاطاً للأهلية لا يقل عن 60 يوماً. المصدر: 49 CFR 383.51 Table 3؛ دليل CDL في ميشيغان."},"51":{"q":"ما هو الحد الأدنى لإسقاط أهلية CDL بالنسبة لمخالفة ثانية لمعبر سكة حديد مع الطريق السريع خلال فترة 3 سنوات؟","options":["60 يوماً","90 يوماً","120 يوماً","سنة واحدة"],"explanation":"تحمل المخالفة الثانية لمعبر سكة حديد مع الطريق السريع خلال 3 سنوات إسقاطاً للأهلية لا يقل عن 120 يوماً. المصدر: 49 CFR 383.51 Table 3؛ دليل CDL في ميشيغان."},"52":{"q":"ما هو الحد الأدنى لإسقاط الأهلية بالنسبة لمخالفة ثالثة لمعبر سكة حديد مع الطريق السريع خلال فترة 3 سنوات؟","options":["120 يوماً","180 يوماً","سنة واحدة","3 سنوات"],"explanation":"تحمل المخالفة الثالثة أو اللاحقة لمعبر سكة حديد مع الطريق السريع خلال 3 سنوات إسقاطاً للأهلية لا يقل عن سنة واحدة. المصدر: 49 CFR 383.51 Table 3؛ دليل CDL في ميشيغان."},"53":{"q":"ما هي مدة إسقاط الأهلية بالنسبة لأول إدانة بانتهاك أمر إخراج سائق أو مركبة من الخدمة (out-of-service order) أثناء تشغيل مركبة تجارية CMV (دون مواد خطرة، دون ركاب)؟","options":["لا تقل عن 30 يوماً","لا تقل عن 90 يوماً ولا تزيد عن سنة واحدة","لا تقل عن 180 يوماً ولا تزيد عن سنة واحدة","لا تقل عن سنة واحدة ولا تزيد عن 5 سنوات"],"explanation":"يؤدي أول انتهاك لأمر الإخراج من الخدمة إلى إسقاط الأهلية لمدة لا تقل عن 180 يوماً ولا تزيد عن سنة واحدة. المصدر: 49 CFR 383.51 Table 4؛ دليل CDL في ميشيغان."},"54":{"q":"ما هو نطاق إسقاط الأهلية بالنسبة لانتهاك ثانٍ لأمر الإخراج من الخدمة في حوادث منفصلة خلال فترة 10 سنوات؟","options":["لا تقل عن 180 يوماً ولا تزيد عن سنة واحدة","لا تقل عن سنة واحدة ولا تزيد عن 3 سنوات","لا تقل عن سنتين ولا تزيد عن 5 سنوات","لا تقل عن 3 سنوات ولا تزيد عن 5 سنوات"],"explanation":"يؤدي انتهاك ثانٍ لأمر الإخراج من الخدمة خلال 10 سنوات إلى إسقاط الأهلية لمدة لا تقل عن سنتين ولا تزيد عن 5 سنوات. المصدر: 49 CFR 383.51 Table 4؛ دليل CDL في ميشيغان."},"55":{"q":"ينتهك سائق أمر الإخراج من الخدمة لأول مرة أثناء نقل مواد خطرة موضوعة عليها لافتات أو أثناء حمل 16 راكباً أو أكثر. ما هو نطاق إسقاط الأهلية؟","options":["لا تقل عن 90 يوماً ولا تزيد عن سنة واحدة","لا تقل عن 180 يوماً ولا تزيد عن سنتين","لا تقل عن سنة واحدة ولا تزيد عن 3 سنوات","لا تقل عن 3 سنوات ولا تزيد عن 5 سنوات"],"explanation":"يؤدي أول انتهاك لأمر الإخراج من الخدمة أثناء نقل مواد خطرة موضوعة عليها لافتات أو حمل 16 راكباً أو أكثر إلى إسقاط الأهلية لمدة لا تقل عن 180 يوماً ولا تزيد عن سنتين. المصدر: 49 CFR 383.51 Table 4؛ دليل CDL في ميشيغان."},"56":{"q":"بموجب القواعد الفيدرالية المعتمدة في ميشيغان، ما هي الغرامة المدنية القصوى التي قد يواجهها سائق مركبة تجارية CMV لاستخدام هاتف محمول يدوي أو إرسال رسائل نصية أثناء القيادة؟","options":["$500","$1,000","$2,750","$11,000"],"explanation":"قد يُغرَّم السائق حتى $2,750 لمخالفة استخدام هاتف يدوي أو إرسال رسائل نصية؛ وقد يُغرَّم صاحب العمل الذي يسمح بذلك أو يشترطه حتى $11,000. المصدر: 49 CFR 392.80/392.82 وصحيفة وقائع قاعدة FMCSA لحظر الرسائل النصية/الهاتف اليدوي؛ دليل CDL في ميشيغان."},"57":{"q":"يُكتشَف لدى سائق مركبة تجارية CMV أي كحول مقاس أو مكتشَف أثناء أداء الواجب، أو استخدم كحولاً أو حازه خلال 4 ساعات قبل بدء الواجب. ما هي العاقبة الفورية؟","options":["إسقاط فوري لأهلية CDL لمدة سنة واحدة","الإخراج من الخدمة لمدة 24 ساعة","الإخراج من الخدمة لمدة 7 أيام","إسقاط فوري للأهلية مدى الحياة"],"explanation":"بموجب حظر الكحول، يجب إخراج هذا السائق من الخدمة لمدة 24 ساعة. وهذا منفصل عن عتبة المخالفة الكبرى البالغة 0.04. المصدر: 49 CFR 392.5؛ دليل CDL في ميشيغان."},"58":{"q":"أُدين حامل رخصة CDL بمخالفة قيادة متعلقة بالكحول أثناء قيادة مركبته الشخصية (غير التجارية). كيف يؤثر ذلك على رخصة CDL في ميشيغان؟","options":["ليس له أي تأثير لأنه لم تكن هناك مركبة تجارية CMV معنية","يؤدي إلى إسقاط أهلية CDL لمدة سنة واحدة","يؤدي فقط إلى إسقاط الأهلية لمدة 60 يوماً","يؤدي فقط إلى نقاط، وليس إسقاط الأهلية"],"explanation":"تؤدي المخالفات الكبرى، بما في ذلك مخالفات الكحول، إلى إسقاط أهلية CDL حتى عندما تُرتكَب في مركبة شخصية؛ وأول مخالفة من هذا القبيل تؤدي إلى إسقاط الأهلية لمدة سنة واحدة. المصدر: 49 CFR 383.51 Table 1؛ دليل CDL في ميشيغان."},"59":{"q":"يُسجِّل سائق مركبة تجارية CMV تركيز كحول في الدم BAC قدره 0.02 أو أكثر ولكن أقل من 0.04. أي عبارة تصف بشكل أفضل العاقبة بموجب القواعد المطبَّقة في ميشيغان؟","options":["يُعامَل كمخالفة كبرى مع إسقاط الأهلية لمدة سنة واحدة","لا توجد عاقبة دون 0.04","لا يجوز للسائق أداء الوظائف الحساسة للسلامة لمدة 24 ساعة","هو انتهاك تلقائي لأمر الإخراج من الخدمة"],"explanation":"يمنع تركيز الكحول المؤكَّد البالغ 0.02 أو أكثر ولكن أقل من 0.04 السائقَ من أداء الوظائف الحساسة للسلامة لمدة 24 ساعة؛ وتبدأ المخالفة الكبرى المُسقِطة للأهلية عند 0.04. المصدر: 49 CFR 382.505 و383.51؛ دليل CDL في ميشيغان."},"60":{"q":"بموجب قانون \"التزحزح جانباً\" (Move Over) في ميشيغان، عند الاقتراب من مركبة طوارئ متوقفة وأضواؤها مُفعَّلة ولا يمكنك الانتقال إلى مسار آخر بأمان، بكم يجب أن تخفض سرعتك دون حد السرعة المعلن؟","options":["بما لا يقل عن 10 mph دون حد السرعة المعلن","بما لا يقل عن 5 mph دون حد السرعة المعلن","بما لا يقل عن 15 mph دون حد السرعة المعلن","بما لا يقل عن 20 mph دون حد السرعة المعلن"],"explanation":"يقتضي قانون \"التزحزح جانباً\" في ميشيغان (MCL 257.653a) من السائق الذي يقترب من مركبة طوارئ مرخّصة متوقفة وأضواؤها مُفعَّلة أن يتزحزح بمقدار مسار واحد على الأقل، أو إذا تعذّر ذلك، أن يخفض سرعته إلى ما لا يقل عن 10 mph دون حد السرعة المعلن وأن يتجاوزها بعناية واجبة. المصدر: MCL 257.653a؛ حملة \"التزحزح جانباً\" التابعة لشرطة ولاية ميشيغان."},"61":{"q":"على طريق في ميشيغان به مساران أو أكثر للسير في اتجاه واحد، أين يجوز قيادة شاحنة يزيد وزنها الإجمالي عن 10,000 رطل، أو جرّار شاحنة، أو مركبة مركّبة؟","options":["فقط في أيٍّ من المسارين الأقصى إلى اليمين","في أي مسار، مثلها مثل سيارات الركاب","فقط في المسار الأقصى الوحيد إلى اليمين في جميع الأوقات","فقط في المسار الأوسط لتجنّب حركة المرور المندمجة"],"explanation":"يقتضي قانون ميشيغان (MCL 257.634) أنه على طريق به مساران أو أكثر في اتجاه واحد، يجب ألّا تُقاد الشاحنة التي يزيد وزنها عن 10,000 رطل، أو جرّار الشاحنة، أو مركبة-ومقطورة مركّبة إلا في أحد المسارين الأقصى إلى اليمين. المصدر: MCL 257.634."},"62":{"q":"على طريق سريع في ميشيغان محدود الوصول حيث يزيد حد السرعة المعلن عن 65 mph، ما هي السرعة القصوى لشاحنة يبلغ وزنها الإجمالي 10,000 رطل أو أكثر؟","options":["65 mph","60 mph","70 mph","55 mph"],"explanation":"بموجب MCL 257.627، حيثما يتجاوز الحد المعلن 65 mph، لا يجوز لشاحنة وزنها 10,000 رطل أو أكثر، أو جرّار شاحنة أو مركبة مركّبة، أو حافلة مدرسية أن تتجاوز 65 mph على طريق سريع محدود الوصول أو طريق رئيسي تابع للولاية. وهذا يعكس التغيير الذي أحدثه القانون العام رقم 445 لعام 2016. المصدر: MCL 257.627."},"63":{"q":"في ميشيغان، على أي مسافة من أقرب قضيب سكة حديد يجب على سائق مركبة محمّلة بمواد خطرة وتحمل لوحات تحذيرية أن يتوقف قبل عبور مزلقان سكة حديد على مستوى الأرض؟","options":["في حدود 50 قدماً ولكن ليس أقل من 15 قدماً","في حدود 100 قدم ولكن ليس أقل من 25 قدماً","في حدود 40 قدماً ولكن ليس أقل من 10 أقدام","في حدود 75 قدماً ولكن ليس أقل من 20 قدماً"],"explanation":"يقتضي MCL 257.669 من سائقي المركبات التي تحمل لوحات تحذيرية (والمركبات التي تنقل 16 راكباً أو أكثر أو ركاباً مقابل أجر) تفعيل أضواء الخطر والتوقف في حدود 50 قدماً ولكن ليس أقل من 15 قدماً من أقرب قضيب قبل العبور. المصدر: MCL 257.669؛ دليل CDL لميشيغان القسم 9."},"64":{"q":"في ميشيغان، يجب على مركبة تلتقي بحافلة مدرسية أو تتجاوزها وهي متوقفة وتُظهر ضوءين أحمرين متناوبين الوميض أن تتوقف توقفاً تاماً على أي مسافة دنيا من الحافلة؟","options":["بما لا يقل عن 20 قدماً","بما لا يقل عن 10 أقدام","بما لا يقل عن 15 قدماً","بما لا يقل عن 30 قدماً"],"explanation":"يقتضي MCL 257.682 من السائق الذي يتجاوز أو يلتقي بحافلة مدرسية تُظهر أضواءً حمراء وامضة أن يتوقف على بُعد لا يقل عن 20 قدماً من الحافلة وألّا يمضي حتى تتحرك الحافلة أو تُطفأ الإشارات. المصدر: MCL 257.682."},"65":{"q":"في ميشيغان، على طريق سريع مقسوم إلى طريقين بمساحة فاصلة مرتفعة أو حاجز مادي، أي السائقين غير مُلزَمين بالتوقف لحافلة مدرسية تُظهر أضواءً حمراء وامضة على الجانب المقابل؟","options":["السائقون الذين يلتقون بالحافلة من الطريق المقابل عبر الحاجز","يجب على جميع السائقين في كلا الاتجاهين التوقف رغم ذلك","فقط السائقون خلف الحافلة مباشرةً","فقط السائقون في المسار الأقرب إلى الحافلة"],"explanation":"بموجب MCL 257.682(2)، حيثما يكون الطريق السريع مقسوماً إلى طريقين بمساحة فاصلة مرتفعة، أو حاجز مادي، أو قسم فاصل مُبيَّن بوضوح، فإن السائق الذي يلتقي بالحافلة عبر ذلك الفاصل غير مُلزَم بالتوقف. أما السائقون المسافرون خلف الحافلة على الطريق نفسه فيجب أن يتوقفوا رغم ذلك. المصدر: MCL 257.682(2)."},"66":{"q":"عندما يوقف سائق CDL في ميشيغان مركبة تجارية على كتف طريق ذي اتجاه واحد أو طريق مقسوم، أين ينبغي وضع المثلثات التحذيرية العاكسة الثلاثة؟","options":["على بُعد 10 و100 و200 قدم باتجاه حركة المرور القادمة","على بُعد 10 و100 و100 قدم على جانبي المركبة","على بُعد 25 و100 و250 قدماً باتجاه حركة المرور القادمة","على بُعد 50 و150 و300 قدم باتجاه حركة المرور القادمة"],"explanation":"على طريق ذي اتجاه واحد أو طريق مقسوم، تُوضع أجهزة التحذير على بُعد 10 و100 و200 قدم من مؤخرة المركبة باتجاه حركة المرور القادمة. يتّبع دليل CDL لميشيغان المعيار الفيدرالي الصادر عن FMCSA (49 CFR 392.22). المصدر: دليل CDL لميشيغان؛ 49 CFR 392.22."},"67":{"q":"على طريق في ميشيغان ذي مسارين باتجاهين، كيف ينبغي لسائق مركبة تجارية متوقفة (CMV) أن يضع المثلثات التحذيرية الثلاثة؟","options":["واحد على بُعد نحو 10 أقدام خلف المركبة، وواحد على بُعد نحو 100 قدم خلفها، وواحد على بُعد نحو 100 قدم أمامها","الثلاثة جميعها على بُعد نحو 100 قدم خلف المركبة في صف واحد","واحد على بُعد 10 أقدام، وواحد على بُعد 200 قدم، وواحد على بُعد 500 قدم خلف المركبة","واحد على غطاء المحرّك واثنان على بُعد نحو 50 قدماً خلف المركبة"],"explanation":"على طريق ذي مسارين باتجاهين، ضع مثلثاً واحداً على بُعد نحو 10 أقدام إلى الخلف باتجاه حركة المرور القادمة، وواحداً على بُعد نحو 100 قدم إلى الخلف، وواحداً على بُعد نحو 100 قدم إلى أمام المركبة. المصدر: دليل CDL لميشيغان؛ 49 CFR 392.22."},"68":{"q":"خلال قيود الوزن الموسمية لـ\"قانون الصقيع\" الربيعي في ميشيغان، ما هي السرعة القصوى لمركبة تجارية تنقل حمولة مخفّضة الوزن على طريق مقيَّد، وفقاً لما هو محدد في قانون مركبات ميشيغان؟","options":["35 mph","45 mph","25 mph","55 mph"],"explanation":"ينص MCL 257.627 على أنه خلال الفترات التي تكون فيها حدود الحمولة المخفّضة (الموسمية) سارية، تُقيَّد المركبات العاملة تحت تلك الحمولات المخفّضة بسرعة 35 mph. وهذا جزء من برنامج \"قانون الصقيع\" المميّز في ميشيغان. المصدر: MCL 257.627؛ قيود الوزن الموسمية الصادرة عن MDOT."},"69":{"q":"بموجب قيود الوزن الموسمية في ميشيغان، أي الطرق مصنَّفة على أنها لا تخضع لأي تخفيض في أوزان المحاور القانونية خلال ذوبان الجليد الربيعي؟","options":["طرق \"كل المواسم\"، المعروضة باللونين الأخضر والذهبي على خريطة مشغّلي الشاحنات الصادرة عن MDOT","جميع الطرق الحصوية في المقاطعات","فقط الطرق السريعة بين الولايات داخل حدود المدينة","الطرق المعروضة بخطوط حمراء متصلة أو متقطعة على خريطة مشغّلي الشاحنات الصادرة عن MDOT"],"explanation":"تحدّد MDOT طرق \"كل المواسم\" (باللونين الأخضر والذهبي على خريطة مشغّلي الشاحنات الصادرة عن MDOT) التي تحافظ على أوزان المحاور القانونية الكاملة طوال العام، في حين تخضع الطرق \"الموسمية\" (بالأحمر المتصل أو المتقطع) لتخفيضات وزن المحور الربيعية. المصدر: خريطة مشغّلي الشاحنات الصادرة عن MDOT / إرشادات قيود الوزن الموسمية."},"70":{"q":"خلال قيود الوزن الربيعية على طريق \"موسمي\" في ميشيغان، ما تخفيض وزن المحور الذي يُطبَّق على الرصف المرن (الإسفلتي)؟","options":["35 بالمئة","25 بالمئة","10 بالمئة","50 بالمئة"],"explanation":"على الطرق الموسمية خلال القيود الربيعية، تفرض MDOT تخفيضاً في وزن المحور بنسبة 35 بالمئة على الرصف المرن (الإسفلتي) و25 بالمئة على الرصف الصلب (الخرساني). المصدر: إرشادات قيود الوزن الموسمية الصادرة عن MDOT."},"71":{"q":"يقترب سائق CDL في ميشيغان من مزلقان سكة حديد مُعلَّم بلافتة كُتب عليها \"EXEMPT\" (مُعفى) أثناء نقله حمولة تحمل لوحات تحذيرية. ماذا يقتضي قانون ميشيغان؟","options":["التوقف غير مطلوب عند مزلقان مُعلَّم بـ\"مُعفى\"","يجب على السائق رغم ذلك التوقف في حدود 50 قدماً من أقرب قضيب","يجب على السائق التوقف ووضع المثلثات التحذيرية","يجب على السائق التوقف فقط إذا كانت أضواء الخطر غير متاحة"],"explanation":"بموجب MCL 257.669، التوقف غير مطلوب عند مزلقان سكة حديد على مستوى الأرض مُعلَّم بلافتة كُتب عليها \"مُعفى\"، حتى بالنسبة للمركبات التي تحمل لوحات تحذيرية. أما عند جميع المزلقانات الأخرى فيجب على المركبة التي تحمل لوحات تحذيرية أن تتوقف على بُعد 15 إلى 50 قدماً من أقرب قضيب. المصدر: MCL 257.669."},"72":{"q":"ما هو الحد الأقصى للعرض القانوني لمركبة تجارية أو حمولتها في ميشيغان دون تصريح للحجم الزائد؟","options":["96 إنشاً (8 أقدام)","102 إنش (8 أقدام و6 إنشات)","108 إنشات (9 أقدام)","120 إنشاً (10 أقدام)"],"explanation":"يحدد MCL 257.717 الحد الأقصى للعرض القانوني في ميشيغان بـ 96 إنشاً (8 أقدام)؛ وأي شيء أعرض من ذلك يتطلب تصريحاً للحجم الزائد. لاحظ أن هذا أضيق من معيار 102 إنش المستخدَم في كثير من الولايات الأخرى. المصدر: MCL 257.717؛ \"الحدود القصوى القانونية لأحمال وأبعاد الشاحنات\" الصادرة عن MDOT."},"73":{"q":"ما هو الحد الأقصى للارتفاع القانوني لمركبة تجارية، محمّلة أو غير محمّلة، في ميشيغان دون تصريح؟","options":["13 قدماً و6 إنشات","14 قدماً و0 إنش","13 قدماً و0 إنش","12 قدماً و6 إنشات"],"explanation":"يحدد MCL 257.719 الحد الأقصى للارتفاع القانوني للمركبة في ميشيغان، محمّلة أو غير محمّلة، بـ 13 قدماً و6 إنشات. المصدر: MCL 257.719؛ \"الحدود القصوى القانونية لأحمال وأبعاد الشاحنات\" الصادرة عن MDOT."},"74":{"q":"على طريق سريع في ميشيغان به ثلاثة مسارات أو أكثر للسير في الاتجاه نفسه، ماذا يقول قانون استخدام المسارات (MCL 257.634) بشأن المسار الذي يجب أن تستخدمه المركبة؟","options":["لا يُمنع وجود مركبة في أي مسار من مسارات طريق سريع به ثلاثة مسارات أو أكثر في الاتجاه نفسه","يجب على جميع المركبات البقاء في المسار الأقصى إلى اليمين ما لم تكن تتجاوز","يجب على الشاحنات استخدام المسار الأوسط فقط","يجب على جميع المركبات استخدام المسارين الأيسرين فقط"],"explanation":"ينص MCL 257.634 على أن اشتراط الالتزام باليمين لا يمنع وجود مركبة في أي مسار من مسارات طريق سريع به ثلاثة مسارات أو أكثر في الاتجاه نفسه. ومع ذلك تبقى الشاحنات الثقيلة مقيَّدة بالمسارين الأقصى إلى اليمين. المصدر: MCL 257.634."},"75":{"q":"في ميشيغان، قبل عبور مزلقان سكة حديد على مستوى الأرض، ما الذي يجب على سائق حافلة مدرسية فعله بالإضافة إلى التوقف على بُعد 15 إلى 50 قدماً من أقرب قضيب؟","options":["تفعيل أضواء الخطر، وفتح باب الركاب ونافذة السائق، والإصغاء والنظر في كلا الاتجاهين","إطلاق البوق ثلاث مرات قبل المضي","وضع مثلثات عاكسة على بُعد 100 قدم خلف الحافلة","التحويل إلى ترس منخفض والعبور أثناء التسارع"],"explanation":"يقتضي MCL 257.1857 من سائق الحافلة المدرسية التوقف على بُعد 15-50 قدماً من أقرب قضيب، وتفعيل أضواء الخطر التحذيرية، وإيقاف مصادر الضوضاء، وفتح باب الركاب ونافذة جانب السائق، والنظر والإصغاء في كلا الاتجاهين قبل المضي دون تبديل التروس على القضبان. المصدر: MCL 257.1857."},"76":{"q":"سائق CDL يسير على طريق ريفي ذي مسارين في مقاطعة بميشيغان دون لافتات لحد السرعة المعلن. ما هو حد السرعة القانوني العام المطبَّق؟","options":["55 mph","45 mph","65 mph","60 mph"],"explanation":"يحدد MCL 257.627 حد سرعة عاماً قدره 55 mph على الطرق الرئيسية وطرق المقاطعات حيث لا يكون أي حد آخر معلناً (وحد سرعة عام مطابق قدره 55 mph للطرق الحصوية). ولن تتجاوز الشاحنة الثقيلة هذا الحد. المصدر: MCL 257.627."},"77":{"q":"أي العبارات التالية دقيقة بشأن طرق الرسوم (Toll Roads) للسائقين التجاريين العاملين في ميشيغان؟","options":["ليس لدى ميشيغان أي طرق سريعة برسوم؛ وتُطبَّق الرسوم فقط عند بعض معابر الجسور والأنفاق مثل جسر ماكيناك (Mackinac)، وجسر بلو ووتر (Blue Water)، وجسر إنترناشونال (International)","جميع الطرق السريعة بين الولايات في ميشيغان هي طرق برسوم تتطلب جهاز إرسال (transponder)","تدفع الشاحنات رسوماً على I-94 وI-75 لكن السيارات لا تدفع","تفرض ميشيغان رسوماً على جميع الطرق الرئيسية التابعة للولاية خلال الشتاء"],"explanation":"الطرق السريعة بين الولايات وطرق الولاية في ميشيغان مجانية من الرسوم؛ ولا تُجبى الرسوم إلا عند معابر حدودية ومضائق محددة مثل جسر ماكيناك (Mackinac)، وجسر بلو ووتر (Blue Water)، وجسر إنترناشونال (International) في سو سانت ماري (Sault Ste. Marie). المصدر: معلومات رسوم الجسور الصادرة عن MDOT."},"78":{"q":"فيما يتعلق بالفحوص الدورية الروتينية للمركبات، ما الصحيح بالنسبة للمركبات التجارية المسجَّلة في ميشيغان؟","options":["لا تشترط ميشيغان فحص سلامة أو انبعاثات دورياً على مستوى الولاية، رغم أن المركبات التجارية (CMVs) يجب أن تستوفي متطلبات الفحص الفيدرالية للمركبات التجارية","تشترط ميشيغان اختبار انبعاثات سنوياً لكل مركبة تجارية","تشترط ميشيغان فحص سلامة كل سنتين في محطة تديرها الولاية","تشترط ميشيغان فحص دخان قبل كل تجديد لـ CDL"],"explanation":"لا تفرض ميشيغان فحص سلامة أو انبعاثات دورياً على مستوى الولاية للمركبات. غير أن المركبات الآلية التجارية تبقى خاضعة لمتطلبات الفحص والصيانة الفيدرالية الصادرة عن FMCSA بصرف النظر عن غياب برنامج على مستوى الولاية. المصدر: Michigan SOS / MDOT؛ 49 CFR Part 396."},"79":{"q":"بموجب قانون \"التزحزح جانباً\" (Move Over) في ميشيغان، عندما تسمح ظروف المرور بتغيير المسارات لمركبة طوارئ مرخّصة متوقفة، إلى أي مدى يجب أن تتزحزح؟","options":["مسار سير واحد على الأقل أو عرض مركبتين بعيداً عن المركبة المتوقفة","بالخروج تماماً عن الطريق إلى الكتف البعيد","عرض ثلاث مركبات على الأقل بعيداً عن المركبة المتوقفة","إلى أقصى المسار الأيسر بصرف النظر عن الموضع"],"explanation":"يقتضي MCL 257.653a من السائقين، عند الإمكان، الانتقال إلى مسار يبعد بمقدار مسار سير واحد على الأقل أو عرض مركبتين عن مركبة الطوارئ المرخّصة المتوقفة، مع الإبطاء أيضاً إلى ما لا يقل عن 10 mph دون الحد المعلن. المصدر: MCL 257.653a."},"80":{"q":"أي جهة تُصدر رخص القيادة التجارية (CDLs) في ميشيغان؟","options":["شعبة المركبات التجارية في شرطة ولاية ميشيغان","وزارة النقل في ميشيغان (MDOT)","وزارة الولاية في ميشيغان (وزير الولاية / Secretary of State)","الإدارة الفيدرالية لسلامة الناقلين بالشاحنات (FMCSA)"],"explanation":"في ميشيغان، تُصدر رخص CDL من قبل وزارة الولاية في ميشيغان التي يرأسها وزير الولاية (Secretary of State)؛ وتُعالَج اختبارات معرفة CDL والطلبات في مكاتب SOS. المصدر: دليل CDL لميشيغان (SOS) وصفحات CDL على michigan.gov التابعة لـ SOS."},"81":{"q":"أين تُجرى اختبارات مهارات القيادة على الطريق والتحكم الأساسي لـ CDL في ميشيغان؟","options":["في أي مكتب فرعي لوزير الولاية على يد موظفي SOS","في مراكز اختبار إقليمية تابعة لـ FMCSA","على يد ضباط الناقلين الآليين في شرطة ولاية ميشيغان","على يد جهات اختبار سائقين من الأطراف الثالثة المعتمَدة من MDOS"],"explanation":"لا تُجري ميشيغان اختبارات مهارات CDL في فروع SOS؛ بل يُجرى اختبار المهارات المؤلَّف من ثلاثة أجزاء على يد جهات اختبار سائقين من الأطراف الثالثة المعتمَدة من وزارة الولاية في ميشيغان (MDOS). المصدر: دليل CDL لميشيغان (SOS)."},"82":{"q":"من كم جزء يتألف اختبار مهارات CDL في ميشيغان؟","options":["جزءان: اختبار كتابي واختبار قيادة على الطريق","ثلاثة: فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","جزءان: مهارات التحكم الأساسي وفحص المواد الخطرة","أربعة: ما قبل الرحلة، والرجوع للخلف، والقيادة على الطريق، واختبار سلامة كتابي"],"explanation":"يتألف اختبار مهارات CDL في ميشيغان من ثلاثة أجزاء: اختبار فحص المركبة (ما قبل الرحلة)، واختبار مهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق، وجميعها يجب اجتيازها. المصدر: دليل CDL لميشيغان (SOS)."},"83":{"q":"قبل أن يتمكن متقدّم لـ CDL لأول مرة من إجراء اختبار المهارات في ميشيغان، ما التدريب الفيدرالي الذي يجب إكماله؟","options":["تدريب مهني برعاية صاحب العمل لمدة ستة أشهر على الأقل","دورة سلامة المواد الخطرة مدتها 40 ساعة","تدريب السائقين المبتدئين (ELDT) من مزوّد مسجَّل","دورة قيادة دفاعية معتمَدة من MDOT"],"explanation":"منذ 7 فبراير 2022، تقتضي قاعدة تدريب السائقين المبتدئين (ELDT) الصادرة عن FMCSA من المتقدّمين لـ CDL لأول مرة (وبعض الترقيات/التصديقات) إكمال ELDT من مزوّد مُدرَج في سجل مزوّدي التدريب لدى FMCSA قبل اختبار المهارات. المصدر: دليل CDL لميشيغان (SOS)؛ قاعدة ELDT الصادرة عن FMCSA."},"84":{"q":"بعد الحصول على تصريح CLP، كم يجب على المتقدّم في ميشيغان أن ينتظر قبل إجراء اختبار مهارات CDL؟","options":["14 يوماً على الأقل","60 يوماً على الأقل","14 يوماً على الأقل","30 يوماً على الأقل"],"explanation":"تقتضي القواعد الفيدرالية وقواعد ميشيغان الاحتفاظ بتصريح CLP لمدة 14 يوماً على الأقل قبل أن يتمكن المتقدّم من إجراء اختبار مهارات CDL. المصدر: دليل CDL لميشيغان (SOS)؛ 49 CFR 383.25."},"85":{"q":"عند التصديق الذاتي على نوع القيادة لرخصة CDL في ميشيغان، من كم فئة فيدرالية يجب على المتقدّم أن يختار؟","options":["اثنتان","خمس","ثلاث","أربع"],"explanation":"يجب على كل متقدّم لـ CDL في ميشيغان أن يصدّق ذاتياً على إحدى أربع فئات: غير مُعفى بين الولايات، أو مُعفى بين الولايات، أو غير مُعفى داخل الولاية، أو مُعفى داخل الولاية. المصدر: نموذج التصديق الذاتي لـ CDL في ميشيغان (SOS)؛ 49 CFR 383.71."},"86":{"q":"أي فئة من فئات التصديق الذاتي تقتضي من سائق في ميشيغان أن يحتفظ بشهادة فاحص طبي فيدرالي تابع لـ DOT؟","options":["لا تقتضي أي من الفئات شهادة طبية","غير مُعفى بين الولايات","مُعفى داخل الولاية","مُعفى بين الولايات"],"explanation":"السائق الذي يصدّق ذاتياً على أنه \"غير مُعفى بين الولايات\" يعمل في التجارة بين الولايات ويجب أن يحتفظ بشهادة فاحص طبي صالحة تابعة لـ DOT؛ أما الفئات \"المُعفاة\" فلا تقتضيها للسبب نفسه. المصدر: نموذج التصديق الذاتي لـ CDL في ميشيغان (SOS)؛ 49 CFR 383.71/391."},"87":{"q":"ماذا يعني سائق في ميشيغان عندما يصدّق ذاتياً على أنه \"مُعفى داخل الولاية\"؟","options":["أنه يقود عبر حدود الولايات لكنه مُعفى من جميع القواعد الفيدرالية","أنه يقود فقط داخل ميشيغان لكن يجب أن يحمل بطاقة طبية فيدرالية","أنه يقود فقط داخل ميشيغان في عمليات أعفتها الولاية من متطلبات التصديق الطبي","أنه يقود بين الولايات ويجب أن يحتفظ ببطاقته الطبية مودعة لدى SOS"],"explanation":"تعني \"مُعفى داخل الولاية\" أن السائق يشغّل مركبة CMV فقط داخل ميشيغان في أنشطة قرّرت الولاية أنها مُعفاة من متطلب التصديق الطبي، فلا تُشترط بطاقة طبية فيدرالية. المصدر: نموذج التصديق الذاتي لـ CDL في ميشيغان (SOS)؛ 49 CFR 383.71."},"88":{"q":"ما هو السن الأدنى لإصدار رخصة CDL لقيادة مركبة آلية تجارية داخل ميشيغان فقط (داخل الولاية)؟","options":["21 سنة","19 سنة","18 سنة","16 سنة"],"explanation":"يجب أن يكون عمر المتقدّم 18 عاماً على الأقل ليحمل رخصة CDL للقيادة التجارية داخل الولاية (داخل ميشيغان فقط)؛ أما العمل بين الولايات فيتطلب عموماً سن 21. المصدر: دليل CDL لميشيغان (SOS)؛ MCL 257.312e."},"89":{"q":"في اختبارات معرفة CDL في ميشيغان، أي اختبار يجب على كل متقدّم لـ CDL اجتيازه بصرف النظر عن فئة المركبة؟","options":["اختبار المعرفة العامة","اختبار نقل الركاب","اختبار المواد الخطرة","اختبار المقطورات المزدوجة/الثلاثية"],"explanation":"يجب على جميع المتقدّمين لـ CDL اجتياز اختبار المعرفة العامة؛ أما اختبارات المعرفة الإضافية (مثل المكابح الهوائية، والمركبات المركّبة، والتصديقات) فتعتمد على الفئة والتصديقات المطلوبة. المصدر: دليل CDL لميشيغان (SOS)؛ 49 CFR 383.23."},"90":{"q":"عند تجديد رخصة CDL في مكتب وزير الولاية بميشيغان، أي مما يلي يُعد جزءاً من العملية القياسية؟","options":["اختبار مواد خطرة كتابي إلزامي لجميع عمليات التجديد","فحص بصري ومراجعة لسجل قيادة المتقدّم على مستوى الولاية والوطني","فحص طبي جديد تلقائي تابع لـ DOT يجريه موظفو SOS","إعادة إجراء اختبار المهارات الكامل المؤلَّف من ثلاثة أجزاء في كل دورة"],"explanation":"عند التجديد يُجري مكتب SOS اختباراً بصرياً ويتحقق من سجلات قيادة المتقدّم على مستوى الولاية والوطني (CDLIS)؛ ولا يُشترط عادةً إعادة اختبار المهارات الكامل. ملاحظة: يمكن أن تتغير الرسوم الدقيقة. المصدر: دليل CDL لميشيغان (SOS)؛ صفحة تجديد CDL على michigan.gov التابعة لـ SOS."}}};
